window.BOOK_DATA = {"title": "عندما تطير الحيتان", "author": "أسامة ياسر لافي", "pages": [["كلمة المؤلف", "في طفولتي قيل لي أنني قد تعلمت الكتابة قبل نطقِ الحروف من شدة الهدوء الذي كان يخيم على شاكلة هالةٍ غير مرئية، وفي المراحل المدرسية الأولى عندما قمت بالمشاركة بإحدى مسابقات الكتابة للقصة القصيرة أذكر مزاح أحد أعضاء اللجنة، قائلاً: غسان كنفاني جديد؟", "رددت أنا هامسا: بس أنا أشطر منه.", "ضحك الجميع، وأخذت أنا بدوري أقرأ تجاعيد عيونهم مستغربا .. في ذلك الوقت كنت أرى نفسي أديبا مخضرما، ومنافس شديد يهدد عرش أكبر الكتاب اللذين داسو الكروية يوما من الأيام.", "في هذا الكتاب الذي قد أصفه بأنه سيناريو سينمائي في بعض الأحيان، قصص جملتها أدبيا للتخفيف وطأة المأساة.. ولجذب الشباب الذي تناهز أعمارهم عمر عناقيد الزهور.. أو إثبات عقد قراني على الكتابة لأنجب إبنتي الأولى ورقيا .. ربما عبارة عن دليل يجعلني أتمسك بالحياة.. وأن أخوض حروبا فرضت علي ظلما محاربا فيها بنصل قلمي.", "عاركت ألف فكرةٍ برأسي قبل إخراج هذه النصوص للعلن.. سائلاً نفسي: هل أستطيع إدخال غريبٍ على حياتي الخاصة؟", "هل أنا قادرٌ على السماح للجميع أن يستبيح حرمة عقلي؟", "رأيتها بحدقة عينٍ شديدة الإتساع .. تغمرها مشاعر الحب والدهشة وحماسٌ شديد لإستكمال إجراءات نشر هذه القصة للعلن.. شاركتني المفرد المناسب، مسحت دمعتي عندما فقدت الأمل بإحدى محطاتي.. رأتني بطلاً خارق أحلق من سماء الشام.. للقدس وصولا لعمان.. كانت أول طفلة أحاطتني بطقوس الأبوة وأنا في الثامنة من عمري .. حتى يومنا هذا، ابنة أختى الكبرى \"سما\" .. فإخراج هذه النصوص من الدرج الخشبي للسماء، يعتبر تحديا أخير .. هل \"سما\" أحبت القصة لأنها تستحق؟ أم لأنني خالها المفضل؟"], ["أما الآن .. أترككم برحلة خبِئت في ثنايا هذه الصفحات.. لمحبين الفنون، للمثقفين، للأوفياء رغم غدر الزمان وأهله، للشجعان القادرين على الحُب حتى لو كانوا يعلمون أن نهاية المطاف قد تحطم فؤادهم .. ومع ذلك، أكملوا المشوار.. برفقتي.", "ملاحظة/ لتجربة أفضل، يرجى الإستماع إلى الأغاني المذكورة تزامنا مع ذكرها خلال القرآءة.", "-أسامة ياسر لافي."], ["في بداياتي لم يقرأ لي أحد، باستثناء صديق او اثنين..", "فهل تقبلون جميعكم أن تصبحوا أصدقائي، جميعكم؟! -أسامة ياسر لافي"], ["لم أكن أتصور أن تتغير حياتي عن طريق روحٍ تطفو في السماء.. أو من خلال حياةِ شخصٍ آخر.. من خلال رسائل مهملة.. خطُت بألم.. أو حتى من خلالِ حيوان!", "لم أكن أتخيل تلك الحياة.. كنتُأظنُّ أن حياتي سوف تكون صاخبة يا رجل! أغاني روك! والسهر حتى ساعاتٍ متأخرة من الليل! قضاء معظم وقتي أتسكعُ مع رفاقي وألعب الـ (X-Box) في الحقيقة إنها في البعُد الموازي من تخيلاتي! لكن لا بأس بها.. أقلُّها ألعبُ الـ (X-Box) دائما ... أو أحيانا، حسنا حسنا سأعترف؛ أقصد نادرا!", "ربما السبب ليس أنا، أو حتى أمي.. أنا متأكدٌ أنها تبذل قصار جهدها لكي أكون سعيدا ولا أحتاج لشيء.. لم يكن الأمرُ صعبا في ذلك الوقت.. عندما كان أخي الأكبر معنا.. أتذكر تلك اللحظاتِ جيدا حتى أن أمي كانت تبتسمُكثيرا.. أو بالأحرى أكثر من هذه الأيام..", "فادي! فادي! لماذا لا ترد! هتفت أمي. وقفت أنا بدوري أجيبها: أنني أكتبُ يومي البائس، رمتني بنظرة ثاقبة وقالت: إياك أن تتجرأ وتتلفظ بتلك المفردات أمامي! إنزل من السيارة لقد وصلنا يا ذكي.", "أقر بأني وقحٌ أحيانا.. ولكن أمي أصبحت مزاجية بشكلٍ مبتذل أيضا تعطيك أفضل نموذج عن برج الجوزاء! أنا أعلم بأنها تحبني ولكن ما فائدة هذا الحب إذا كانت المعاملة سيئة!", "فتحتُ باب السيارة الصدئ.. وقفزت منها.. أخذت قدماي تضرب الأرض كعسكري غاضب من أوامر سيده.", "فتحت أمي الباب وذهبت إلى المطبخ لكي ترتب مشتريات السوق.. وأنا أكملت وجهتي إلى غرفتي وأغلقت الباب بعنف.", "حياتنا تغيرت جدا، أسألُ نفسي أحيانا هل أنا سعيدٌ بموتِ أخي؟! هل استنجدت لحظة بالله واستجاب لها؟", "جلستُ أتأملُ السقف، وأقرأ التجاعيد التي فيه.. داهمتني أمي.. وبيدان ترتعشان أمسكت مقبض الباب وفتحته.. توجهت إلى سريري بخطوات مرتبكة.. وجلست على طرفِ السرير وقالت بصوت خافت: فادي حبيبي ما بالك؟ هل هناك شيءٌيزعجك؟! قلتُ لها بصوتٍيملأهُ الخبث: ما الذي يهمك؟ أنا لست الفتى المفضل أو \" theappleofmyeye \"، وهنا ظننتُ أنها سوف تعاتبني"], ["وتصرخ، لكن نُسجِت دمعة على طرف عينها.. وسقطت على وجنتيها.. وقالت: حبيبي فادي؛ كلٌّ منكم له جزءٌ من قلبي.. أنا أحبك جدا عزيزي! خيم علينا الصمت للحظات ولم أنظر إليها.", "بعدها بثوانٍقالت: أدري أنك تنزعجُِمن تقلباتي المزاجية.. ولكن يا صغيري رحيل أبيك.. وبعدها موت أخيك.. كلُّ شيء يخلف أثرا في قلبي وتكثر الندوب فيه.. أشعرُ به يشتعل! إنه ليس حجر. تركتُ كل الكلام وفكرت بشيء واحد.. \"يا صغيري!\"", "أنا لستُ طفل أنا الآن في الثانوية! خاطبتُ نفسي. قالت لي: حسنا، تجاهلني.. لكن سوف تفهم ما أقصدُ يوما ما.. وتركت مجموعة من الدفاتر والرسائل وراءها ومشت نحو الباب بخطواتٍ مثقلة.. وقالت أحبك فادي. أمسكتُ تلك المجموعة .. ونظرتُ لها.. بعد التفحص قليلا أيقنتُ أنها من كتابة \"يوسف\" وقلت مع ضحكة ساخرة: تراهات هه.. وقذفتها على مكتبي الذي يسوده الخراب والأوساخ.. ما هذه؟ يا الهي! قطعةُبيتزا عفنة أوه!", "استلقيتُعلى الأريكة، وأخذتُ أتصفح كتاب الرياضيات.. يا لهذا العلم السخيف! أحسست بالاشمئزاز وتركته.. عدلت هيأتي وجلست.. وأخذت أفكر. ما ذنبُ أمي؟ ماذا اقترفت لأعاملها هكذا؟ لطالما كانت قوية لأجلنا، وأفنت حياتها في سبيل إرضائنا.. أمي في آخر العقد الثالث لكنها شديدة الجمال، قامةٌ طويلة، قوامٌ رشيق، وشعر مموج كستانئي.. وعينان تشعرانك بالدفئ الغامر.. وأنا أحبهُّا أيضا .. ربما قد تباعدنا قليلاً في تلك الفترة المسماة \"بالمراهقة\"، أظن أن السبب هو التغير الهرموني والجسدي، بالإضافة إلى شبه النضوج الفكري.. ممم.. هذا مقزز! أتمنى أن أعود بالزمن لكي أظل طفلاً ساذج يحبه الجميع ويقرصون خدوده الممتلئة."], ["( ريتا )", "كلُّ الأمور تضخمت فجأةا، وكلُّ شيء بات يحتاجُ جهدا مضاعفا.. لم أرد تلك الحياة.. كانت حياةٌ أخرى مرسومةٌفي عقلي.. ربما أدرسُِ الفن في مدرسة كلاسيكية راقية.. أتزوج من الرجل الذي أحب، ونبني عائلة صغيرة.. ونعيش في مكان هادئ يكسوه الخضار والأزهار.. حسنا، هذا يحدث في أفلام هوليوود.. ربما قصةُ حياتي ذهبت بالخطأ إلى مخرج في بوليوود! وجاءت خلاف ما اشتهي.. تركني زوجي في بداية المطاف.. هـهـه \"حب حياتي\" كان يخاف من المسؤولية.. تجاوزنا هذا الخوف في أول رضيعٍ لنا.. وظننتُأنه قادرٌعلى التغيير.. أحد أخطاء هذا العصر هو أن تظن نفسك قادرا على تغيير الشخص عبر حبه بشكلٍ أكبر “Icanfixhim” ، أن تحب تفاحة ربما.. وتراها برتقالة.. لكن لم يحتمل قلبه الضعيف مسؤولية الرضيع الآخر.. غادرنا بعد مولد فادي.. سارت أمور الطلاق بسرعةٍ، أحيانا أفكر هل وجوده سوف يحدث فرقا؟ هل سيتوزع الحمِلْ الذي على كتفاي؟ من الجيد أنه قد ذهب.. لم أرد يوما أن يكبر أطفالي في كنف رجلٍ غير مسؤول..", "أعملُ ممرضة في مستشفى \" كاليفورنيا UCSF/MC \" واصلتُ الليل بالنهار لكي أدفع فواتير المنزل على الأقل.. من حسن حظي أن رزقني الله بشاب رائع.. له القدرة على تحمل مسؤولية كبيرة، إبني الأكبر \"يوسف\". أفتقد وجوده كثيرا.. كان يساعدني في أعمال المنزل.. والأمور الخاصة بفادي.. أعلمُ أنه ناجحٌ مثلي، يشبهني .. أخذ الجينات الوراثية الحميدة كلها مني.. وأخذ من أبيه اسمه الثاني البائس.. كانت علاقة \"يوسف\" بأخيه لا بأس بها.. كان يحاول أن يكسر الجليد الذي وقف حائلاً بينهما.. لكن فادي كان يضع الكثير من تلك الحواجز.. أعتقدُ أن فادي يظن بأنني أميزُ أخاه عنه.. أو أني أحبه أكثر منه.. لكن هذا غير صحيحً..ل يوجدُ أمٌّتميز بين أبنائها.", "أتمنى أن يعود إلى رشده ويكف عن قول أنه \"إبن البطة السوداء\" كم أكره هذا التعبير البغيض! توفي \"يوسف\" قبل شهور من الآن بمرض السرطان.. كل شيء حدث فجأة.. لم نتمكن من العودة إلى بر الأمان.. انتشرت تلك الخلايا اللعينة في كامل جسده.. حاولنا بشتى الطرق.. لكن لا اعتراض على قضاء الله وقدره..حسنا، أحيانا أحدث ذاتي.. وأقول، لماذا أخذه الله مني، ألكي تصبح همومي أقوى؟! لكن سرعان ما أنظف رأسي من هذه الأفكار.", "كان \"يوسف\" مولعا بالكتابة.. كان صدقا كاتبا رائعا، كلامه موزون وحروفه منسوجة بحبٍ كبير. ترك العديد من الرسائل، اليوميات، وحتى القصص القصيرة.. أوصاني قبل موته بإعطائها"], ["لفادي عندما تصعد روحه للسماء.. أتمنى أن تحمل هذه الرسائل التغيير المنشود على فادي.. أتمنى ذلك بشدة.", "", "( فادي )", "الحياة هنا كانت معقدة في البداية، لكن تأقلمت معها مع قليل من الوقت، كان الأمر صعبا أولها.. شابٌّ مسلم انتقل حديثا إلى مدرسة أغلبُ من فيها يصورون لأنفسهم جوانب مظلمة للإسلام.", "انتقلنا هنا منذ ثلاث سنوات، أو أكثر بقليل..حصل أخي على منحة لإتمام دراسة البكالوريوس كان تحصيله الدراسي يخوله لتلك النتيجة.", "هل أفتقدُحياة الأردن؟ مممم ربما قليلاً .. أو قليلاً جدا جدا لا أدري. أمي تفقدُ عائلتها جدا وتبكي حين تكلم خالتي. لن نرجع للأردن \"حاليا \" أنا تأقلمت بشكل جيد وكونت صداقات.. آندرو.. أو كما يحب أن يُنادى \"آندي\" .. ويلي.. أو كما يحب اسمه الكامل \"ويليام\" وتلك الفتاة فيكتوريا حسنا إنها ليست صديقتي لكنني معجبٌ بها بشدة.. وأعلم أن نهاية الطريق جدارٌ كبير والسبب أنها أجملُ فتاة بالثانوية ولها شعبية هائلة!", "وأمي استقرت بعملها وأخذت علاوة قبل أسابيع قليلة.. الأمور تتحسن قليلاً. كان يدرس أخي علم الجينات والطفرات وكلُّ ما يتعلق بعلم الهندسة الجينية، كان مغرما بها ! ويجتهد جدا بالدراسة وعمل الأبحاث.. لكن باغته السرطان في سنة التخرج.. وظلت دمعة أمي معلقة بجانب عينها.. متأملة تخرجه من الجامعة.. وكما هي أمي مغرمة بالفن ورثت أولادها تلك الصفة.. ولكن وقف المجتمع بوجه ذلك الطموح \"الفن لا يطعم الخبز\" لذلك كان خيارها أن تدرس التمريض وتتخرج منها بتقدير +A أيضا!", "كان \"يوسف\" يرسم كثيرا وكان يقضي ساعاتٍ متواصلة إلى جوار أمي يتسامرون ويرسمون وكنت أنا في ذلك الوقت ألهو بألعاب الفيديو أو الدراسة. لهذا من الطبيعي أن يكون \"يوسف\" قريبا من قلب أمي."], ["", "( المدرسة الثانوية )", "إنها سنتي الأولى بالثانوية، ولم يختلف الوضع كثيرا فكل من كان بالإعدادية ترفع (للثانوية) ولكن أنفس الطلاب اختلفت قليلاً .. مثلا أتذكرُ أن فكتوريا كانت تلاطفني في السنوات الإعدادية.. كان ذلك نادرا ولكنه حدث! أما الآنلا يحدث.", "أجمل ما في الأمر أن القيود العمرية تناقصت قليلاً.. والجميع يعتبر أنك مسؤولٌ عن تصرفاتك. حتى السهر لساعاتٍ متأخرة مسموحٌأيام العطلة. وهنالك ما تغير بي قليلاً.. كنت مولعا بالكتابة والمطالعة لكن ويليام أخبرني مرةا: يا رجل يجبُ أن تنضم إلى مجموعة الـ (Nierds) أو مجموعة. مارغريت النباتية، ويمكنك أن تقيم معهم حفلات الشاي وحرب الوسادات أو حتى تقبيل وحيد القرن! وأخذ يضحكُ بشكل هستيري! لكني بالمرحلة الثانوية عدتُ للقراءة لأسباب كثيرة جدا، ولطالما كانت مكتبة \"يوسف\" تجذبُالأنظار وكان ينصحني بالمطالعة قبل موته، أظنُّ أني لا أقرأ لكي \"أتكاتب\" بل أكتب بالفطرة.. أقرأ بالحاضر عن أحداثٍبالماضي.. لكي أعرف كيف السبيل للتعايش مع المستقبل.", "هل سمعتم عن آلة \"قراءة الأفكار\"؟", "أجزم بأنها حقيقة.. وبسعر زهيدٍ جدا، مجردُ صفحاتٍ وحبر.. وأضمنُ لك بأنك سوف تتجول بعقل الكاتب! أن تتقمص دورا.. مريضٌ نفسي وردود فعله مثلا.. طفلٌ على حافة الموت.. جنديٌ في وسط الحرب.", "وأنا كالعديد من الأشخاص لا أحب أن يكون لي حياةٌ واحدة.. أو جسدٌ يعيقني عن السفر وإطلاق العنان لنفسي. كلُّ ما في الأمر، إفتح الكتاب واغرق بين طياته.", "ومن الأمور التي تغيرت هي ذوقي الموسيقي لم أعد أحبُّالأغاني السريعة كثيرا.. أو بالتحديد أغاني الروك، اتجهت ميولي إلى أغاني الـ “pop” والكلاسيك أكثر."], ["لكن الغريب بالأمر أن الجميع تغير على عكس التغير الخاص بي.. ظلت القراءة والكتابة للمخبولين.. والأغاني الصاخبة تنمي بهم روح الشباب الضائع.", "", "( ريتا )", "بعد يوم عملٍ طويل.. رجعتُ إلى المنزل منهكة.. تبعتُ خطواتي نحو غرفة فادي الذي وجدته نائما كالملاك الصغير.. وذهبت لكي أشغل السخان لأحظى بحمامٍ ساخنٍيريح عضلات جسدي المتعبة.", "خلعتُ ملابسي، فتحتُ صنبور الماء الساخن، وأخذت كميةا كبيرةا من الصابون وبدأت بالالتحام مع الماء.", "أعلمُ بأن أفضل وقت للتفكير هو تحت الماء الساخن مرَّشريط حياتي أمامي ببطئ.. أوقاتٌ سعيدة معدودة، اوه تقريبا ثمانٌ أو تسعُ. هل ستكون حياتي أجمل إن درست ودرست ومارستُ الفنون؟! أو لم أتزوج أحمد؟!", "هل سأكون أسعد إن تركتُ زوجي الأبله في مرحلة مبكرة ومضيتُ قدما في حياتي؟! كلُّ الذكريات تنهش بعقلي .. أبي وأمي.. أخواتي.. أبنائي.. كل شيءٍ يسير بسرعة البرق.", "لم أعد قادرة على الرؤية الواضحة من بخار الماء الذي يحتويني.. أحسست برعشة في جسدي لانسكاب الماء البارد عليه بعد نفاذ الساخن.. رعشةٌبدت كأنها تخبرني بالوقت الطويل الذي أمضيته تحت الماء.. أغلقتُ الصنبور.. أخذتُ المنشفة وبدأت بتجفيف جسدي وشعري وقمت بارتداء الكنزة الصوفية الوردية.. كانت هديةُمن فادي في عيد الأم.. ومن وقتها هي المفضلة لدي.. أشعلتُالإنارة الخافتة... وجلست على سريري.. ولكن شعري ما زال مبتلاً.. حسنا لا أريد أن أجففه مرةا أخرى.", "تك! صوت إغلاق مفتاح الإنارة، حزمت الغطاء وشددته على نفسي. وغططتُ في نومٍعميق فعلا ولكن ما زال عقلي يرفضُ فكرة النوم. ما زال يفكر ويفكر ويفكر.. ويرهقني معه."], ["", "(قسم مرضى السرطان)", "العمل في مشفى (UCSF) مرهق أحيانا لكن ليس كما تصوره كاميرا السينما، كمسلسل ! صدقنيإنهاهوليوود Dr.House أو Grey’s anatomy", "كانت مناوبتي اليوم في قسم العلاج الكيميائي للخلايا السرطانية، سعيتُ دائما الابتعاد عن هذا القسم لكن أخبرتني صديقتي \"كريستين\" بأنها يجب أن تقلَّ أمها من دار العجزة.. أخبرتني عن تفاصيل مرض أمها، وأنها أصبحت متطلبة جدا. كنت أنا ساهمة، أفكر بطريقة لكي أهرب من تلك الأفكار التي سوف تراودني وتنهش عقلي ... تلك الذكريات التي تخص يوسف.. آهٍ يا ولدي.. كم أني مشتاقة إليك.", "أخبرتها بأنه لا مشكلة لدي.. وأنني مدينةٌ لها بتلك المناوبات التي غطتها مكاني عندما كنت أخوض مع يوسف جلسات علاجه الكيماوي .", "مشيت في وراق القسم.. كادت ساقاي تتعثران من شدة خوفي.. صوت خفقان قلبي يكاد يجعلني صماء! تمالكي نفسك يا فتاة! إنه مجردُ عملٍ عادي يذكرك بإبنك الذي قد لاقى حتفه بنفس الشأن!", "", "(فادي)", "لماذا تمر الأيام بشكلٍ بطيءٍ ممل؟!", "وأنا جالس على المقعد في صف العلوم وجدت شيئا ينقذف علي من \"ويليام\" ..كانت رسالة، رفعتها وفتحتها، يخبرني فيها أن سارة ولوسيان يتحدثان بشأنك ويقولان أنك من أكثر شباب الثانوية إثارةا يا رجل!", "صراحةا لم أهتم، حتى لو كان هذا الخبر صحيحا من يهتم لكلام ورأي مراهقات فارغات!"], ["أشرتُإليه بإبهامي وابتسامة شاحبة مبتذلة .. وأخيرا سمعتُ صوت الجرس، معلنا إنتهاء الدوام وأن عطلة نهاية الأسبوع في الانتظار! تنفستُ الصعداء.", "أخذتُ كتبي ومد آندي يده عاليا كي أصافحها، وبعدها خرج كلٌّ منا متوجها إلى الحافلة التي ستقله إلى الحي الذي يقطنه.", "كانت الحافلة الخاصة بي ممتلئة وكان هناك مقعدٌ واحدٌ شاغرٌ، وكان من يجلس بجانبه فكتوريا.", "اضطررت إلى أن أشاركها إياه... أزاحت حقيبتها بخجل، وأنا شعرت بأن كل الدم الذي في جسدي تركز في وجهي.", "وقلت بصوتٍ خافتٍ جدا، أكادُ أن أسمعه أنا: أهلاً قالت هي بدروها: أهلاً، تفضل بالجلوس.. بصوتٍ أخفض من صوتي.. ولكنني سمعته فقط.. ولا شيء سواه.", "أمضينا الطريق في صمتٍ محدق، ولكن مع أننا لم ننطق بكلمة كانت أجمل دقائق في حياتي البائسة. وصلنا إلى منزلي، وقمت أنا بدوري وودعت فيكتوريا وقلتُ لها: عطلة نهاية أسبوع جميلة، باي.", "وهي اومأت برأسها، ومع ابتسامة تذهب العقل قالت: ولك أيضا... وداعا، كدتُ أتعثرُ بقدماي من شدة الحياء.. نزلت من الحافلة وأكملت طريقي إلى الباب، فتحته وقمت أهتف وأنادي على أمي، وأنا أمشي في الرواق سمعت صوت نحيب صادرٌ من غرفة يوسف والباب بالكاد مشقوقٌ.. شاهدتُ امي تجلسُ على سريره وتحملُ ألبوم صوره، تبكي تارة وتضحك تارة .. مشاعرٌ مجبولةٌ بالفرح.. بالشوق.. وبالحزن.", "لم أرد إزعاجها.. انسحبتُ ببطئ.. قرأتُ مرةا أن البكاء يخفف التوتر.. أرجو ذلك. وصلت غرفتي التي كانت عبارة عن مكبٍ للنفايات بصريح العبارة! وبما أنني أملك نهاية الأسبوع بأكملها سوف أستغلها وأنظف غرفتي..أعتقد أن ذلك سوف يرفع من روحِ أمي ويجعلها سعيدة.", "انقضى وقتٌ وأنا أنظف، وكنتُ أشاهد فيلما على الحاسوب الخاص بي فيلم TheBrave “ ” heart لطالما كان يرفع روح المغامرة لدي."], ["أنهيتُ كل شيءٍ تقريبا، إلا المكتب.. باشرت تنظيفه، وقعت عيناي على الرسائل التي خلفها يوسف من بعدِ موته.. كانت رسائل وخواطر كثيرة جدا.. غير مرتبة حسب تاريخ الكتابة على ما أظن.", "أمسكتُ واحدة بشكل عشوائي، وبدأت أقرأُ بها رويدا رويدا .. وكان يقولُبها يوسف:", "\"صديقي الخيالي:", "أشعر بأني أغرقُ في بحرٍ من غير قاعٍ\" تقودنا أجسادنا إلى الهلاك.. أظُن أن السبب هو السلطة التشريعية المتمثلة بـ \"القلوب\" .. والشعبُ مندفعٌ .. ثائرٌ.. غاضبٌ.. يريد التغيير مٌجسَّدا بـ \"العقول\" تلك الأشياء أفسدت الحياة بهجتها.. نمضي وسط عاصفة.. تأخذنا يمينا ويسارا.. أشعرُ بهوائها البارد يتخلل عظامي..", "لم أعد أشتهي الكتابة، يأخذني جسدي إلى أماكن من العدمً..ل يوجد بها حبرٌ أو ورق..", "هل من الضروري أن أكتب؟! هل أمزقُ جسدي وأجعلُ منه ورقة، ودمي حبرٌ يلونها؟", "حتى في وسط هذه العاصفة .. والعدم، إن استمريت بالصراخ طالبا النجدة لن يسمعني أحد، تتناثر أمواج صوتي وتتلاشى إلى مكانٍبعيد.. كلها غبار في الريح.. أتذكر أني علمت أحدا الكتابة .. ف\"تكاتب\" في رثائي، يظن أن التكاتب والتطبع سيتحول لطبع، لكن لطالما كان الطبع يغلب التطبع ويرمي به أرضا.. تاركا إياها تنهش وتتغذى على جسده.أحيانا إرسالُكلماتٍ وحروفٍ إلى الخيال جميلٌ جدا، أقلُّها إنه مستمعٌجيد، لهذا أكتب لك يا صديقي.. على أمل أن ترد علي ...أن تحلم وأنت مستقيظٌشيءٌ جميل؛ لأنك لا تحتاج إلى أن تحاول النوم مجددا لكي تكمل التفاصيل .. حلمٌلامس مشاعرك.", "تعال لنركض بين السنابل الذهبية، هاتِ بيدك.. ومن يدري؟! لعلنا نلتقي\"", "فادي؟! فادي!! نادت علي أمي..", "نعم ماما.. قلت", "قالت: ما بك عزيزي؟! عيونك مملوءةٌ بالدموع", "قلت:لا شيء أمي.. أنني أقرأُ كتاباتِ يوسف رحمه الله."], ["عانقتني بشدة.. لدجة أنها كادت أن تكسر ضلوعي ثم قالت: آملُ أن تستفيد بشكلٍ أو بآخر من رسائل أخيك.. فانتما تشتركان في الصفات وكلاكما شابان تفهمان على بعضكما ومررتما بنفس المواقف والمشاكل.", "همهمت بصوت منخفض: سوف آخذُ منها كل الفائدة أعدك ماما.", "قبلت جبيني وقالت: جهز معدتك للعشاء، أعددتُ لك البيتزا!", "قلت لها: آمل ألا تكون نهايتها كهذه القطعة وأشرتُ إلى القطعة المتعفنة منذ أسابيع.", "ضحكت وقالت: كم أنت مشاكس!", "", "(النفاق والتطبع)", "ظلت كلمات يوسف تتردد في عقلي.. ولم أنفك عن التفكير بها وتحليلها..", "وفي تلك اللحظات جاء إلى بيتي ويليام وآندي وابن عمِآندي اسمه \"كريستوف\" كان لطيفا وهادئا بعض الشيء.", "قال ويليام: يا رجل هل أحضرت لعبة \" Assasin’screed \" إنها دموية وأحبُّتلك الدماء التي تتلطخ في الواقع الافتراضي. مخاطبا آندرو.", "شعرتُ بالقرف. لكن لم أتفوه بكلمة. رد عليه آندي: كيف لي أن أنسى وأنت قد طلبت مني إحضارها ما يقارب المليون وخمسمئة ألف وتسعون مرة؟! وضحكنا جميعا: وكان آندور لطيفا ولا يحبُ أن يجرح أحدا.", "بدأنا باللعب على الـ “X-Box” الخاص بي، ثم خسر ويليام ورمى بذراع اللعب أرضا وصرخ: هراء! تلك الذراع بها خلل وعطلٌ فني! لا شك في ذلك. لم يكترث له أحد وأكملنا اللعب، وأخذ هو يتجول في غرفتي ثم اقترب من مكتبي ورأى بعض الكتب والروايات عليه."], ["صرخ بنبرة مجبولة بالاستهزاء: ما هذا؟! هل ستتحول جنسيا؟! أخبرتك أن هذا الشيء التافه للفتيات أو للمخبولين! وكان يحملُ كتاب “TheDavinciCode” لدان براون.", "صمت الجميع بما فيهم أنا، وصرتُ أفكر بما سأرد. هل أناقضُنفسي؟! هل أكذبُعلى روحي المتعطشة للمعرفة والقرآءة؟! هل أتطبع بشيءٍ يخالفُ طبعي وسلوكي أدعي الجهل؟..", "ثم قال ويليام: هاه؟ لماذا لا ترد؟! وهنا خرج مني صوت قوي، يقول: هذا الشيء بناتي وللمخبولينً،ل أعتقدُ أن أمثالك من \"العباقرة\" كاملي \"الذكورة\" قادرين على فهمها يا غبي! نعم أنا أقرأ وأكتب أيضا!", "استهجن ويليام ردة فعلي، ورأيتُ الغضب يتكون في عينيه! ثم بدأ بالقول: أيها الـ....، وفي تلك الحظات قال آندي: تبا! لقد خسرت انظروا لقد قطعوا رأسي، وأخذ يضحك.", "علمتُ بأنه لا يريد أن يشبَّعراك لفظي بيننا. أكملنا اللعب على مضد، ولم يعد أحدٌ فينا يشتهي اللعب، سئمتُ أنا من ذلك فتركتهم وتراجعت، وأخذتُ أتأمل النافذة الخاصة بغرفتي، فجأةا أحسست بيدٍ تربت على كتفي، نظرتُإلى الخلفِ بسرعة ورأيتُ كريستوف، وهلعت: كريس لقد أفزعتني.", "قال كريستوف: لم أقصد ذلك فادي، وكان يضحك بشكلٍ مهذبٍوجميل، وبعدها قال: ممم أشعر بالملل من تلك اللعبة السخيفة! أنا أكرهُ الدماء والقتل! قلت بتعجبٍوبإعجابٍ كبيران: وأنا أيضا!", "وأخبرني بأن أعرض عليه كتبي والروايات التي أقرأها، وقال أنه من محبي القرآءة ولا يظنها حكرا على الفتيات والمخبولين.", "تحدثنا قليلاً عن الكتب والمؤلفين، قال لي أنه يحب الأدب العربي وقد قرأ الكثير من الكتب العربية المترجمة، ثم سألني عن كتابٍ أحبهم. أخبرتُهُ بأنني أحبُّ \"دستويفسكي\"، والأدب الروس يلا بأس به بالنسبة لي.", "قال كريستوف: ها، \"إني مصابٌ بحمى التفكير، أفكر فيما حدث وما سيحدث، وما قد يحدث، أفكر في الأشياء التي لن تحدث وماذا سيحدث لو حدثت فعلاً\" رددناها سويا."], ["ثم أضاف: أحب هذا الاقتباس جدا، لأنني من هذا النوع، الذي يفكر جدا، بأقل التفاصيل حجما وبكل شيء! لذلك أذكر نفسي به لكي لا أقلق، أو لا أفكر كثيرا.. حسنا سوف أقرب الأمر لك، مثلاً أنا أخافُمن طائر البوم، لذلك وضعتُتمثالا لها فوق مكتبي.. أشعر بأني مسيطر وهي ساكنةلا تفعل شيئا، وأنا قادرٌ على تحريكها والسيطرة عليها.", "قلت له آه تذكرتُ شيئا مشابها! تذكرتُ فيلم “Thefaultinourstar” حيث كان البطل يضع السجائر في فمه دون أن يدخنها، كأنك تضع سبب موتك بين أسنانك ولكنك لا تموت!", "هتف كريستوف: بالضبط! هذا هو ما أريدُ إيصاله لك.", "أعجبتني شخصية كريستوف جدا، يذكرني بيوسف، أعتقد بأنني سوف أصادقهُُ وستنشأ بيننا صداقة بشكلٍ أو بآخر.", "تبادلنا حسابات الـ (Instegram) وتواعدنا بأن نتواصل بشكلٍ جيد، آملُ ذلك.", "وفي وسط حديثنا الشيق صرخ آندي: خذ بعضا من هذا يا ويلي الزومبي وكان يضحك ويتلوى على الأرض.", "رسم ويلي على وجهه التعاسة وعقد حاجبيه، وبعد قليل من الضحك الجماعي قال : حسنا حسنا، لا أريدُ أن آخذها بشكل شخصي يا أوغاد وكان يضحك بشكلٍ مبتذلٍ واضح.", "وبعدها تأخر الوقت وصراحةا كنت متعبا وفرحتُبسري بأن قد جاء وقت الخلوة بنفسي. ودعتهم وأخبروني بأن المرة القادمة ستكون في بيت آندي، وأنا دعوتُ كريس لكي يزورني إن شاء الله.", "نزلت إلى المطبخ، لكي أبحث عن طعام، أشعرُ بأن معدتي لم يدخلها شيء منذ شهور! وجدت رسالة على الثلاجة من أمي، وكانت تقول فيها:", "فادي عزيزي،", "إن البيتزا في الفرن، لا تقلق يا حبيبي لدي مناوبةٌ اليوم للخامسة فجرا . قبلةُ وحضنٌ دافئ. أمك."], ["لم أستغرب كثيرا، فأنا معتادٌ على هذا منذ صغري، أكلت، وشبعت، وغلبني النعاس وقادني إلى سريري.", "", "(ريتا)", "والآن حان الوقت لكي أواجه مخاوفي، اضطرت \"كريستين\" لأن تتغيب اليوم أيضا، أظن أن أمها في حالةٍ حرجة، وأنا لم أمانع أن أسد موضعها وأن تكون مناوبتي في قسم العلاج الكيماوي مرةا أخرى.", "كانت الساعة متأخرة، والهدوء يسكن جميع الغرف تقريبا، ولكن لفت انتباهي صوتٌ متوسط الحدة، ولم يكن صعبا التنبؤ بأنه صادرٌ عن فتاةٍ صغيرةٍ. دسستُ رأسي استكشف الغرفة عبر الشق، كان هنالك فتاةٌ تدير ظهرها للباب وتردد أغاني وترسم. اقتربت منها ببطئ شديد، ولم تمضِ لحظات حتى شعرت بوجودي، وقالت بصوتٍ مبحوح ومنخفض: أهلاً سيدتي، وكانت ترسمُ على شفتيها ابتسامةا تقبضُ الروح وتعيدها في ثوانٍ معدودة.", "أخذتُ أتأملها دون أن أرد.. ثمَّ سمعتُصوت يخرج من فمها ويقول: هلا جلبتي لي بعض الماء سيدتي؟ أشعرُ بعطشٍشديد!", "قلت لها بسرعة: بالطبع يا عزيزتي، اطلبي مني ما تشائين.", "سكبتُ لها بعض الماء وسقيتها إياه بخفةٍ وبطئٍ شديدين. ثم تبادلنا الأحاديث عن كم عمرها وعن حالة الطقس، وعن ذوقها في الأفلام والأغاني وعن كل شيء. كنت سعيدة جدا يغمرني الفرح.. كلُّ حرفٍ كان له نكهة شديدة اللذَّة.", "ثم سألتها ماذا ترسم، أخبرتي بأنها ترسمُ أمها، ثمَّ قلت: ممم، كم هي محظوظة بتلك الفتاة اللطيفة! هل هي معكِ الآن؟!", "ردت علي وهي تهز كتفيها الصغيران: لا هي غير موجودة، منذ سنتان ونصف..", "حاولت جاهدةا إبعاد خيار الموت الذي يتناجى بداخلي.", "إذا هي مسافرةٌ بالتأكيد! أخبرتها."], ["ردت علي بتهكم شديد: هل تترك أمٌّ ابنتها سنتان بداعي السفر؟! هاه.. إنه نوع من أنواع السفر، ولكن سافرت إلى السماء.", "شعرتُ بخداي يحترقان وما لبثتُ ثوانٍحتى عرفت أنني أبكي.. حاولتُإخفاء دموعي.. لكن من غير جدوى، نظرتْ إلي ومدت يدها ومسحت دموعي بلطف كبير.. وقالت: بما أن الرب قد أخذها عنده، فهو يحب قربها بالتأكيد! وأنا أشعر بها في النعيم..", "في تلك اللحظات، تسآئلت في داخلي، هل أنا أبكي لأنني تأثرت على موقف هذا الملاك الصغير، أم أنني تذكرت معاناتي؟! ومفارقتي لأحبتي؟! أظنُّ أن هذا السبب.. آهٍ كم أنا قاسيةٌ جدا... لدرجة أنني أستغلُ معاناة الآخرين لكي أنفس عن نفسي.", "", "(رسالة يوسف.. (2) )", "صديقي الخيالي..", "أعذرني لأنني لم أراسلك منذ فترة. كنتُ مشوشا بعض الشيء، لم أكن أدري إلى أين أقصد وأي مسارٍ أسلك، فكلُّ الشوارع وجهتي... وكلُّ الوجوه ضالتي.", "خطر ببالي أن أكتب اليوم \"رواية\" لكن تذكرتُقول شخصٍ لي، أخبرني بألا أكتب وأنا حزين، فتظهرُ حروفي منسوجةا باليأس والضجر، لكن برأيي إن أعظم الروايات والمسرحيات العالمية النابضة بالحياة، ولدت من رحم قلمٍ حبره \"جاف\".", "اليوم ذهبتُ للطبيب، شعرتُ بألمٍ ينتشر في كامل جسدي، غثيانٌ يدفعني إلى الاشمئزاز ويقلب وظائفي الحيوية.", "مجردُطفرة، طفرة بسيطة.. قالها لي الطبيب بشكل مباشر، بلا تمهيد ولا أي مشاعر.. أنت مريضٌبالسرطان.. هل الأطباء دمويون؟! أما تعلمنا في الصفوف الابتدائية؟! كذبة رجالٍ ونساءٍ \"نبلاء\" لدرجة أنه يشيحُ بنظره عن مريضه بعد التشخيص والفحص."], ["آه، حتى الخيال غيرُ قادرٍ على أن يحقق بعض الأحلام.. حقيقةٌ وأسطورة.. أمزجها معا بحرصٍ؛ لكي أنتج خيالي.. الذي يبدو مذاقُهُ لا بأس به، أحيانا..", "ها أنا عالقٌ بين الحقيقة والأسطورة.. حقيقةا تركت بصماتٍ على جسدي.. تحرقني وتكويني. وأسطورةٌ وجهت لي الضربة المميتة، في حينها أدركتُ أنني لا أنتمي إلى أحدٍ منهما. أنا خرافةٌ ساذجة، محمولةٌ بين طياتِ قصةٍ في آخر الدُّْرج المُهْمل.", "هل سيتذكرني أحد؟! هل سأكون بطلاً لأحدهم أم سأشربُ من كأس النسيان؟! ويشبُّ حريق بذلك الدُّْرج المُهْمل، وأنتقل أنا من اللامكان إلى اللامكان في البعد الآخر؟", "نوما هادئا عزيزي .", "", "(فادي )", "بعدما أتممتُ قراءة الرسالة، خفتُ عليها من الذوبان جراء دموعي المنهمرة عليها.", "كيف يمكن لقلبٍ أن يحمل كلَّ هذا الألم؟! أتمنى أن أعود بالزمن وأضرب نفسي! من أين اكتسبتُ تلك القوة! لطالما كان يسعى لتحسين علاقتنا لكي نعيش يوما جميلاً، لكي يحتويني ويخفف علي ألمي.. لكن بسبب غيرتي وشخصيتي الممسوحة والغبية صددته! دعوتُ الله أن يأخذهُ من الدنيا!", "فاستجاب للأسف...", "", "(مجرد طفرة )", "عاش يوسف في حب الطفرات والجينات.. ومات فيها.. بسببها.. مجرد خطأ لتجربة فاشلة.. هذا كان سبب موت أخي.. طفرةٌ ساذجة.", "هل كان يعلم بأن موته سيكون مسببه أكثر شيء أحبَّه؟"], ["هل ما قلته لكريستوف صحيح؟ بشأن أن نضع سبب موتنا بين أسناننا للسيطرة عليه، ولكن ماذا لو وضعنا سبب موتنا في قلوبنا وأحببناه، هل سيفتك بنا كما حدث ليوسف؟!", "جالسٌ أنا على مكتبي، صداعٌ ينهش رأسي.. يداي ترتجفان.. قلبي ينبض بقوة.. أشعرُ به يتحرك بشكل ثائر بين ضلوعي.", "عندما ظننت ألا أحد بجانبي، وجدتُ يدا تمسك بيدي.. لكن للأسف كانت يدي الأخرى.", "هل يعاقبني الله لما سببته ليوسف من وحدةٍ وفقدان حنان الأخ عليه.. هل سأشرب من هذا الكأس؟! حان دوري الآن، كم كنت وغدا يا يوسف.. سامحني يا أخي.. هل تسمعني الآن؟ أجبني حتى ولو بسرك.. فهذا مناسبٌ لمواساةِ ألمي المريع.", "", "(ريتا )", "أرى فادي يتغيرً..ل أستطيع أن أحكم هل هذا تغير جيد أم سيء؟!", "أصبح بالكاد يتكلم.. هائم طوال الوقت.. تغير أسلوبه في التعامل معي.. أصبح أكثر حنانا وعطفا.. هذا تغير إيجابي، أتمنى أن تحمل الأيام القادمة المزيد من التغيرات التي سوف تقع على فادي.", "يا ليتك كنت معنا يا يوسف.. لترى أخاك يتعالج من مُر حياته من خلالك.. شكرا لك يا عزيزي.", "قررت بأن أتثبت في قسم مرضى السرطان.. أصبحتُ متعلقة جدا بتلك الملاك الصغير \"أورورا\" كم أعشق لهجتها البرتغالية وطريقة لفظها للراء، اكتسبت تلك اللهجة من أمها المتوفية. ومنذ أول يوم لنا أصبحنا أعز صديقتين حيث قامت بصنع أساور مكتوب عليها Friends4 “ ” ever ، لكن تلك الكلمة \"للأبد\" تُخيفني، لأن الشيء الوحيد المتأكدة منه.. أنلا شيء مؤكد، لذلك سوف أحاولُ أن أقلب الموازين لنكون سويا قدر المستطاع."], ["أعترفُ بأنني كنتُ أتسللُ إلى غرفة \"اورورا\" ليلاً ونمضي الوقت سويا حتى تغفى عيونها البنُية البريئة.", "وجاء ذلك الوقت وسألتني فيه عن الحجاب وقالت: ما هذا الشيء الذي تغطين به رأسك؟ أخبرتهُا بحزم وثقة: إسمه \"حجاب\"", "قالت لي: وما هو؟ أو بالأحرى ما فائدته؟", "هممت: هو أحد أساليب العفة والشعائر الدينية في دين الإسلام، الذي هو ديني.", "ثم سألت بذكاء كما لو كانت تجهز ذلك السؤال: هل تعتقدين أنه سلوك يحُجم حرية المرأة؟!", "قلت:ُ بالطبعلا! أولا هنالك فئة من المسلمات لا يضعن الحجاب.", "ثانيا وهو الأمر الذي من وجهة نظري، بأنَّ ارتداء الحجاب نابعٌ من التصالح مع الذات.", "ردت: وكيف ذلك؟! أرجو أن تصبري علي فأنا ما زلت صغيرة وغير ملمَّة بتلك الأمور.", "رددت عليها: حسنا، سأقربها لك؛ نحنُ البشر بطبيعتنا نحبُّ أن نكون كلنا إثارة وجمال، ولذلك فإن رأي الآخرين سيكون شديد الأهمية لنا، فإن تصالحنا مع ذاتنا وآمنا بأنفسنا، وجعلنا رأي الآخرين مجرد أفكار تدور في ذهنهم. هنا نتصالح مع الذات، ونكتفي بأنفسنا.", "نظرت لها فلمحتُ نظرة تعجب على وجهها، وجلستُ أفكر ما الذي يدفعني لكي أقول لفتاةٍ صغيرةٍ هذا الكلام؟ أدخلتهُا بمتاهات عقائدية على ما أظن.", "وأخيرا انتهت مناوبتي، حان وقت الرحيل. أدرتُ مفتاح السيارة وعدت أدراجي إلى منزلي.", "", "(فادي )", "من بعد ذلك اليوم – الذي لعبنا فيه (X-Box) في منزلي – تغير أسلوب ويليام معي 180 درجة!"], ["ولكن صبرت، وحاولت التغاضي عن تلك المواقف \"التمس لأخيك 70 عذراا\" وتذكرت رسالة يوسف الثانية، حيث قال عن الروايات والمسرحيات الناجحة التي خطُت بقلم جاف.. فلا تستغرب إن خرج رجلٌ صالح من بين قومٍ أشرار.", "ولكن بعد فترة تبين لي بأني أبحث عن شرارة وسط الرماد.. عندما أبحثُ بالخير في ويليام. كنا في فصل اللغة الانجليزية، بالمناسبة .. هل تريدُ محفزا للانتحار؟! اتبع هذه الخطوات:", "أولا تعال إلى مدرسة كاليفورنيا الثانوية", "ثانيا ضع جدولا دراسيا يحتوي على مادة الأدب الانجليزي", "ثالثا اختر المعلم \"آدم تيرنر\"", "رابعا احتفظ بمادة سامة أو سكين حاد لانجاز المهمة بأسرع وقت.", "بغض النظر عن الصعوبة التي واجهتني عندما انتقلنا حديثا هنا، كنت متميزا باللغة الانجليزية بين أقراني، ولم أكن اعتمد على المنهاج فقط بل كنت أتعلم من الأغاني، الأفلام والكتب! لكن الصدمة أنني طوال ذلك الوقت كنتُ أتعلم اللهجة البريطانية، أما اللهجة الأمريكية فهي تختلف كثيرا.. يا رجل صدقا إنهم يأكلون نصف مخارج الحروف! لكن مع الوقت أصبحت معتادا عليها.. فهي أسهل بمراحل من البريطانية.", "كان الفرض الخاص بنا هو التحدث عن الرواية أو الكتاب المفضل لك قبل نهاية العام بقليل.. سيكون الاختيار صعبا لكن سوف أجهز قنبلةا أفاجئ بها الكثير.", "مر الوقت وجاءت استراحة الغداء.. كالعادة ذهبتُ إلى الطابور الطويل ووقفت أنتظر وجبتي، عندما وصلت رأيتُالطباخة التي لها شامةٌمليئةٌبالشعر بحجم أنفها تقريبا .. وضعت في طبقي بعضا من قطع البروكلي المسلوق والأرز الأبيض وحليبٌ منزوع الدسم.. حقا مزيجٌ غير متناسق إطلاقا!", "ثم اقتربت مني وهمهمت: إن لم يعجبك بإمكاني أن أهرسهُ لك يا وسيم، وضحكة صفراوية.. أحسست بالغثيان والتقزز أووه!"], ["اخذتُ الصينية الخاصة بي وتابعت خطواتي نحو الطاولة التي نجلسُ عليها دائما.. أنا وآندي وويليام والتوأمان بيكرز والعديد من الرفاق.", "لكن المفاجأة أنه عندما وصلت وقف الجميع وغادر إلا آندي.. لم استغرب كثيرا لطالما كان هذا أسلوب ويليام الرخيص في تحطيم معنويات الآخرين.", "جلستُ بجانب آندي وقُلت: ماذا يحدث يا صاح!", "قال لي: كما تقول أنت، من يهتم لقولِ المراهقين الأغبياء، وضحكنا سويا كأن شيئا لم يكن. كان ويليام يتهامسُ مع الجميع ويخبرهم بالأكاذيب عني، بأنه وجد في خزانتي مجلة للشواذ جنسيا أو أنني غريبُ الأطوار، وأنا لم أكترث كالعادة .. وتابعتُ مسلسل التجاهل، إلى أن لاحظ ويلي أن جميع محاولاته باءت بالفشل.", "وقف وقال: هيه أنت، أخبرنا كيف مات أخوك؟ هل ما يقولونه صحيح؟ أنه قد مات نتيجة خطأ في الشيفرة الخاصة به؟", "مات بسبب طفرة، وهو يضحك.", "حاولت التماسك أكثر... وأكثر... وأكثر.. لكن ... طفح الكيل!", "حاولت أن أكون هادئا قدر الإمكان، قلت له: لا أسمعك ويلي هل تريد الاعتذار مني؟", "قال: ألا تسمعُ جيدا؟! أقول لك أيها البائس هل مات أخـ.... وجاءت لكمةٌ بسرعة الضوء، شعرت بأن قوتي تجمعت في يدي، وشعرت بفكهِ يطقطق وينزف الدماء السوداء.. ربما كان الكلام الذي قالهُيوسف حكرٌعلى الحبر والورق.. ولا يدخلُ في تركيبة جسم البشر. الطيب يبقى طيبا أما الشرير..", "", "(ريتا)"], ["عندما تلقيت اتصالاً من مدرسة فادي ظننتهم سوف يطالبون بالقسط الذي قد تراكم علي.. على أيتِ حال كنت سوف أدفعه قريبا.", "ذهبت إلى المدرسة والتقيت بالمديرة ذات اللهجة اللاتينية.. رحبت بي وسألتني عن حالي.. وأنا لم أكن واعية لما تقول.. كنت مركزة على طريقة لفظها للراء.. التي اعتدت على أن أسمعها من فم \"أورورا\" وأصبحت مدمنة عليها.", "سيدة ريتا؟! سيدة ريتا هل بك خطبٌ ما؟! قالت المديرة سيسيليا.", "قلت لها:لا لا مجرد صداعٍ خفيف، وأنا أمرر أصابعي على جبيني.", "ردت الآنسة الشابة سيسيليا: ألف سلامة عليك، هل أجلب لك مسكن أو ما شابه؟", "قلت لها:لا الأمر عرضي، هلا تعيدي الكلام لطفا.", "أخبرتني هي: نشب عراكٌبين فادي وأحد زملائه، وحدثت بعض الأضرار، لكن لا تقلقي فادي بخير، وقد تحدثنا مع ولي أمر زميله ويليام وقد أسقط حقه وطالب بإجراءات المدرسة المتخذة فقط.", "صرخت أنا دون قصد وقلت: هل تعارك مع ويلي! إنه أفضل أصدقاءه! لم اكن متوقعة ذلك! أخبرتني بأن الإجراء المتخذ هو أن يتم فصل فادي لمدة أسبوع واحدٍ فقط وبعدها يعاود المجيء هنا، لكن ترجو أن يعدل سلوكه وألا يكرر فعلته.. وأنها لا تريد أن يتضخم الموضوع لأن فادي من أفضل الطلاب في المدرسة..", "أخذتُ فادي واحتضنته بقوة، وهو لم يمانع بل بادلني الأحضان.. هذا ليس من عادته. لم أسأله عن الموضوع.. لأنني أعرف فادي جيدا وأنه اتخذ قراره بعد صراعٍ نفس يٍ طويل.. أعرف ذلك.", "كان المشوار للمنزل طويلاً ومليئا بالهدوء القاتل، لم أضغط عليه وتركته يتكلم براحته.. وبعد الصمت الطويل.. خرج صوتٌ منه وقال: كان الأمر متعلقا بيوسف، وبدأت دموعه بالانهيار وأنا ما لبتث قليلاً حتى شاركته البكاء."], ["", "(أسبوعٌ في المنزل)", "عطلةٌ لمدةِ أسبوع، هذا ما كنت أتطلع اليه.. راحةٌ للعقل والروح والجسد..", "كما جرت العادة، في أطراف المشاجرة في المدرسة يفصلُ الذي يسبب الأضرار.. بمعنى آخر أنا.. لا أحد يرى السبيل، ولا السبب.. الكل يلتفت للنتيجة فقط... فقط يضغطون عليك.. يجردونك من صبرك.. يدفعونك للجنون ويحاولون تحفيز الجانب المظلم منك.. ثم يشُار لك بالبنان على أنك المجرم والشيطان الذي يتجول بين الملائكة.", "أقر بأنني لستُ نادما على كل ما حصل.. لو لم يحدث لبقيت طوال حياتي أفكر، كما قال دوستويفسكي.. ربما هي مجرد سيناريوهات منوسجة في خيالك.. لكن صدقني، يمكن أن تبدأ من عقلك ثم إلى باقي جسدك، تنهش وتمزق كل ما في طريقها.. كمرضٍ خبيث.", "ربما أنا نادم قليلاً.. كان يجب علي أن ألكمهُ بشكلٍ أقوى، ربما لكمة أخرى على أنفه الذي يكسوه حبُّ الشباب.. آه كم أنا شخصٌ أحمق!", "مرت الأيام.. الأول والثاني.. أما الثالث كان جميلاً بعض الشيء.. أو كثيرا ! لكي أكون دقيقا. كنتُ جالسا أقلب محطات التلفاز، رن جرس الباب مرتين متتاليتين.. فتحتُ الباب وأنا أنافخُ الهواء الذي تجمع في رئتي.. وقلت من بالبا...تلعثمت، فالمفاجأة كانت غير متوقعة؛ فكتوريا! ظللتُ واقفا محملقا فيها، كانت شديدة الجمال.. أجمل من كل تلك المرات التي قد رأيتها فيها. عيونها الزرقاء.. شعرها البني المموج.. بشرةٌ تشع نظارة وصفاء.. ابتسامةٌ منسوجةٌ بحرصُرسِمتْ على وجهها لكي تترك وراءها أجمل لوحةٍ عابرةٍ للعصور.. وبعد نصف دقيقة من التأمل بتمعنٍ شديد.. سمعتُ صوت.. ربما هو نابعٌ من ملاكٍ من الجنة؟ أو من آلةٍ موسيقية يضربُعلى أوتارها أمهر العازفين؟ تبين لي أن المصدر هو نفسه تلك اللوحة التي تسرق القلوب. قالت: ألن تدعُوني للدخول فادي؟"], ["استفقتُ أنا من سباتي الجميل.. وقلت لها بصوتٍ مجبولٍ بالحياء: أرجوك تفضلي بالدخول! لم أدرِ ماهية مشاعري.. هل هذا الحب أم الإعجاب؟! ربما هو الخوف يا ترى؟! أو الدخول إلى عالم الخيال؟!", "جلسنا في غرفة المعيشة، ثم سألتها ماذا تشرب، أجابتني: الصودا إن وُجدت ستكون مثالية.. لم تكن تعلم بأنه إن لم تكن موجودةا سوف أركض ثلاثة شوارع لكي أصل أول محل بقالة، وأشتري كل الصودا الموجودة فيه.. أوه، لحسن الحظ أنها كانت موجودة تملئ الثلاجة.", "تناولت علبتين وأعطيتها واحدة وأخذت أنا الأخرى.", "لم أستطع إخفاء التعجب من زيارتها.. حقيقة كنت متوترا وعرقي يتصبب!", "حمدا لله أنها كسرت الجليد وتحدثت.. أخبرتني أنني بالتأكيد مستغربٌمن زيارتها .. وأننا لم نتحدث في الفترة الأخيرة كثيرا.. قاطعتها أنا قائلا: بل تقصدين مطلقا .. وأخذت هي تضحك وتقول يجب أن نطوي تلك الصفحة الرثة ونفتح واحدة جديدة ونتشارك في كتابتها، ثم أضافت بأنها شعرت بالقلق على حالتي النفسية جراء ما حدث بالمدرسة، وأنها ساقتها قدماها إلى عتبة الباب من غير وعي..", "لا بأس بالـ \"لا وعي\" أحيانا.. يصنع أشياء جميلة كهذه الزيارة مثلاً.", "أخبرتها أنني بأحسن حال، عدا يدي المصابة، قالت بصوت قلق: ماذا! دعني ألقي نظرة عليها! قلت لها: لا لا، ليس هنالك داعي للقلق، قاطعتني وكأنها غير مهتمة لما أقول. أمسكت يدي، ولأول مرة أحسست بأن الزمن توقف.. توقفت عقارب الساعة، كل شيء يبدو أجمل، كأنني أرى العالم بالألوان.. لأوَّلِ مرة، كل شيء تباطئ وتوقف.. عدا نبضات قلبي، خفتُ عليه أن يتوقف، صرت أدعو الله ألا يتوقف الآن.. أريد أن أعيش هذه الثواني.", "همست وهي تكشف عن الجرح أنه بخير وأنني أحتاج إلى أن أداوم على تناول مضادٍ حيوي لكيلا يلتهب الجرح.", "مع أن الزمن قد توقف.. مر الوقت سريعا سريعا كأرنبٍ يركض على حديدٍ درجة حرارته فوق 1000 درجة مئوية."], ["تبادلنا أطراف الكلام.. عرفتني جيدا وعرفتها جيدا.. أو لم أعرفها ذلك اليوم؛ لأنني كنت مهووسا بها وأعرف عنها كل شيء، ولطالما حاولت تقصي تفاصيل يومها من زملائنا.", "ولكن الشيء الغريب أنني لم أكن أعلم بالخلافات التي بين والديها.. وطلاقهما \"حديثاا\"، كنا متشابهين كثيرا من جوانب عدة، ما عدا الصفات الذكورية ومستويات هرمون التستيرون والأستروجين وأخٍ قد مات بالسرطان.", "حان وقت الرحيل، وهمت بالوقوف.. قلتُلها بصوت رحب مسموع: انتظرُ زيارتك القادمة، وفي داخلي صوت وحشٍ حزين يقول: أرجوكِلا تذهبي.", "اتصل بي آندي وأخبرني عن أحوال المدرسة.. وقال لي: يا صاح يجب أن ترى وجه ويلي، كأنه مسخٌ وزادت قباحتُهُ بعد لكمتك، وأخذنا نضحك سويا.", "عرف بأمر زيارة فيكتوريا، وخيل لي وجهه وهو يتكلم.. كأنه قد لسُِع من قنديل بحر.", "وأنا بدوري غيرت محور الحديث الدائر حول فيكتوريا.. هل بدأت بالغيرة عليها؟! لا أدري لكن هكذا أفضل.. وأخبرني بأنه سيرسل لي الفروض التي تغيبت عنها.. بأنه اشتاق لي ومتى أعود.. وأنا أخبرته بأنه تبقى ثلاثة أيام.", "", "(رسالة يوسف \"3\")", "صديقي الخيالي..", "متكورٌأنا في زاوية غرفتي، أطلق همساتٍ حزينة إلى السماء.. كطائرٍقطعت أوصاله.. أكثر صوتٍ مزعج هو صوت الهدوء، وخفقاتُ قلبي في وسطه..", "إيجادُ النفس أمرٌصعبٌ نسبيا، أحدهم وجد نفسه بين سطور رواية عتيقة، بين صفحات رسائل مهملة، بين فرشاةٍ وألوانٍ زاهية.. بين ألحان أغانٍ كلاسيكية.. وبين الحلمِ والحقيقة.. لكن أصعب شيء أن تجد نفسك مغتربا بين أهلك.."], ["أتدري يا صديقي؟! لولا قلمي هذا لملأ الصدأ أناملي وجعلها تتآكل.. صوتٌخارجٌ من بين ثنايا القلب وحجراته.. شيءٌ يدفعني للإشمئزاز والتلويح بالراية البيضاء.. شيءٌيمزق أوصالي.. يدفعني للصراخ.. للنَّحيب المعجون باليأس.", "ربما خط يدي باهت، وحروفي غير نابضة بالحياة لكن صدقني.. لم يكُ شعوري واضحا أكثر من هذه اللحظات.", "صحيحٌ ما يُقال.. الكاتب وليدُ اللحظة.. لكن بعض اللحظات تخرج من رحم قلب الكاتب.. لحظاتٌ ربما تكون مصدر اعتزاز وقرة عين له.. وبعضها كولدِ خطيئة.. لا يتعرف عليه أحد.. مثل الآن.. ماذا لو قرأت أمي هذه الرسالة؟! أو فادي؟!", "هل سأعترف بأنني أنا الذي كتبها؟! هل كانوا متوقعين كمية الظلام التي بداخلي؟! خصلات شعري نزلت ترحب على عيناي التي انجلى لونها.. وأصبحت مصدرا للألم..", "آه.. إلى متى يدوم هذا الشعور؟! كل مر سيمر.. ربما يمر زاحفا فوق صدرك مانعا عنك الهواء.. مانعا إياه أن يصل إلى شفاهك الباردة وتصرخ! اصرخ! اصرخ! تحرك في أرجاء غرفتك جدف بيديك.. ارتفع عن الأرض، وعاود الارتطام بها أقوى عما سبق.", "تلك هي سنة الحياة ... سمعت هذه الكلمات كثيرا من بعد موت صديقي سامي قبل أيام.. لكن أشعر بروحه تحوم وقلبه ينبض.", "ولكنهم نسوا بأن يقولوا لي تلك الكلمات عند موت أبي... نعم إنه ميتٌ بالنسبة لي..", "الموتُ ليس موت الجسد وتوقف وظائفه الحيوية، بل الموتُ هو موتُ الروح والقلب القاسي! صديقك الجاهل: يوسف ", "(أول يوم من بعد الفصل)"], ["استيقظتُ في الصباح الباكر.. وكان الهواء دافئا قليلاً.. كما هو متعارفٌ عليه في صيف كاليفورنيا.", "قمتُ بغسل وجهي وتنظيف أسناني.. وترتيب خصٌلات شعري المبعثرة. أعددت رقائق الحبوب الكاملة لأخذِ بعض القيم الغذائية.. ورائي يومٌ حافل في المدرسة..", "ولكن كنتُ أفكر.. هل أشعر بالريبة؟! أو بشيء من الخوفً؟!ل أدري.", "جاءت الحافلة على موعدها المعتاد.. رحَّبتُ بالسائق الصعلوك دائم الغضب.. وقلت: صباح الخير سيد ماثيو!", "وعلى خلاف العادة، أرسل لي غمزة بطرف عينه، وأنا قمت بكتم ضحكتي من شدة الاستغراب! لاحظتُ أن فيكتوريا تجلس بجانب لوسيان، أومأتُ لها برأسي مع ابتسامة، وهي ردتها لي.", "كان الجو لطيفا بعض الشيء، وكنتُ أرافقُ كتاب ”? Whomovedmychees “ للكاتب “SpencerHohnsin” مكتوبٌ على الغلاف \"تعامل مع التغيرات في عملك وفي حياتك\" Deal “ with changes in your work and in your life”", "لعلي أستفيد بعض الشيء.. إلى جانب رسائل أخي.", "وصلنا المدرسة وأخيرا.. وكان الوضع خلافا لما كنت أظن! الكل يرفع لي \" Highfive \" ويحيي بي! شعرتُ بأنني ليوناردو ديكابريو يمشي على السجادة الحمراء!", "وسط ذلك الترحيب لمحتُ شيئا واحدا... ولم أر سواه.. ابتسامة فيكتوريا، وهي واقفة بين لوسيان وسارة وكيت والكثير.", "فجأةا وسط فرحي وتعجبي أحسستُ بلكمةٍ على كتفي قطعت حبل أفكاري.. كان آندي يهتف أهلا بك يا صاح! لقد اشتقتُ لك كثيرا، وعانقني عناقا سريع.", "ذهبنا سويا إلى فصل العلوم، جاءت معلمة بديلة لفترة قصيرة، بسبب مرض المعلمة \"تريزا\" .. وعلى ما يبدو ستكون حصة تعارف.. سألتنا عن أسمائنا وهواياتنا وما إلى ذلك.. عندما وصلت إلى ويلي.. نظرة الجميع له .. بعضٌ نظر إليه نظرة قرف لوجهه البائس.. والبعض نظر إليه"], ["بشفقة.. وجزءٌ كتم ضحكة كادت تنفجر في سماء الصف.. وهناك من نظر إليه نظرة انتصار.. كما هو حالي.", "لم يكن ويليام محبوبا يوما.. بل كان متسلطا وصاحب ظل ثقيلا...ل يطيقه أحد.", "لمحته بطرف عيني.. عيناه تناظرني، وتقدح شرارا..", "", "(ريتا)", "عدتُ للمنزل اليوم باكرا.. قبل وصول فادي من المدرسة حتى.", "كان العمل المنزلي متراكما كالعادة.. هذه حالتي وحال الأمهات الموظفات جميعا.", "بدلتُ ملابسي وارتديت ملابس بيتية مريحة بدلا من تلك التي تخنقني في العمل. غسلتُ ونظفتُ الأواني، مسحتُ الرخام، ولم مْت جميع الملابس المتسخة من غرفتي وغرفة فادي.", "وعندما وصلت غرفة فادي كانت منظمة جدا والملابس التي تحتاج للتنظيف كانت في سلة بلاستيكية متطرفة.. ها قد بدأ ولدي الصغير بالنضوج ولم تعد غرفته مكرهةٍ صحية.. كادت عضلات فكي تنفصل من شدة فرحي وحجم ضحكتي الكبيرة!", "كنتُ في غرفة المعيشة انتظر وصوله وأعد مائدة الطعام.. سمعتُ صوت الحافلة.. نظرت من النافذة وإذ بفادي ينزل منها ويلوح لأصدقاءه، مشى مسرعا كأنه متلهفٌلملاقاتي.. أو للعودة لا أدري. فتحت الباب لملاقاته.. سارع باحتضاني حتى أنني كدت أسقط.. سارعتُبإسناد نفسي على حافة الباب.. هو يشد يداه على جسدي.. وأنا أشد إحكام يديَّ عليه.", "فجأةا همس: أحبك ماما.", "رددتُ عليه: وأنا أيضا عزيزي.", "تناولنا الطعام وكان يحضرُ الغداء معنا الفرحُ والهودءُ والطمأنينة... والكثير الكثير من الحب."], ["لا أعلم ما الذي حصل.. ما السبب الذي أدى بنا إلى هذه الحالة الرائعة.. مهما كان السبب لا أريد أن يختفي.", "كنا قد وصلنا نهاية الأسبوع.. وأنا كنتُ قد أخذتُ إجازةا للغد لكي أريح نفسي قليلاً من الأعباء التي أثقلت كاهلي... قال لي فادي بأنه سوف يصعد إلى غرفته ويقرأ قليلاً.", "سألته قبل أن يذهب: فادي أخبرني كم تقيم يومك الأول بعد المشاجرة من عشرة؟! قال لي: تسعةُ ونصف! قالها وهو يصعد الدرج ويدقه بأقدامه القوية الشابة.", "تنفستُالصعداء.. وارتاح قلبي وسكن في صدري ...", "", "(فادي)", "صعدتُ إلى غرفتي.. فتحت النافذة قليلاً لكي يتسلل إلي ما تبقى من أشعة الشمس.. ويدخل بعض الهواء.", "والآن حان موعد قراءة أحد رسائل يوسف.. مممم.. أي واحدةٍ يا ترى؟! وقع بصري على رسالةٍمتطرفةٍ عن باقي الرسائل..", "فتحتها بلهفتي المعتادة.. وكان يقول فيها يوسف رحمه الله...", "صديقي الخيالي..", "عندما أتممتُقراءة رواية \"شيفرة بلال\" للكاتب \"أحمد خيري العمري\" جلست أتفكر، كيف لشخصٍ قد مات قبل آلاف السنين أن يغير حياة شخصٍيعيش في زمننا المعاصر؟!", "هل بقيت تركيبة القلوب نفسها؟ أو ترتيب ثنايا عقلنا ومشاعرنا؟", "كلنا متشابهون، صحيحٌ أن كل شخصٍ يملكُ شيفرةا جينية خاصة به.. وتترتب فيها النيوكلوتيدات على نحو مختلف.. لكنْ جميعنا لديه خوف.. لديه \"أمية\" خاصٌّ به.. صراع العقلِ والنقل ... صراع الدين... والدنيا."], ["أعترف بأن نظرتي للأمور تغيرت بشكل كبير. ويعود الفضل لتلك الرواية.", "سوف أوافيك بالروايات والكتب الأخرى يا صديقي العزيز.", "ولكن ما هو كتابك المفضل؟", "دعني أخمن.. ملكُ الخواتم أو هاري بوتر؟!", "هل تسائلت لماذا هما بالذات؟ لأنه يجمع بينكم العديد من القواسم المشتركة.. مثلا جميعكم من وحي الخيال.. دمت بخير", "صديقك.. يوسف أتممت قراءة الرسالة... وصراحةا لم أكن قد سمعت بهذه الرواية من قبل، لكنِ استحوذ علي الفضول لأقرأها..", "هناك سؤال يتجول في عقلي.. لماذا كانت هذه الرسالة متطرفة.. لماذا لم يضعها في قاموس الكتب الذي من كاتبته.. هل هذه إشارةٌإلي لكي اقرأها؟ هل يقول لي يوسف هذا؟!", "ذهبتُمسرعا إلى مكتبته.. وكما سبق وقلت أن مكتبته رائعة ومنظمة جدا.. كان يضع الكتب على حسب الحروف الأبجدية.", "حسنا.. ممم.. ألفٌ.. باءٌ... ها أنا أبحث في صف الكتب التي في حرف الباء وأمرر يدي عليها.. باءٌ.. باءًٌ..ل أجده!", "ذهبت وتأكدت من اسم الكتاب.. يا إلهي! وأخذتُ أضحك مع نفسي.. ليس \"بلال\" بل \"شيفرة بلال\"", "عدتُ مرة أخرى.. أبحث عنها في صف حرف الشين.. شين.. ممم. شين... شيفرة! لا لا إنها شيفرة دافنشي .. ها هي! شيفرة بلال! أتمنى ألا تكون مملة.. ومملوءةا بالتاريخ وهذه الأمور.", "جلستُ وقراءةٌ لساعات.. وصلتُ إلى آخر الصفحات وأغلقتُ الكتاب وألقيته بعيدا.. وبدأت بالانهيار.. أمسك أعصابي قليلاً.. ظللت على هذه الحال لدقائق.. ولكن لم أستطع تحمل المزيد.. بدأت بالعويل! دموعي منهمرة كأنها شلالات نياغرا.."], ["خفتُ أن تسمعني أمي.. غطيتُ فمي بقوة أحاول أن أكتم صوتي... محاولا أن أنسى ألمي بألمٍ آخر... أنا مجبرٌ على ذلك..", "كلُّ حرف يغدو يذكرني بيوسف.. أعراضٌ مشتركة بينه وبين أحد الشخصيات.. السرطان. ", "(التغير المنشود)", "قال يوسف في رسالته أنه مستغربٌ كيف لشخص قد \"مات\" أن غير حياة شخصٍ على قيد الحياة..", "آهٍ لو تدري يا عزيزي إلى ما آلت إليه الأمور الآن، يمكن لشخص ميتٍ أن يُحدث فرقا وتغييرا في حياة أحدنا.التغير لا يحتاج إلى قلب نابض.. بل يحتاج إلى روح نابضة، كما هو حالي الآن بفضلك. وكما قلت سابقا بأحدى رسائلك.. الموتُ هو موت الروح.. وروحك يا أخي ما زالت تحوم بيننا، أشعر بذلك في عظامي..", "شعرت بضيقٍ في صدري.. نزلت وقمت بالتوضئ من غير سابق تخطيط.. شعرتُ بالماء ينسال على أطرافي، يغذيها كأنها أرضٌ قاحلة.", "اختلط دمعي بماء وضوئي.. رفعتُرأسي إلى الأعلى.. وكنتُ على يقين بأنَّ الله لن يخذلني وسوف ينزل السكينة على قلبي.", "الله أكبر.. الله أكبر..", "", "(ريتا)", "\"وداع أورورا\""], ["بعد يوم العطلة.. ارتاح جسدي، ولكنه ما زال يطلب العطلة إلى أجلٍ غير مسمى.", "وأنا متثاقلة أحاول النهوض من فراشي الدافئ تذكرت صوت المذيعة وهي تقول بأن الذين لا يستسلمون ولا يخضعون لأهواء أنفسهم سوف ينجحون.", "حسنا أيتها الغبية... أغلقي فمك الذي يحتجز لسانك المعسول المقرف، أحيانا لا بأس بالاستسلام. رن هاتفي.. نظرتُ إلى الساعة.. كادت أن تكون السادسة صباحا .. ملأ قلبي الهواجس، ما الذي يحدث؟ كان المتصل إحدى الممرضات المناوبات، رددت عليها بصوتٍ يرتعش. أخبرتني بالمجيء حالا.. هناك أمرٌ ضروري.", "كان صوتها غريبا، كأنها تخفي بكاءها.. شعرتُبذلك، حاولت جاهدةا أن أبعد كل الأفكار السلبية عن عقلي... أرمي بها بعيدا، لكنها تعود وتحتل الجزء الأكبر مني.", "لا يمكن أن تموت! قلتها بصوتٍ عالٍو مسموع، قلتها مرةا أخرى بصوت منخفض، قلتها مرارا وتكرارا..", "مشيتُحتى غرفة فادي.. كان نائما بعد، لم أشأ إيقاظه، بل تركته يرتاح في يوم عطلته. ارتديت ملابسي بشكلٍ سريع جدا جدا.", "استغرقت خمس عشرة دقيقة فقط، رقمٌ قياس يٌ جديدٌ لي. أخذت مفتاح سيارتي الصغيرة، صراحةا لم أواجه صعوبة كتلك وأنا أحاول أن أضع المفتاح بمكانه المناسب لكي أديره وأفتح الباب.", "هفف.. محاولة تلو الاخرى.. وأخيرا! حمدا لله . فتحت الباب، دخلت السيارة.. وذهبت مع الرياح.. في طريقي إلى المشفى."], ["لم أشعر يوما بتلك المسافة البائسة للطريق المؤدي إلى وجهتي، كان الطريقُ طويلا، كل شيء فيه باهتٌومكرر .. بالكاد كانت الساعة السابعة صباحا، إنعكاس أشعة الشمس من على الشارع الممهد ذو اللون القاتم تحرقُ عيناي.. أقود بيد، وأبحثُ عن نظارتي الشمسية التي أهداني إياها يوسف باليد الأخرى.. غفلتُعن الطريق لثوانٍ معدودة، وأنا مستمرةٌ بالبحث عنها.", "سمعتُ صوت بوقِ سيارة يعصف في ذهني ويكادُ يفتك بأذناي، نظرتُ للشارع بسرعةٍكبيرة، لحظات، سيارةٌ متوجهةٌإلي، سيارة من نوع “GMC” ذات حجم كبير.. يقودها عجوزٌ متصابٍ فظ. أغلقتُ عيناي، أمسكت المقود بقوة وأدرته إلى الجهة الأخرى..", "فتحت عيناي.. بعد أن تلاشت أمواج صوت البوق... هل أنا في الجنة؟ هل أنا على قيد الحياة؟!", "تحسستُجسدي.. ما زلتُ على قيد الحياة.. قلبي ينبض... رئتاي تتنفسان... وعقلي يفكر.. وصلتُ المشفى، نظرتُ إلى اللافتة الكبيرة بعينان مرهقتان غائرتان من شدة البكاء والتعب، “UCSFMedicalCenter” ، تابعتُ خطواتي نحو الباب.. فتح بشكل تلقائي، أكملت السير.. وقفت لحظة وفكرت لماذا أبكي؟ أو أن التوتر يأكلني وأنا على قيد الحياة؟!", "ربما هناك اجتماع طارئ، أو زيارة مفاجئة من وفد أجنبي.. لماذا نفكر فقط بالأشياء السيئة؟!", "أتمنى أن يكون فقط ضغط عمل ولا شيء آخر.. ياه، إلى أين وصل بي الحال.. أتمنى ضغط العمل وألا يكون شيء آخر.", "وصلت إلى القسم.. لاقتني زميلتي \"أنجيلا\" التي قد هاتفتني صباحا.. عانقتني، وقالت بصوت خافت: آسفة عزيزتي.. يبدو أن \"أورورا\" تلفظ أنفاسها الأخيرة.. وطلبت رؤيتك.", "لم أحدثها ولم أنظر إليها حتى، مشيت في صمت.. لم أسمع شيئا فقد كنت أسمع صوت أفكاري السلبية البائسة تجول في أرجاء عقلي.. وصوتٌ يشوشها يهتف وينادي ريتا! هل تريدين المساعدة؟ لم أهتم، أكملت خطواتي وأنا أضرب الأرض.. خطوة خطوة.. وصلت إلى غرفة \"أورورا\" الغرقة رقم \" 303 \"."], ["كان البابُ مشقوقا.. لمحتها تسعل.. تجمع حول عينيها السواد.. كأنها سحابةٌ تنذرُ بهبوبِ عاصفةٍ كبيرة، تقدمتُ باتجاه سريرها.", "شعرت بوجودي.. توقفت عن السعال.. وقالت وهي لا تنظر إلي...ربما بسبب وهنِ جسدها الصغير: لقد انتظرتك طويلاً ماما ريتا.", "صدمة، أو شبه صدمة. حدثتها: أنا هنا حبيبتي. مسكت يدها الدافئة الصغيرة، وعبراتٌ تجري على خداي.. مسحتْ دمعوي، ولملمتْ خصلات شعري الصغيرة الخارجة من تحت الحجاب، وضعتها فيه وقالت: هكذا أجمل.. كما أعتدت عليك.", "لم أنطق بكلمة.. وزادت دموعي بشكل كبير.قالت: لماذا تبكين؟ ها أنا مسافرةٌ إلى أمي... على أي حال أنا مشتاقة لها، قالت تلك الكلمات وعلى شفتيها ابتسامة صغيرة.", "هززت رأسي.. وأنا أمسح دموعي، وبعد جهد جبار، قلت لها: وأنا؟! ألا تريدين أن تبقي بجانبي؟!", "رأيتُ دمعة تتسلل من تحت جفونها، زمت شفيتها وبدأنا البكاء سويا ... ذرفنا دموعا من شأنها أن تملأ محيطا.", "توقفنا عن البكاء.. لفترة قصيرة فقط.", "تمددت إلى جانبها، مسكتُ يدها الناعمة التي قد غرز فيها العديد من الإبر والمغذيات.", "قالت: ماما ريتا.", "هممتُ: أنا هنا عزيزتي أورورا.", "قالت هي: الأمر جميل.. كالتجول في حقول من زهور عباد الشمس. لا تقلقي، سنلتقي في الجنة.. أشعر بذلك.", "أغمضت عيناها الجميلتان.. ارتخت يدها الصغيرة وراحت في نوم عميق.. أبدي."], ["", "“4 EVER”", "\"ريتا\"", "كما سبق وقلت.. كم أخاف هذه الكلمة.. {للأبد}.", "ولكن في قلبي شيءٌ من الرضى.. لأنني قضيت معها أكبر وقت سويا.. كنت أحاول جاهدة ذلك، هذه أول جنازةٍ أحضرها منذ انتقالنا إلى هنا، أول جنازة على المراسم المسيحية.", "كنت متطرفة، أقف بجانب شجرة كبيرة أحاول أن أفرغ ألمي وأستند عليها.", "لم يكن الحضور غفيرا .. قلة فقط، ماذا تتوقع أن تكون جنازةُ طفلةٍ يتيمة؟", "حان وقت الرحيل.. أدرت ظهري للجنازة متوجهةا إلى سيارتي البغيضة.", "سمعتُ صوتا ينادي، هل هو من خيالي؟! أم حقيقي؟ سيدة ريتا.. سيدة ريتا انتظري من فضلك، قالت الراهبة القصيرة صاحبة الوجه المجعد.", "خذي هذه الرسالة من \"أورورا\" تركتها في عهدة دار الأيتام التي كانت تقطنها. شكرتها، وشعرت بيدها تربت على ظهري.", "مضيت في حال سبيلي...", "آه... إلى متى يدوم هذا الشعور..", "", "هامش الحياة", "\"أورورا\"", "\"سيدتي ريتا، أو كما تحبي أن أنادي عليكي ماما ريتا.", "ستعرفي بعض الأشياء في هذه الرسالة كانت مجهولةا لك من قبل، على ما أظن.."], ["ربما أفضلُ شيء حدث لي هو هذا المرض البائس.. أتدرين لماذا؟", "عندما كنت في دار الأيتام كان ينفرُ الجميع مني بسبب مرضي، كم كنت أتمنى أن أصرخ بأعلى صوتي، وأقول بأنَّالسرطان ليس بمرض معدٍ!", "حتى عندما كانت أمي على قيد الحياة.. كانت تثملُ كثيرا وتهملني للزمن القاسي... تقضي جلَّ وقتها تشرب وتتسكع مع رفاقها الفاشلين.", "هل الرب يحبها وأخذها إليه، كما قلت لكِ في أوَّل لقاء لنا؟", "أم أن الرب يحبني أنا وانتشلني من المعاناة التي كنت أواجهها؟!", "لا أدري.. كلُّ شيءٍ مسيرٌَّ ومقدر من عند الرب.", "الأفراح التي هي بعيونِ الآخرين أتراح، كانت أفضل أشياءٍ حدثت لي.. وأضافت الحياة إلى روحي الميتة، موت أمي.. السرطان.. السرطان.. الذي قدم لي أجمل هديةٍفي حياتي، تلك الهدية المغلفة بخيوط \"العفة\" – كما أخبرتني – التي تغطي رأسها وسائر جسدها.", "التي سدت مكان الأم الذي كنت أفقده .. صديقةٌ أشارك معها أسراري وتفاصيل يومي القصير، أنتِ.. أنتِ هي تلك الهدية، بفضلك عشتُ أجمل لحظاتٍ قبل رحيلي نحو الحياة الأخرى. آه.. كم أنا مطمئنة الآن، لأنني كنت خائفة أن أكون على هامشِ الحياة.. ومطوية بين الصفحات المتحللة.. التي سطرت أسماء الموتى، ولا أحد يتذكر وجودي.. فتاةٌ يناهزُ عمرها سبعة أعوام وأربعة أشهر وثلاثة أيام.. وترجو أن تعيش بضع ساعات قادمة لرؤية هديتها الأفضل.", "لن أكون هامشا.. سأكون حاضرةا بقلب أجمل الناس في المجرة.. عن تلك الراحة النفسية مثلا؟! لا تحزني، أنا مرتاحة ومطمئنة ... صلي لي بأن أدخل النعيم.", "دمتِ بخير ماما.. وداعا", "مع حبي، ابنتك \"أورورا\"", "دموعٌ تسيل .. فرحٌ أم حزن؟! حزن للفراق والشوق المبكر.. يسوده راحة وسرور، هل قالت هذا لكي تريح قلبي؟! أم أن هذه الكلمات صادقة نابعة من قلبها؟"], ["سوف أدعو لك كلَّ ليلة.. في كل سجود سوف يذكرك حسي ولساني.", "كم أكرهُالسرطان .. أخذ مني أغلى أشخاصٍ مروا في حياتي .. الدهر والسرطان.. متشابهان، يأخذان منا كل شيء ولا يوجد علاجٌ فعال لكلاهما ... اختبارٌ من عند الله..", "وما إذا أحبَّ الله عبدا.. ابتلاه.", "ركبت السيارة.. طويتُ الرسالة ودسستها بصعوبة في حافظتي، وأخذت أضرب المقود بشكلٍ جنوني، أفرغ شحنات غضبي... ظللتُ أضرب حتى آلمتني يداي.. وطغى عليهما لون الدم.", "كنت شاردةا وأنا أقود.. ما زالت الأفكار والذكريات تعصف وتعصف.", "شغلتُ الراديو، باحثةا عن شيء يشتت ويقطع حبل أفكاري المتين.", "أولُ محطة.. دعاية لشركة سياحة وسفر، بلا بلا بلالا أهتم،", "المحطة الثانية.. جمعية خيرية تساهم في جمع المساعدات المالية لمرضى السرطان.", "أدرتها بسرعة.. كانت ثوانٍ بائسة سيئة تذكرني بما أحاول الهروب منه.", "المحطة الثالثة.. كنت شبه مستسلمة فتركتُزر التبديل، كانت أغنية فتحت الجروح. أو بالأحرى زادت سرعتها وعمقها، لا مفر.. استسلمت للأمر الواقع – Alexandsierra لوتعلمقليلاً “Little do you know”", "Little do you know How I’m breaking while you fall a sleep Little do you know... I’m still haunted by the memories... Little do you know... I’m trying to pick myself up piece By piece … Little do you know"], ["I need a little more time... Underneath it all I’m held captive By the hole inside… I’ve been holding back for the fear That you might change your mind… I’m ready to forgive you but Forgetting is a harder fight Little do you know I need a little more time I’ll wait, I’ll wait … I love you like you’ve never felt the pain … I’ll wait … I promise you don’t have to be afraid … I’ll wait … The love you see right here stay … So lay your head on me … Little do you know … I know you’re hurt while I’m sound asleep … Little do you know … All my mistakes are slowly drowning me ... Little do you know … I’m trying to make it better piece by piece …"], ["Little do you know … I love you till the sun dies … لو تعلم قليلاً ...", "كم اتحطم عندما تنام ...", "لو تعلم قليلاً ...", "لا أزال متمسكة بالذكريات ...", "لو تعلم قليلاً ...", "أنا أحاول أن أجمع نفسي قطعةا قطعة ...", "لو تعلم قليلاً ..", "أنا أحتاج القليل من الوقت ...", "تحت كل هذا ... أنا محتجزة داخل حفرة ...", "لقد تغلبت على المخاوف التي غيرت رأيك ..", "أنا مستعدة لمسامحتك ، لكن النسيان أصعبُ من الصراع...", "لو تعلم قليلا ...", "أنا أحتاجُ إلى القليل من الوقت ...", "سوف أنتظر، سوف أنتظر ...", "أنا أحبكِ وكأنكِ لم تشعري أبدا بهذا الألم ...", "سوف أنتظر ...", "أنا أعدكًِ...ل ينبغي بأن تكوني خائفة ...", "سوف انتظر ...", "هذا الحب هنا ... ويبقى هنا ..."], ["لذا ضعي رأسكِ علي ...", "لو تعلمي قليلاً ...", "أنا أعلم أنكِ تتألم ين عندما أتظاهر بالنوم ...", "لو تعلمي قليلاً ...", "كل أخطائي تغرقني ببطئ..", "لو تعلمي قليلاً ...", "أنا أحاول أن أجعلها أفضل قطعةا ... قطعة ...", "لو تعلمي قليلاً ...", "أحبكِ حتى تموت الشمس ..", "", "فكتوريا", "فيكتوريا؟ ماذا ينقصها ؟! إنها تملك كلَّ شيء!", "كلماتٌ تخرج من أفواه الناس الكريهة.. كلماتٌ تتردد كثيرا .. ربما لا يجبُ عليَّ أن ألوم أحدا على تصوراته.. لطالما كنتُ أُظهر \"المثالية\" الكاذبة للناس.. حسنا، لا يدري ولا يشعر أحدٌ بالألم، إلا الذي يعيشهُ ويختبرهً..ل يحسُّ أحدٌ بنزفِ القلب إلا الجسد الذي يحتجزه بين ضلوعه.", "انفصل والداي منذ أسابيع .. أظنُّ أن هذا كان قرارا متأخرا جدا .", "كان يجب أن تقع كارثة طبيعية وتعكر صفو لقائهما الأول، ولا يقعا بالحب الوهمي السخيف الذي أجبرا نفسيهما لكي يختبرانه.."], ["انتقل أبي إلى شيكاغو، أفتقده جدا .. كان أفضل من أمي بمراحل، لكن الوصاية بهذه الحالات تكون للأم.", "لا أقول أنَّ أمي سيئة ... بل علي القول بأنني لستُضمن برنامج أولوياتها العظيم!", "مثلاً أنا أم جلسةُ عناية البشرة؟!", "الأولاد يعوضهم الزمن، لكن الجمال والشبابلا.", "الثانوية وكرٌ للأوغاد.. تحتوي على أشخاصٍ قلةٍ صالحين.. ولكن الأغلبية سفلةٌ ومدمنو مخدرات.", "أعترفُ بأنني تغيرت جدا.. لا أدري كيف حالت الأمور وأصبحتُ أكثر الفتيات شعبية وجمال، صداقات تافهة، كل ما يهم هو الموضة والتسوق ومواقع التواصل والنزهات السخيفة وكل شيء غير مهمٍ وتافه.", "أحاولُ التغير الآن. أحيانا يجب عليك أن تمضي للوراء؛ لأنك قد تجاوزت جادة الصواب بمراحل كبيرة .", "إرجع لها وإن تعثرت وسقطت ودُّق عنقك.. أقلُّها مت وأنت تحاول.. أفضل من المضي في الفراغ! اخرج من \"اللامكان\" إلى \"المكان\".", "طموحي؟! قد تبدو طموحي للآخرين غير مناسبة لشكلي... بل يجبُ أن أكون محشوة بالتفاهة والسذاجة، مرحبا! أنا صاحبةُ عيون زرقاء وبلهاء.", "كنت دائما أسيرة حبٍلعلم الفلك .. النجوم .. الأبراج .. الكواكب.. الشمس والقمر.", "أحبُّ الكلاسيك كثيرا ... أتخيلُبيتي كوخ متوسط الحجم مع أرضية خشبية، أرقص عليها أنا وزوجي الوسيم الطويل الـ ( slow )، ممم.. أعتقد أن “Ed-shareenperfect” هي أغنية أكثر من مناسبة!", "تحف وكتب... بكل مكان، لوحاتٌوزهور وبيانو، اقتناء كلب من نوع هاسكي، نلعبُ سويا ويجرُّ عربتي في الثلج."], ["آه، كما قال مستر سلطع في سبونج بوب \"إستمر في الحلم.. فهو مجاني\".", "أنا مؤمنةٌ بوجودِ ذاتي، حتى لو كانت بين النجوم سوف أمسكُبها وسأسافر للنجوم إن لزم الأمر، ربما غدوت الفتاة الوحيدة الغير مرتبطة... شبابُالثانوية أغبياء وتفوحُ منهم رائحةٌ نفاثة أسميها بـ \"الفشل المحتم\".", "لكن أشعرُبشيء تجاه شخصٍ ما.. لا أدري ما أسميه، ربما إعجاب أو شيء يتخطاه بقليل... بصراحة لم أكن متوقعة هذا، لكنه شعورٌ جميل.. وأنا أتركه يتمدد ويكبر داخلي كما يريد. فادي، كان دائما مختلفا عن باقي الشباب، يحب القراءة جدا مثلي، والأغاني الكلاسيك.. وهو شديدُ اللطف والوسامة! طويلٌ جدا، عيناه خضراوان، إنهما تأسراني، أشعرُ بأنني محاطةٌ بجذوع الشجر من كل اتجاه..", "أصلهُ شرقي، لا بأس بالبهارات الشرقية! فأنا متيمة بها. كما أنه مسلم، وأنا مسيحية، لكن لن تقف الديانة حائلاً بالنسبة ليً،ل أدري بما أتحدث.", "الإعلام الغربي بشكل عام يجسد لنا صورةا غير التي أخذتها عن فادي، ليس إرهابيا أو متعصبا! كما أنه مليءٌبالأخلاق الحميدة .. لطيف ومتطلع وذكي، لا أعتقد بأنه مجرد إعجاب .. ربما حرب نفسية في داخلي، أو مجرد حرب ... ولكن دون الراء.", "", "سارة ولوسيان", "من بعيد .. قد تظنُّ أننا أفضل صديقات، لكن عن قرب الأمر ليس كذلك. لم أكتسب منهما إلا بعض الأشياء السخيفة، كمجموعة من طلاء الأظافر صعب الإزالة، وحب العطور الثقيلة. هل أشعرُ بالغيرة منهما؟! صدقا لا، أعلم بل متأكدة أن لكلٌّ منا ما يميزه.. وكلٌّ منا جميلٌ بطريقته..", "حسنا، ربما هي شيءٌ قريبٌمن الغيرة، سمعتهما يتهامسان ويتحدثان عن فادي، يقولان أنه مثير، كم كنتُ أريد أن أقتلع عيونهن البائسة وأرميها في المرحاض. ربما ليست غيرةا. لا أدري.", "لا أعلم إلى أين أمضي، لكن سأجدُ الطريق... ربما متأخرة، لكن سأجدُه."], ["لا أعلمُ إلى أين سأصلُ أنا وفادي، ربما يعتبرني مجرد صديقة، وأنا فخورةٌ بصدقاته الرائعة. عندما تكون مراهقا، تشعرُ بأن كل شيء قد أغلق في وجهك وأنها النهاية، وهذا صحيح.. إنها النهاية، لكنها حياةٌ طويلة نسبيا، مليئةٌ بالأجزاء الجديدة.. نهاية... تتبعها بداية ... وهكذا حتى يموت المخرج أو البطل.", "", "فادي", "انتهت عطلة نهاية الأسبوع، كانت قصيرةا جدا وتسربت بهدوء تام.", "جهزتُ نفسي للمدرسة، ارتديت قميصا أخضر وبنطالا بلون بني فاتح تقريبا. أبدو كشجرةٍ متحركة ربما، لا أدري لم أستطع رؤية نفسي في المرآة لطولي الذي يبلغ 190 سم فقط، شيءٌ جميل أن تكون طويلاً، بإمكانك قطف الثمار بسهولة، ورؤية تحركات الجميع الذين يبدون أقزاما بالنسبة لك، ولكن هناك سلبيات أيضا، إذ لا يمكنك أن تلعب على الدراجة التي في النادي إلا وأنت جالس، خوفا من ضرب رأسك بالسقف.", "وأن تتجاوز باب المواصلات العامة بسلام، أذكر أنني ضربت رأسي بشدة مرةا، ورأيت فتاةا تضحك وتكتم ضحكتها حتى أن القهوة خرجت من أنفها! يا للإحراج.", "غيرت تسريحة شعري، مممم هكذا أفضل.", "ودعت أمي بسرعة وقبلت يدها وخرجت مسرعا، كانت الحافة تنتظر في الخارج، صعدت إليها، وقلت: مرحبا سيد ماثيو، هل تأخرت؟! مع أنني أعرف إجابته. قال: لا بأس، تأخرت ثلاث دقائق ونصف أيها البائس! لا تكررها وإلا ... !", "أجبتُهُ بتهكم: وإلا؟!", "رد السيد ماثيو: بالله عليك! هيا ادخل لقد تأخرنا بما فيه الكفاية.", "أخذتُ أتفحص الحافلة بعيناي وأبحثُ عن مقعد شاغر. لمحتُ فكتوريا تطالعني وتبتسم، ثم أشارت لي بيدها. تابعتُ خطواتي نحوها، ألقيتُ عليها التحية ثم جلستُ. سألتها عن حالها، قالت بأن كل شيء على ما يرام. لكن في أعماقي أشعرُبالعكس."], ["رأيت جهاز “Ipod” في يدها، سألتها عن الأغنية التي كانت تسمعها، أجابتني أنها كانت تسمع أغنية “Happier–Marshmello” ، رددت أنا : أوه، إنها جديدة أليس كذلك؟!", "قالت: نعم! نزلت على الـ (Itunes) قبل أيامٍ قليلة فقط!", "أخبرتها بأنني أحبُّ أغاني الـ (pop) جدا، ومارشميلو دي جاي رائع، لكنني أحبُّ فرقة the “ ” Chainsmokers أكثر، إنهم أشخاص يجيدون صنع الموسيقى ببراعة.", "قالت لي وهي تبتسم: يا إلهي! وأنا أحبهم جدا!", "وبالصدفة كنا نحبُّ نفس الأغنية لهم، نحن متشابهان جدا... يا رجل إنها تحب “Somethingjustlikethis” ! أكملنا حديثنا الشيق حتى وصلنا المدرسة، وأسوء شيء يمكن أن يحدث لك أن تبدأ يومك بصف الرياضيات.", "كنت أجلس أنا وآندي، نتبادل أسماء ألعاب الفيديو الجديدة والأغاني الحديثة، كان الطلاب شبه نائمين، أو كذلك كانوا.", "أحسستُ بيدٍتدق على كتفي وتناولني قصاصة ورق صغيرة، كانت لوسيان، ناولتني إياها وهي تهمس.. من فكتوريا.", "انتبه آندي وشعرتُ بأن عيناه تريد التتسلل لترى ما كتب على القصاصة التي بين يداي. مثلتُ أنني لم أنتبه، وتجاهلت أمره، انحنيت لجهة اليسار قليلاً وفتحتها: كُتبِ فيها:", "“yOu l00KE hAnDSomE tODay! KEep Move!” kIsS aND HUG “vIctORiA” احمر وجهي جدا، ببطء نظرت نحو مقعد فيكي، رأيتها تبتسم، ثم أشاحت بنظرها نحو الكتاب وهي تلعبُ بخصلات شعرها الناعمة.", "كنت قدلاحظت أسلوب كتابتها الغريب من قبل، وسألتها عن السر في أحد المرات.", "أجابتني بأنها تؤمن بالعدل والقدرات، وهي مع نبذ العنف والظلم، لذلك لماذا نضع الحروف الصغيرة في المنتصف والنهاية؟!", "كل له منزلة عالية، ويحتل حيزا كبيرا في مجرة درب التبانة!"], ["ضحكنا سويا يومها.. ولكن صراحة أعجبني أسلوب تفكيرها اللطيف.", "", "\"حيتان بكل مكان\"", "بعد يومٍ دراسي مليء بالأرقام والملل الذي يدفعني للجنون، قررتُ الاسترخاء ونسيان العالم الخارجي قليلا.. بل كثيرا... كثيرا جدا !", "وأفضل نافذة يمكن لي أن أخرج منها إلى العالم الآخر،الذي هو أفضل من عالمنا بأشواط، هي نافذةُ يوسف، وعندما أقول نافذةُ يوسف أقصد كتاباته ورسائله المذهلة.", "لم تكن رسائل اليوم كسابق عهدها، كانت مختلفة بعض الشيء، مثلاً هي غير مخططة بالحروف... كانت عبارة عن منحنيات وألوان.", "وجدتُ مجموعة من رسومات يوسف.. كانت كلها عبارة عن حيتان. عددتها، وإذ بعددها يتجاوز الثلاثين.. حوتٌ أزرق، حوتٌ أحدب، حوت العنبر، والكثير منها.", "أنا لا أعرف شيء عن الحيتان سوى أنها تعيش في الماء وحجمها ضخم، أما بالنسبة للأسماء فقد قرأتها عن ظهرِكل رسمة.", "لم أر من قبل شيءا كهذا ... بارع الجمال.. متقنٌ جدا.", "كان الحوت هو الحيوان المفضل ليوسف، وكان يرسمها كثيرا ويكتب فيها، يجمعُ المعلومات عنها بشكل مبالغ وجنوني! كنت أظن أنه نصف حوت!", "أما أنا كنتُ أريد أن أكون نصف ذئب، ويفضل أن يكون رماديا وضخما، أركضُ في الغابة بلا قيودٍ أو خوف، أشعرُ بالهواء يتسلل إلى فرائي، انتظر هبوط الظلام، وأطلق عواءا شديدا متواصلاً باتجاه القمر المكتمل، إلى أن أفقد صوتي..", "أعشق قصص المستذئبين، وأحلم دائما باقتناء ذئب صغير. ربما هو تأثير فيلم \"الشفق – \"twilight"], ["أتذكر لحظات.. أو بالأحرى دقائق معدودة، لا تتجاوز الـ 13 دقيقة. كانت إحدى المرات القليلة التي كنت بجانب يوسف فترات مرضه الأخيرة.", "كنت مستيقظا الساعة الواحدة بعد منتصف الليل ومعدتي تطلب الغذاء، على وشك هضم نفسها، ذهبتُللمطبخ وحضرت لنفسي شطيرة فولٍ سوداني.. وفي طريقي للعودة سمعت صوتا من غرفة يوسف، شيء يسقط ويرتطم بالأرضية.", "اقتربتُ من الباب، دفعت يدي اليسرى.. وقرعت الباب ببطء شديد.. وكنتُ أتناول شطيرتي باليد الأخرى.", "لم يرد علي أحد.. كررت القرع.. ولم يرد علي أحد مرةا أخرى، حينها قررت الدخول من غير إذن. وجدت يوسف يزحف على الأرض، محاولا أن يصل إلى سلة المهملات لكي يتقيأ، وهي أكثر الأعراض الجانبية شهرة للسرطان، الغثيان المستمر.", "وضعتُ شطيرتي على الرف المجاور للباب بسرعة وركضت نحوه، رفعته بصعوبة، وهو كان يحاول أن يلم قدماه ويقف عليهما. أوصلته حتى السلة، وأخذ يتقيأ.. هل شعرتُ بالحزن؟ شعور الأخوة النائم بداخلي، هل أفاق من سباته العميق؟ هل شعرت بالقرفً؟!ل أعرف.", "ظللت أشده حتى انتهى، وقف مجددا وعاودنا المشي إلى سريره، عندما استلقى على سريره نظر إلي بعيناه المرهقتان، ابتسمت شفتاه الزرقاء ووقال:لا بأس بأن نترك أثرا وراءنا دائما.. ولكن أثر جيد وليس كهذا القيء..", "لم أنطق بكلمة، اكتفيتُ بالاستماع.", "ثم قال: حسنا يبدو أنك لم تفهم ما أقصد، اذهب وابحث عن \"حوت العنبر\" وتذكر كلامي جيدا لِتربط بينهما .", "", "\"حوت العنبر\"", "تذكرت تلك الحادثة حالما رأيتُ الحيتان التي قام برسمها يوسف."], ["فتحتُ الـ ( Imac ) خاصتي – معلومة: كان هدية في ميلادي السادس عشر من بيتِ جدي – أدخلتُ كلمة المرور، نقرتُ على نافذة غوغل وبحثت عن حوت العنبر.", "أغلبُ المعلومات كانت عن حجمه ووزنه وأين يتواجد، وكم عددها الآن وما إلى ذلك.", "شعرتُ بالملل قليلاً.. ولكن لم أيأس واستمريتُبالبحث لكي أجد مرادي، لا يقول يوسف شيئا عبثا.", "بعد تقليب ما يعادل 83 موقع مختلف وبعض الفيديوهات، تمحصت قليلاً في موقع.. وقرأتُ ما فيه بروية، كان يحتوي نفس المعلومات التي في المواقع التي قبله، لكن وأخيرا فهمتُ مقصد يوسف.. عطر العنبر.", "قبل أن يموت هذا النوع من الحيتان، تنبعثُ من جوفه رائحةٌ زكية جدا اسمها \"العنبر\" وهي سبب تسميته، لذلك قال لي يوسف اترك أثرا طيبا.. كحوت العنبر تماما.. مع أنه حيوانُ مفترس، وأعتقد أن الأسماك الصغيرة تنظر إليه كأنه كابوس... ووحشٌ فتاك يتمنون زواله.", "بأسنان تحتها أنياب.. وتحت الأنياب صفٌّ احتياطي.. لذلك لا يحتاج الحوت إلى أن ينتظر مطولا راجيا معاينة طبيب الأسنان.. فبوجود هذا الكم الهائل من هذه الأسلحة البيضاء.. تغلب على أكبر الكتاب الذين قد مروا تحت أجهزة التفتيش وهم يحملون نصل القلم. تخيل أن تكون في وسط فك كبير كأنك مقبلات غير دسمة.. وهل تظن أن \"نيمو\" سيجدُ الطريق... بما أن \"دوري\" عندما ترى الحوت سيرجع لها شريط ذكرياتها بسرعة الضوء؟", "لكنه يتركُ أثرا طيبا، ربما يحاول أن يصحح أخطاءه بتلك الرائحة الجميلة.", "قيء.. وأثر.. أثر.. وقيء.. قيء البشر.. ناتج عن انقلاب الوظائف الحيوية للجسم، أثر سيئ. ولكن القيء \"الجميل\" ليس من البشر، بل من حوت العنبرً.ل تستطيع أمعاء حوت العنبر أن تهضم كل ما يأكل.. وكل ما يعلق في جوفه. لذلك تقوم أمعائه بإفراز مادةٍ معينة، تحميه من الداخل من تلك المواد غير المهضومة والعالقة.", "وبعد فترة يقوم حوت العنبر بِتقيأ تلك المواد وطرحها في البحر."], ["وعندما يجدها الصيادون أو أي شخص على الشاطئ بسبب المد والجزر، يكون محظوظا جدا! وأصبح في عالم الأثرياء، لأنه وجد قيئا!!", "لا تبدو كل الأمور واضحة من النظرة الأولى، كنافذةِسيارة تجمعت عليها حبيبات المطر، وشوش الرؤية بخار الماء المتكاثف على سطحها.", "قيء يجعلك ثريا، أو يحملُِ بين سوائلهِاللزجة علاجا يستخدم في بعض المضادات التي قد تشفيك بعونِ الله.", "الإنسان نادرا ما يترك وراءه أثر حميد، يخلف وراءه الحروب، أمٌّ تبكي لأنها لم تستطع أن تودع ابنها فلذة كبدها.. طفلٌ محروم من دفء العائلة.. أمه.. أبيه. عجوزٌأو شيخٌ؟.. لم يعترف البشر بالعمر، كلُّ سواء تحت زناد البندقية.. تحت أجنحة طائرة حربية، تنفث الهواء الذي يكتم الأنفاس ويخنقها، الجميع يذل ... العمر؟ مجرد رقم.", "حوتٌ أم بشري؟! الحوت حيوان مفترس، ويفتك بالكائنات الحية الأخرى أليس كذلك؟!", "حسنا، ماذا عن الجنس البشري؟!", "حوادثٌ معدودة.. وشحيحة حين قام حوت بقتل إنسان، حدث ولكن قليل.", "لكن الإنسان؟ ضاقت به الدنيا وانتهى لحمها حتى أصبح يتغذى على لحم \"الوحش\"، على لحم الحوت.", "بشكل أو بآخر، تجمع النفايات الصلبة وبقايا البلاستيك، تقوم بقتل عشرات الحيتان والأحياء البحرية الأخرى سنويا! هل تفضل أن تكون \"حوتا كاسرا\" أم بشري؟", "في تلك اللحظة، تمنيت أن أحمل جينات حوت في أحشائي.", "", "\"يوميات حوت\"", "أبحرُ في المحيط الكبير... أطلق الماء خارجا من الفوهة الموجودة أعلى رأسي."], ["صدى صوتي يمر، ويقطع آلاف الكيلومترات دون عناء.. صوتٌ تقشعر له الأبدان، معزوفتي الخاصة. أضربُ الماء بلطف، بخفةٍ ورشاقة، بذيلي وزعانفي الضخمة. خطواتٌ سريعة، أدفعُ بجسدي الضخم إلى خارج الماء.. مقدمةُرأسي أولا، تعانق نسيم المحيط اللطيف، أداعبه بأنفي الكبير، وسط جسدي الرطب.. كأنه قد مُلأ ونُثر عليه ملايين المجسات الحسية، باقي جسدي يخرج للسماء ... لثوانٍ كنت معلقا بالهواء.", "جمعتُ كمية من الهواء داخل رئتاي العملاقتان، نزلتُ إلى الماء بسلاسة بجسدي الانسيابي. ظلٌ كبير هبط في وسط المحيط.. إنها سفينة بشر.على متنها بحارة مختلون عقليا، ما زالت آثار الثمالة والشرب عليهم. يطلقون الدعابات غير المضحكة، ومع ذلك يضحكون.", "قبطان، عجوز مريع.. بائس وكئيب. صدره كبير وأكتافه واسعة. يده حلَّ مكانها خطافٌ حاد، ساقٌ واحدة، وأخرى خشبية، ذقنٌ أشعث شائب مخيف، إلى أين أُبحر؟! لا أعلم... ولكن أشعرُ أنني مجبرٌ على ذلك. أمضي في الفراغ.. أعلمُ بأن نهايتي قريبة، لا أعلم ماهيتها.. لكني مجبرٌ على خوضها، لا مفر. يجب أن أمضي ... لكي لا تتحلل زعانفي، يجبُ أن أحركها.. سأمضي حتى تضع حربي الناعمة أوزارها.", "أصواتُ صراخ غير واضحة بالنسبة لي، خيالات أشخاص مشوشة.. أخرجتُ رأسي قليلا، القبطان يطالعني بتلك النظرة التي يرمقها القاتل للضحية.. ابتسامةٌ صفراوية.", "رمح. هل هو في جسدي؟! أم مرَّ بسلامً؟!ل أعلم.", "قبل أن أسمح للقبطان أن يخرج ما فيه من إبداع ويصبح دافنشي على حساب روحي، ويلون مساحة الماء بالقاني، رأيتها مذعورة.. كانت تستميت حتى تدخل شبكة الصيد، على أن تقترب مني. سمكة ذهبية.. بعيارٍ صافٍ، دون تكاليف المصنوعية.. قطعتُ الشباك ورسمت طريقا وهميا لكل سمكةٍ في الأرجاء وقتها.. خفت أن أظل متوحشا على أبناء جنسي، في ظل وجود وحش فتاك أكثر مني متمثلاً ببشريٍ هزيل.", "دماء تلون أفق الماء. نصل اخترق جسدي، أيقنتُذلك متأخرا. بعدما شق جسدي واقتلع روحي. قلبي الكبير ينزف.. من يساعدني؟! روحي تصعدُإلى لسماء.. وجسدي يسحبُإلى لأعلى."], ["حمدا لله أنني لستُ إنسانا، متوحشا.", "", "\"فادي يكمل عن يوسف ورسوماته\"", "جمعتُ الرسومات كلها، وضعتها في صندوقٍ خشبيٍ لونه أخضر، كنتُ قد نويتُ أن أضع إطا ارا لكل رسمة، وأن أعلقها على جدران بيتنا، وغرفتي، ليكون شيءٌ من يوسف في بيتنا، وأن أجعل من غرفتي محيطا كبيرا يحتوي على عدةِ حيتان.. وأحميها وتحميني ترشدني. إلى سرِالحياة.", "كم جميل أن تكون محاطا بالحيتان من كل اتجاه.. أمرٌ بالغُ الجمال.", "", "\"ريتا\"", "تحسنت نفسيتي قليلاً... وبدأتُ بالتناسي شيئا فشيئا، أخبرت رئيس الفرع بحالي، لكي أنقل مؤقتا إلبى قسمٍ آخر، كان لقاءه صعبا، سأشرحُ له حالي بالتفصيل.. يوسف وأورورا، وكل شيء. كنتُ أتمنى أن أنقل لكي يلتأم جرحي فقط، وبعدها أرجع إلى مكاني.", "لم أر رئيس الفرع قبلاً طوال السنوات الثلاث والنصف. كنتُ أتخيلَّه رجل كبير بالعمر في نهاية العقد الرابع وبداية العقد الخامس.. أسنانه جميلة وابتسامته دافئة.. وشيبٌعلى جانبي ومؤخرة رأسه... متفهم ورقيق... صاحبُ قلبٍ كبير طيب، وسوف يفهمني بسهولة، ودون عناء، وسيحقق مطالبي وأكثر! كلُّ هذه السيناريوهات والتخيلات كتبتها ورسمتها.. أنتجتها وأخرجتها وعرضتها لنفسي قبل أن أدخل وأتجاوز عتبة مكتبه.", "طق.. طق، قرعتُ الباب مرتين متتاليتين ... دقيقة ونصف الدقيقةً،ل أحد يردُ. لا شيء.", "قرعتُمرةا أخرى، نصفُ دقيقة أخرى مرت. سمعتُ صوت من الداخل يقول: \"ألقي نظرةا على الباب يا جينفير!\"", "بصوتٍ غاضبٍ وعالٍ. انتظرتُ فينة من الوقت.. وبعد وقوفٍ طويل وعناء فُتح الباب، من قبل المساعدة الشقراء الجميلة. تضع أحمر شفاه فاقعا ومزعجا، وشعرها مسرَّح بشكلٍ متقن،"], ["طريقةٌ ارتداءها للملابس غريبةٌ قليلاً بالنسبة لشخصٍ يعمل في مستشفى محترم كهذا. أنا مشوشة. هل هذا أسلوب العاهرات أم أسلوب مارلين مونرو؟!", "نظرت إلي قليلاً، ثم أشارت لي بإصبعها لكي ادخل. دخلتُ المكتب الكبير والمليء بالتحف والديكورات الباهظة.", "كان يجلس على الكرسي وراء الطاولة شابٌّ في العشرين حسب تقديري، يضعُ سماعات رأس من نوع \" beats \"، سألتُنفسي هل هي أصلية أم تقليد من المركز التجاري الذي في منطقتنا؟!", "ويلهو ويلعبُعلى هاتفه “Iphone-X” حتما هذا أصلي. يضعُ قدماهُ على الطاولة، واحدة فوق أخرى، لم ينظر إلي كل هذا الوقت. شعرتُ بالحر فجأة، ولم أعرف ماذا أفعل.", "أصدرتُ جلبةا صغيرةا لكي ينتبه لوجودي، طالعني بنظرة غير مبالية، أكمل لعبهُ على هاتفه. ثم وضعهُ وقال باستهتار تام وخانق: بماذا أساعدك آنسة...؟!", "ريتا ... اسمي ريتا.", "حسنا يا بيتا، بماذا أساعدك؟!", "قلت أنا بصوتٍ خافت: شكرا لك مقدما، وبالمناسبة اسمي هو ريتا، ليس بيتا.", "رد بشيء من الاستهزاء: أيا كان، أخبريني ماذا أفعل؟!", "في تلك اللحظة أيقنتُأن تخيلاتي جاءت على العكس تماما. شاب مستهتر وسخيف.", "رويتُ عليه قصتي بالتفصيل، أخبرتهُ بأن الأمر بات أصعب من ذي قبل، وأرجو منه أن يتفهم الحال. وبعدما انتهيت، قلتُ له: هذا كلُّ شيء. رد هو: فقط؟ أهذا كلُّ شيء فقط؟! كدتُ أنام! لقد سمعتُ قصة حياتك.", "صدمني رده الجاف. وظهر على وجهي ملامح الاستغراب والاستياء.", "ثم أضاف: ولكنكِ طلبتي منذ فترة من رئيس القسم أن يثبتك في قسم مرضى السرطان أليس كذلك؟!", "هززتُ رأسي بأنني أوافقُهُ."], ["ثم قال: والآن تريدين أن تنتقلي إلى قسمك السابق؟! هل نحن في لعبة أم ماذا؟! هذا عمل محترم! ويجب أن تقدمي العون واحترام حرمة عملك قبل أي شيء! لا يمكننا أن نسير كل العمل تحت إرادتك!", "كنت أقولُ في نفسي: اصمت أيها الوغد! هل أنت أصم ولا تسمع بما تتفوه يا حقير! أخبر ذلك لنفسك يا نبع العون والاحترام. بائسٌ حقير. ولكني قلتُله: آسفة.", "أخذ ينفخُ الهواء بغضب ثم أصدر صوتا من فمهِ الكريه: حسنا لكِ ما تريدين. هذه آخر مرة. لم أقُل له شيء. أومأت برأسي ووقفتُ للمغادرة.", "بعدها قال: ريتا ... أقصد آنسة ريتا، ما ديانتك؟", "أجبته بفخر: أنا مسلمة، ديني الإسلام.", "رد هو بعدما أشاح نظرهُ وأسقطهُ على هاتفه اللعين: لاحظتُ ذلك من الشيء الذي على رأسك أو أيا كان.", "رددتُ عليه بسرعة: حجاب. إسمه حجاب.", "وخرجتُ وأنا غاضبة، وتعمدت أن أُظهر له غضبي.", "سمعتهُ يهمس: ما بها هذه؟! صراحةا معه حق الرئيس الأمريكي. جينفير! تعالي يا حلوتي.", "شعرتُ بالقرف، وذهبت بحال سبيلي.", "", "\"فادي الجديد\"", "عندما وصلت البيت كنتُ أعلم بأن هناك حفلة تنظيف تنتظرني، وعملٌشاق.. خرجتُ من تعبٍ إلى تعب.", "ولكن عندما فتحتُ الباب، كنتُ قد صدمت وظننتُأنني دخلتُ البيت الخطأ، خرجتُ إلى حديقة المنزل لكي أتأكد. نعم إنه هو."], ["دخلتُ مرةا أخرى، كان كلُّ شيء مرتب على أفضل حال. والأطباق المتُسخة في غسالة الأطباق، والأرضية نظيفة جدا.. كل شيء كان مرتبا.", "وفي وسط اندهاشي، لاحظتُ رسوماتِ يوسف معلقةٌ في كلِمكان.. أتذكرُ كل واحدةٍ منها، لكثرة تمعني السابق فيها حفظتُ تفاصيلها جيدا.", "ماما! متى وصلتِ!؟ هتف فادي.", "رأى دموعي.. تسقط.. سعيدة دموعي لأنها تسقط.", "قال: آه! ما بك؟! هل هناك شيءٌ يزعجك! اقتربتُ منه وعانقته.", "وقلتُ له: أنها دموع الفرح عزيزي.. دموع الفرح.", "سمعته يهمس: حمدا لله.", "ثم قال بصوت مسموع: هيا، بالتأكيد أنتِ جائعة جدا. مائدةُ الطعام تنتظر الأميرة الجميلة. قالها وهو يبتسم وتظهرُ أسنانُهُ الناصعة. في داخلي شيء يقول بصوتٍ رحب وهادئ وجميل جدا: \"إِنَّ مع العُسْرِ يُسْرا، إِنَّ مع العُسْرِ يُسْراا\" سورة الشرح.", "علمتُ أن الحزن والكرب يتبعه فرج وفرح ينتشلك من وسط حزنك ويضعك في وسط حقول من زهور السعادة، اقطف منها ما شئت.. ما خاب ظني بالله.", "", "\"فادي\"", "أعتقدُ بأنه قد نشأ بيني وبين فكتوريا علاقة جميلة.. مزيجٌ بين كل شيء؟...صداقة، أخوة، إعجاب، اهتمام.. والكثير من الحب.", "قد كان ذلك اليوم يوم مولد آندرو.. وبما أننا قد أصبحنا في الثانوية.. ونرتدي الحقيبة المدرسية على كتفٍواحد–كم أكرهُهذا التقليد وضرره على العامود الفقري والجسم بشكلٍ عام–، قررنا أن نقيم \"سهرة\" خفيفة وليست حفلة.. دعاني آندي والعديد من الأصدقاء.. فكتوريا.. سارة ولوسيان... والكثير... ولكن الأهم هو حضور \"كريستوف\" ابن عم آندي، تذكرونه؟ كانت تلك"], ["\"السهرة\" في مزرعةٍ ملكٌ لأهل آندي، تقع في إحدى بقاع غرب كاليفورنيا، ليست بعيدةا كثيرا ... 20 دقيقة في السيارة.", "على حسب ما أظن سوف نبيت فيها... أولاً هاتفت والدة آندي أمي وأخبرتها بكامل الإحداثيات والمعلومات وأدق التفاصيل. وبعد ساعتين من الحديث المتواصل، أظن أن أمي اقتنعت.. أمي تخاف علي جدا وتحب التأكد من الأمان التام.", "سألت أمي: ماذا جلبت لآندي؟ كهديةٍ بعيد ميلاده؟!", "أجبتها: آندرو يحب النظارات الشمسية جدا جدا ويمتلك العديد منها، وأذكر إخباره لي بأنه يريد أن يضيف نظارة جديدة من نوع ( Dior ) لأنه قد جمع الكثير من نظارات (Ray-ban) و(Zara) ردت أمي وهي متعجبة وترتب الزهور على المنضدة: ممممم.. هوايةٌ غريبة جمع النظارات، لكنها مثيرة للاهتمام أقر بذلك.", "قطع حديثنا أغنيةٌ عاليةٌ نسبيا...", "Welcome to the hotel California.. such a lovely place.. such a lovely place. كانت رنة هاتفي... أخذته وأنا غيرُمكترثٍ، أمسكتُ الهاتف بيدان ضعيفتا القوةُمختزلة منها، وعندما رأيتُ اسم المتصل.. توسعت حدقتا عيناي.. وشعرت بالدم يجري في عروقي ويغذيها.أحكمتُ القبضة عليه.. فكتوريا..", "كان المتصل \"فكتوريا\"، عددت للرقم 3، وأخذتُ نفسا عميقا.. وزفيرا قويا بعثر الزهور التي رتبتها أمي على المائدة.", "ردت هي على الهاتف: مرحبا؟!", "قلت أنا مسرعا: أنا هنا.. فيكي.", "قالت بصوتٍ خافت: هل اتصلتُ بوقتٍ غير مناسب؟!", "رددت بدوري أنا:لا لا! كل الأوقاتِ مناسبة.", "أخذت تضحك تلك الضحكة اللطيفة."], ["ثم قالت: أمي مشغولة، كالعادة.. هل يمكنني أن أرافقك إلى مزرعةِ آندي؟! أم أن الخالة ريتا سوف تعارض؟!", "قلت لها بسرعة الضوء: لا بل سوف يروق لها ذلك جدا! أهلا بكِ!", "أخبرت أمي بشأن فكتوريا، وكما توقعت لم تمانع بتاتا بل رحبت بها بشدة، صراحةا بشدة لم أكن أتوقعها.", "ارتديت ملابسي بعناية ودقة شديدان، وكالعادة تسريح شعري شديد النعومة ما زال بمثابة حرب لي. سمعتُ صوت جرس الباب يرن.. وخطوات أمي المستعجلة وهي تهتف بأنها في طريقها لفتح الباب. كنت أعلم أنها فيكتوريا التي كانت على الباب.", "رششتُ أفخم العطور وحملتُ هدية آندي ونزلت من على الدرج، متوجها إلى أمي وفكتوريا لكي نهم بالخروج إلى المزرعة.", "", "\"سهرة المزرعة\"", "كانت المسافة قصيرة جدا، ولكن كانت تحمل العديد من المواقف الجميلة بالنسبة لي.. رغم بساطتها وطفوليتها بالنسبة إلى مراهقين بالثانوية.. أنا وفكتوريا.. كإلحاح فيكتوريا بأن أتابع القمر بعيناي.", "وعندما وصلنا ودعتُ أمي وقبلت يدها، وقامت فيكتوريا بتقبيل وعناق أمي.. حينها ارتحت نفسيا... إن أمي وحبيبتي متوافقتان! أقصد صديقتي.", "كان التوأم بيكرز على الباب وآندي يرحب بهما، صافحت آندي وعناقٌ سريع مع المعايدة عليه ليوم مولده.. أما فيكترويا لم تكن إلا صديقة بعيدة له.. وهو لها كذلك، لذلك اكتفت بمصافحته سريعا، ومع ذلك شعرتُ بأن غيرتي عليها تخنقني.. يا إلهي جينات الرجل الشرقي تقيم حفلة صاخبة داخلي.. حاولتُ تشتيت نفسي وألا أفكر بهذا الأمر. ونجحت في ذلك، بعد جهد كبير."], ["دخلنا إلى البيت الصغير الذي في وسط المزرعة وكان عدد الحضور متواضعا جدا.. كما اعتدت على آندي، رغم شعبيته وحب الكثير له إلا أنه لا يحب الزحام والإزعاج.. وأنا كذلك، أحب الهدوء.", "جلسنا في الغرفة التي بها الموقد، وتسامرنا وتحدثنا في شتى المواضيع وجوانب الحياة.. الدراسة الطموح.. السفر.. المستقبل.. السياسة.. وكل شيء.", "اقترحت لوسيان بأن نلعب لعبة الجرأة والتحدي، وأنا – بما أني كتوم للغاية – لا أحب هذا النوع من الأنشطة. أمسك آندي بالزجاجة الفارغة بحزم وقوة وقام بتدويرها.. وهي أخذت تدور.. وتدور.. أدعو بألا تقف عندي.. نظرتُ إلى الشخص الذي يجلس مقابلي.. ياه! اللعنة! من قام بإجلاس فيكتوريا هنا!", "أخذتُ أدعو الله بسري ألا تقف وهي تدور.. أخذت تتباطأ شيئا.. فشيئا.. وحصل الذي كنت أخاف منه.. وقفت بيني وبين فيكتوريا.", "رمقتني فيكتوريا بنظرةِ نصر وضحكة جميلة جدا يشوبها بعض الشر.. وقالت: هاه.. يا فادي العزيز.. الجرأة، أم التحدي؟", "بدوتُ صامتا من الخارج.. ولكن كان عقلي مشغول بتحليل الكلام.. ويحاول البحث عن الإجابة المناسبة. صوتٌ ما في داخلي، أو صوتان بالأحرى أحدهما يقول: التحدي يا رجل! إن القيام بالشيء أسهل من نطقه!", "وصوتٌ آخر طغى على الصوت الأول ويقول:لا تستمع إليه.. الجرأة أفضل حل.", "بعدها سمعت الأول يقول ويصرخ:لا! التحدي! التحدي! التحدي!", "الجرأة! صرخت بصوتٍعالٍ ألجم الجميع.. قالت فكتوريا كالقطة الجائعة: ممم، حسنا أخبرنا يا فادي الوسيم هل هنالك فتاة أنت معجبٌ بها في هذه الغرفة؟!", "سكت الجميع وعم الهدوء.. أخذ الجميع ينتظر الإجابة بفارغ الصبر، يا إلهي! ألهذه الدرجة هذا أمرٌ مهم!", "وفكتوريا! كأنها لا تعلم أنني أحبها! بل أقصد معجب بها.."], ["نظرتُنحوها.. كأنها كانت تقول أنها تعرف الإجابة ولكن تريد سماعها من فمي..", "سارة ولوسيان وأغلب الفتيات ينظرن إلي تلك النظرة التي في السينما.", "بعد دقيقة تقريبا من الحوار الداخلي الخارجي العنيف قال آندي: هيا يا رجل! قلُها فحسب.", "شعرتُ بوجنتاي تحترق... وبحبيبات العرق تتجمع على جبيني.", "لم أقل شيئا بتاتا.. أشرت بسبابتي إليها.. إلى فكتوريا.", "", "\"موسيقى وحلوى المارشيميلو\"", "تجمعنا حول النار جميعنا، كنتُ أراقب ألسنة اللهب الجميلة وهي ترقص على ألحان قيثارة آندرو البنية... يعزف ويغني بصوتٍ كاد يغلبُ لهب النار دفئا.. يغني أغنيةا تذكرني بالكثير، “careless whisper” بيوسف..أغنية", "من الذي قال بأن الأغاني القديمة مملة؟!", "كان الجميع مشغول بإمتاع أذنيه ويستمع إلى تلك الموسيقى العذبة. وفي حين كان الجميع مشغول بنفسه.. كنت كالجميع مشغول بنفسي.. وبما أن فكتوريا أجزاءٌ مني.. كنتُمشغولا بها أيضا.", "مرت الدقائق ببطئٍ سريع! كلُّ دقيقة لها طعمٌ ورائحة.. تناولنا المارشيميلو الطري بسعادةٍ غامرةٍ. كانت الساعة تناهز التاسعة والنصف حسب ما أعتقد، رن هاتف آندي.. أجاب على المتصل وقال: مممم.. هل وصلت البيتزا؟! ها أنا في طريقي لأفتح الباب، وهم بالوقوف.", "لمحتُ فيكتوريا تطالعني بنظرةٍ لم أعهدها قبلاً.. نظرة.. مجردُ نظرة كفيلة بإشعاري أن هنالك شيء في الحياة يستحق العناء.", "سمعت صوتا خلفي، صوتٌ مألوفٌ بالنسبة لي، صوت يقول: من يريد البيتزا، والفرح يا جماعة؟! إلتفتُّ إليه بسرعة، كان مفاجأة الليلة.. كريستوف. أحسستُ بعضلاتِ فكي تتمزق من شدةِ سعادتي، “HeyFive” سريعة وعناقٌ طويل.."], ["أنا مؤمنٌ بالحب من النظرة الأولى. وحين أقول \"حب\" ليس شرطا أن يكون بين ذكر وأنثى؛ لأن البشرية عرفت الكثير، وما زالت تتعرف على أنواع الحب، حب الأم لأبنائها.. حب الصديق لصديقه والأخ لأخيه. ولكن الغريب بالأمر، هل من الممكن أن يقع أحدٌ بحبنا كما نحن؟! حتى إذا عرف الجانب المظلم من أنفسنا؟!", "أتذكرُ أول مرةٍ رأيتُ فيها فيكتوريا، أتذكرُ ذلك اليوم جيدا، معرض... لوحات... ندوب.", "كانت تملك ندبةا شديدة الصغر تحت أنفها.. تحت الجزء الأيسر بالتحديد. الندوب والجروح ربما يعتبرها البعض عيبا.. ولكن هل أكون صادقا إذا قلت أنني أحببتُ تلك الندبة قبل أن أقع في حب صاحبة الندبة؟! ويا ليتها كانت ندبةا دائمة.", "الساعة 11:40 ليلاً، الجميع خلد للنوم.. إلا أنا. كنتُ أجلس خارجا أتأملُ السماء المكسوة بالنجوم.. إنها صدقا لـ\"ليلةٌ مليئة بالنجوم\".", "سمعتُ أحدهم يتمتمُ من وراءِ ظهري. ألن تنام أيها المشاكس؟!", "لم يأخذ عقلي الكثير لكي يتعرف على صاحب تلك النبرة. لم أدِرْ ظهري حتى. قلت: تعالي يا فيكي وشاركيني هذا المنظر.", "جلست بجانبي وقالت: ما هو حيوانك المفضل؟ أخبرتها \"الحوت\"", "قالت هي: حسنا، هاتِ يدك.", "مددت إليها يدي.. أخذتها وحركتها باتجاه السماء. حركةٌ لطيفة خفيفة... رشيقة وقصيرة.", "نسجت النجوم لكي تُكون حوتا يسبح في السماء... ثم أكملت: وهكذا أنُجزت المهمة.. حوتٌ للسيد فادي.", "شعرتُ بوجهي يحترق... كل الدم صعد إليه.", "ثم حاولتُ إخفاء خجلي وقلتُ لها ما هو نجمك أو برجك المفضل؟", "قالت بصوتٍ بارع الجمال: إممممم. ما رأيك بأن نبتكر برجا خاصا بنا؟", "قلت لها: وكيف ذلك يكون؟!"], ["قالت: ما رأيك بأن نربط بين الشامات التي على وجهك؟ ومررت إصبعها على وجهي.. توقف قلبي.. ثم عاود ينبض.", "فكتوريا: فادي، ما هو الحب؟! أتريد معرفته؟", "", "\"قريةٌ حيثلا قضاء لها\"", "في أحد الأزمنة، وفي بقعةٍ على كوكبنا، كان يقنتُ هناك العديد من العائلات كلُّ منها يملك اسما من الأخلاق والرذائل.. أو حتى المشاعر.", "كانت إحدى العائلات عائلة \"الشوق\" و\"الطيبة\"، كانت الأم \"الشوق\" تنتظرُ بفارغِ الصبر أن تضع مولودها.", "وفي إحدى الليالي اللطيفة، والنسمات الربيعية الهادئة التي تبعثُ الطمأنينة في نفوس الحاضرين.. ولدت \"الشوق\" وتعالت صرخات الطفل وسط الحضور.", "هتف الجميع بالمباركات والضحكات، وبعد فينة من الزمن سمُع صوت بكاء طفلٍآخر.. وكانت أنثى لطيفة شديدة الجمال! حمل الأب \"الطيبة\" ولداه بفرحٍ شديد، وقالت الجدة أنها تريد أن تسمي الذكر الذي يكبرُ الطفلة بثوانٍ معدودة اسم \"المعاناة\"", "وقال الأب بلهجةٍ مجبولةٍ بالفرح، والعبراتِ تجري على وجنتيه: سأطلقُ اسم \"الراحة\" على طفلتي الصغيرة.", "كبُر الطفلان، وكانت \"الراحة\" شديدة الجمال. عيناها الواسعتان الدافئتان تحتضنُ الجميع.. وكان \"المعاناة\" شابا عنيدا ذو بنيةٍ قويةٍ وعضلات مفتولة، لكن بقلبٍ ضعيف.", "تعرفت \"الراحة\" على شابٍ يسكنُ نفس القرية، اسمه \"الحسد\" كان غير محبوب من قبل أهل الحي.. لم يخدع أحدا سوى \"الراحة\" بكلامه المعسول.", "علمتْ \"الشوق\" بالأمر، ووبخت ابنتها هاتفةا : هل جننتِ! ألم تجدي غير هذا الشاب المريع! وبينت الحقيقةلابنتها. صدُمت \"الراحة\" وذهبت تفرسُ وجه أمها وهي توبخها."], ["لم تعد \"الراحة\" تلُقي أيَّ بالٍ للحسد، كأنه لم يكن بحياتها أصلاً.. الفتاة المفضلة لوالديها تنصاع لأوامرهما ولا تخالفها.", "جاءت اللحظة التي كان يخافها \"الحسد\" ... يخافُ أن يمر خلالها.. عرفت \"الراحة\" حقيقتهُ الشنيعة.", "وفي ليلةٍ شؤم.. سوادها كالكحل.. باردةا عصيبة.. كانت \"الراحة\" تعودُ أدراجها إلى البيت من بيت جدها.. صادفها \"الحسد\" وهو ظاهرٌعلى حقيقته المرة.. أمسكها بقبضتِهِ المعدنية.. كأنه تحول إلى مسخٍ يلحق الأذى بالناس.", "استيقظت الراحة في الصباح ثيابها مليئة بالوحل.. كانت زهرة شديدة الجمال.. ولكن قطعت أوصالها.. متعبة، وجهها الشاحب يروي قصة الليلة المؤلمة. خلفها \"الحسد\" وراءه تحمل في أحشائها ولد خطيئة! كان الأمر خارجا عن إرادتها.", "اختفى \"الحسد\" وجرَّ معه عباءته السوداء من كثرةِالذنوب التي نُسجت معها، ولم يعد.", "علم الجميع بما حدث.. وكان وقع هذه الحادثة مؤلما على الجميع وخاصةا الأبوين.. كان مرورهم بين الناس التي تقذفهم بالعيون أشد العبارات،حفلة تعذيب منقطعة النظير.", "كان للراحة والمعاناة إبن عم، اسمه \"الشر\" وسوس للمعاناة بأن ينظف شرف العائلة.. ويقوم بقتل \"الراحة\"، كان من الصعب على \"المعاناة\" أن يفعل هذا الأمر.. أن يقتل توأمه وصديقة روحه.. كان يعلم في أعماقه أن لا ذنب لها في كل ما حدث، كانت \"الراحة\" أشد البنات أدبا وأخلاقا.", "ومع إصرار \"الشر\" عليه.. رفع وجهه للسماء، وصرخ: لم يكن لي توأمٌ قط! ولدْتُ وحدي.. ذاهبٌ بمفردي.. فانٍ لذاتي.", "استمر حملُ \"الراحة\" على مضدٍ، وعلى ألحانِ العذاب النفسي.. لم تلق مساندةا حتى من أقرب الناس لها...", "قضت شهور الحمل بمركز الإصلاح.. ذرفت دموعا من شأنها أن تملأ بحرا بالكامل، تناجي نفسها.. تتكور حول نفسها.. انجلى لونُعيناها الجميلتان.. وأصبحت هزيلة جدا."], ["جاء يوم الولادة .. تجمعت النساءُ حولها.. نظرات الشفقة تقذف نحوها بشدة.. وفجأةا سمُِع صوتُ الطفل، وهمت النساء بالمباركة لها...", "قالت إحداهن: ذكر! إنهُ ولدٌجميل!", "لكنها لم تكن واعية، كانت كقطعةِ ثيابٍ بالية.", "ثم قالت: أريدُ أن أرى طفلي..", "همست لها إمرأة: ماذا ستسميه؟!", "ردت عليها بشفتين مرهقتان: \"الحب\" سأطلقُ عليه اسم \"الحب\"", "خرجت \"الراحة\" بعد فترة من المركز ... لم يكن هناك مكان تقصدهُ إلا بيت والدها \"الطيبة\" الذي أصبح نصف ما كان عليه من الهموم التي تتناجى في قلبه.", "وصلت \"الراحة\" الحي.. وهي على أمل أن يكون أهلها قدموا لها الغفران.. الذي تستحق.", "عندما وضعت قدمها بتلك الحارة، كأنها كانت مدعوة على حفلة، وهي ضيفة الشرف.. كان الجميع يرمقها بنظرةِ وداع... علمت بأنَّحتفها على وشك معانقتها ... وتصعد إلى السماء...", "قالت بصوتٍ متعب... بهمساتٍ ضعيفة إلى السماء... دائما ما كنتُ أفكر بطريقة موتي.. لكنني لم أتصور أن تكون بتلك الطريقة... بالفعل عالمٌ غريب.", "كان \"المعاناة\" ينتظرها بفارغ الصبر... ناوله \"الشر\" السلاح المحشو بذخيرة كافية لقتل أهل الحي جميعا.. كانت \"الراحة\" هادئة... لم تُبدي أي ردة فعل... كأنها تقول بعيونها الذابلة: أقتلني وأرحني من هذا العذاب... سحب الزناد ... وبأعين مغلقة أطلق النار... وأشتد صراخ \"الشوق\".", "علمِ وقتها بأنه قد قتلها.. وبشكلٍ همجي ظلَّ يضغط على الزناد وفرغ جميع الطلقات بجسدِ \"الراحة\" الصغير الساكن.", "أخذت أهل \"الراحة\" على عاتقها بأن ترعى فلذة كبد ابنتها ... بأن ترعى \"الحب\"", "كانت كفالة \"المعاناة\" للحب صعبة.. ولكن ظنَّ أن هذا قد يريحُ ضميره قليلاً.."], ["ومنذُ ذلك الوقت.. ولد \"الحب\" ... يكفله \"المعاناة\" ترعاه عينا \"الشوق\" ... يفتقد حس \"الراحة\" ويكرهُ \"الحسد\".", "", "\"أول صباح في المزرعة\"", "لم أنم جيدا لإرتفاع نسبة الأدرينالين ، أنا والجميع تقريبا.. ربما أنني شخص متيم بالتواجد وحيد وصافي الذهن، فأفضل خيار حولي هو الذهاب إلى غرفة المعيشة.. لكي أكون وحيد مع الجميع. نهضت من فراشي الدافئ، ومشيت في الرواق مستمتعا بوقع خطواتي على الأرضية الخشبية كأنها معزوفة لبتهوفن.. دخلت الغرفة شاي مثلج والرفاق.", "بدأنا النقاش بأمر النشاط الذي سنمارسه شطرنج؟ قال آندي، صوتٌخرج من آخر الزاوية من أحد توأمي بيكرز.. ماذا عن كرة السلة؟!", "قالها بنبرة خبيثة للغاية. إنها داء معدي.. نقل إليه عند طريق صديقه التافه ويليام.. داءُ \"الرغبة الشديدة في إزعاج الآخرين\"", "صمت الجميع.. عيونيلامست ملامح آندي.. متمسر في مكانه دون أن ينبس ببنت شفه.", "قامت لوسيان بضربه على كتفه وهي تقول: ما بالك أيها الأحمق!", "وأخذ هو يردد: على رسلك.. لم أقصد شيء.. الطقس جميل ومناسب لكرة السلة، هذا كل ما في الأمر!!", "آندي يجلس على الكنبة بهدوء مبالغ ... ويقول من يريد كوبا من الشاي؟!", "كرر زاك بيكرز: ألا تريدون كرة السلة؟!", "قال آندي: لم أعد أمارس كرة السلة، اعتزلت.", "قال زاك: من يصدق هذا الهراء، آندي العظيم يعتزل السلة!!", "طفح الكيل يا رجل، اصمت وإلا سوف تفقد أحد عيناك القبيحة، قال كريستوف."], ["صدقا أظن هذا أول صباح وآخر صباح لنا هنا يا للسذاجة.", "", "\"آندرو\"", "صوت الجمهور، تحول إلى صوت خلفية ثانوي... يُحملُِ صوت قلبي الصاخب وصوتُ انفاسي العالية.", "لوهلةٍ شعرتُ بأن قلبي بين مؤخرة لساني وحلقي، يعملُ على تكبير نوتات أنفاسي، ويجعلها صاخبة جدا لدرجة أن الجميع كانوا قادرين على سماعها.. وسط كل هذا الصخب والضجيج الصادر.", "حسنا، ربما أنا الوحيد القادر على سماعها، لا يهم، عرقي يتصبب في محاولة تبريد جسمي، خصمنا متقدم، ياسين يلوح.. أرفع ساعدي نحو صوت ياسين.. آندي ... أنا هنا.", "أقذف الكرة نحوه... يلتقطها بخفة ورشاقة.. يناظرها بحب وشغف.. يرميها.", "هدف! هدف! ثلاثية!", "يا ليتني كرة سلة... تحب أن تقذف بين الأيدي وتحب ارتطامها بالأرض.. يا ليتني كرة سلة تحب أن تهوي إلى الأرض.. عبر سلة ضيقة.", "مؤخرا حلمتُفي هذه الدقائق كثيرا.. يقال أن الحلملا يتجاوز الثواني.. لكن بالنسبة لي هو كابوس لطيف.. يعكرُ ظلامي ليزيده كحلاً... كل ما الأمر أني شخصٌ سيء... ليس الحلم!", "أن تحمل شارة القيادة.. وتكون كابتن لفريق كرة سلة للناشئين ليس بالأمر الذي يحبس الأنفاس.. قد يكون الأمر عاديا بالنسبة لك... أو قد يكون أمر شيق... كما كان بالنسبة لي.. محط اهتمام الجميع... ومسؤول.", "أحبُّ هذه الكلمات جدا.. لم أكن أعلم أن النهاية سوداء.. لم أتوقع حكاية ترتدي الثوب الأسود.. وتتحسن بالدماء.. وتجعل التعاسة عنوانا لها."], ["أقلها قامت بتزيين وجهها العبوس. الفراق صعب.. وعندما يفوت الأوان سوف تنهش جسدك ندما.. قف واصرخ بوجه من تحب: أحبك!!", "فاقد الشيء لا يعطيه.. لكن يعلم جيدا كيف شعور فقدانه.. يصفهُ بدقة كأنه شخصٌ منتشي.. يعلم كيف يكون الأمر بوجود مكانٍ شاغرٍ.. لذلك أحيانا لا بأس بالإنصات إلى تلك الفئة.. أقلها اكتسبت شعور الفقد منه... أو بالأحرى وصل إلى قلبك القليل منه... الفقدُ بحد ذاته أمرٌمخيف، كيف الموت؟", "كنت مضطر بسبب دراستي أن أترك الفريق في المباراة قبل النهايات السنة الثانية.", "كنت لاعب قديم.. مميز وقوي لذلك كُنت الأحق بأن تتوج ذراعي بشارة الكابتن، التي التفت عليها وخنقتها بلطف... حتى حقنت الدماء بها.", "ماذا لو كان أكثر شيء يسعدنا سوف يكون سبب في وقوعنا إلى الهاوية بشدة؟ ماذا لو علمنا أن باب طموحنا وأحلامنا الوردية يفُتح ظرفتيه على الجحيم؟!", "هل سوف نخاطر، أم يجب علينا الاستسلام أحيانا؟!", "عند خروجي من باب الفريق الوهمي.. كانت تنتظرني حياة المدرسة الثانوية... وتركتُشارة الكابتن تخنقُذراع غيري... ذراع ياسين.. ما زال أثرها يكوي روحي.", "يريد الجميع أن تروى قصته الملحمية في سبيل حبه لمجالات وأفق حياته.. إذ إنه لن يعاني من غياهب النسيان.. لو مات عالم إثر تجربته التي سطرت اسمه في التاريخ.. أو البحار الشجاع الذي لامس جسده قاع البحر.. وغرق.. في سبيل إنقاذ الآخرين.. ولم يكتفِبذلك.. بل صعدت جثته إلى السطح كي تكون بمثابةِ ستره نجاة لغيره.", "ماذا لو كنت رياضي.. يلعب في مصلحةِ فريق مغمور.. تموت على إثر بلعك لسانك.. في حصةٍ تدريبية.. ماذا سيكون شعورك؟! ماذا سيكون شعورك وأنت في السماء يا ياسين؟", "كل هذا الحشو والكلام الفلسفي ما هو إلا في كتابٍ رث.. في آخر صفحةٍ دون عليه هذا الشؤم.. كتاب \"فلسفة الأغبياء.. بين المنطق.. والحلم\""], ["لن يعاني ياسين من غياهب النسيان.. أنت خالد يا ياسين أكثر مما تظن... خالدٌ في وفي الفريق لن تزول بصماتك عن تلك الكؤوس بسهولة.", "كان ياسين أحد أصدقائي العرب المسلمين.. بجانب فادي وآمنةً.ل أعلمُ عن ديانتهم الكثير.. لكنهم أناس لطفاء ومفكرين.. لماذا يقذفون بتفاهات ملفقة؟!", "كما قلت.. لا أعلم عن \"الإسلام\" الكثير بالنسبة لشابٍ بعمري.. مدون على شهادة ميلادي أنني كاثوليكي.. لكن لا نقوم بالشعائر إلا ندرة.. نزور الكنيسة ونرتدي البدل الباهضة لمدةٍ قصيرةٍ.. ثم نعود كما كنا...", "لا أقول عن المسيحية شيء... لكن ألوم نفسي... وأهلي لأننا لا نتبع ديانة بشكل ملتزم وحقيقي... ينقصنا ذلك الشيء... لا أذكر اسمه.. لكن لا تجدهُ في الأسواق أو في محال الحاجيات المستعملة. لا نجده بأغلى الثروات... ربما يمكننا أن نعقد صفقة مع أنفسنا وقلوبنا للحصول عليه... للحصول على الإيمان. أوه تذكرت اسمه.. الإيمان.", "أحيانا أفكر ما حالُرفيق دربي القصير.. على أي صورةٍ هو الآن؟! لحظة موته.. هل ضغُطِ على زر الإضاءة وحسب؟! وانتشرت العتمة في أرجاء الظلام؟ هل هي مجردٌكبسة زر؟!", "أم رُكب له جناحان ناصعا البياض... ويتجولٌ في السماء وهو عاري الجسد... والزغبُ يغطي أجزاء منه؟! لا أملك أدنى فكرة.", "أعلمُ في أعماقي أن الكون مسير حسب نظام شديد التعقيد.. ربما كعلم الفلك وخرائطه.. نظامٌ يسمى القدر.", "هنالك رب.. الكونلا يحتمل نظرية الصدفة.. إما أن يكون أولا يكون.", "يا رب.. إن كنت موجود... ساعدني.", ""], ["\"العودة إلى المنزل\"", "\"فادي\"", "عدنا أدراجنا... كل واحدٍ منا عاد إلى حياته... كان ذلك قرارا حكيما لكي نكسر الجليد ونزيح الضباب الذي تكون إزاء كلمات الفتى بيكرز التي خرجت من فمه الكريه مصحوبة برائحة أحد أنواع التبغ الرخيصة.", "ظل أندرو قويا كما عهدته منذ اليوم الأول من وصولنا إلى هنا، لكن عندما كنت أوضب حاجياتي سمعت صوت نحيب خارج غرفته... يمارسُ طقوس ضعفه لوحدهِ.. كانت لدي نيةٌمُلحة في أن أربت على كتفه.. وتمتزج دموعي بدموعه.. لكن كانت مجرد نوايا... تفتقر إلى الشجاعة.", "عندما وصلتُإلى المنزل... بعد أن ركبتُسيارة شوفرليه كورفيت كلاسيك لقريبة لوسيان التي تبلغ قرابة الـ 22 عام لكي توصلني إلى منزلي، همهمت هي قائلة: أوه، ما هذه الوجبة كاملة الدسم.. هل والدتك تملك مصنعا للحلويات؟!", "سمعتها تهمسُ لوسيان \"من هذا المثير غريب الأطوار\" ظلت لوسيان تتأملُ تقاسيم وجهي ويعلو وجهها ذلك التعبير الذي كانت ترمقه بطلة فيلم “Mebeforeyou” تظاهرت بعدم الاكتراث.. لكن في أعماقي كنت أشبع غروري الداخل من تلك النظرات والتلميحات الفتيات... ولكن لا أحد يرويني من تلك النظرات كما تفعل فكتوريا العزيزة.. على أي حال أنا أفضلُ الأودي فئة ثامنة على الكورفيت عندما تذكرُالعربات الخارقة.", "كيت ولوسيان يتهامسان في الخلف... وأنا أداعبُ خاتمي من نوع \"دولتشي أند غابانا\" الذي قالت لي أمي أنه كل ما تركه والدي خلفه وهو يجرُّ ثوبه الأسود الملطخ بالجبن.. والتفكير الوضيع.. ماذا لو كان هنا؟! على أي حال أعتدت على معرقلات الحياة دون وجود يد أبي تنجدني.. تعلمت ركوب الدراجة بفضل أمي.. والسباحة بسبب جهود يوسف الجبارة. كانت الطريق موحشة.. وجميلة في ذات الوقت أحسست بأجزاءٍ مني في الداخل تقول لي أنني مغترب.. أنا مغترب ... لأنني بعيدٌ عن أمي بضع كيلو المترات."], ["", "\"أزرقٌيبللُ خط الأفق\"", "لا أدري كيف وصلتُإلى منزلي، كيف حال بي الأمر واضعا يداي على وجهي.. جالسٌ أمحلق في القصاصات المنثورةِ على مكتبي القاتم.. رأسي شديد الثقل كأنني تشربتُ زجاجة خمر كاملة، أبعثرُ خطوط جبيني بأناملي وأعدلها.", "لفت نظري لونٌ أزرق مموج غارقٌ بين العديد من الورق، حملتها بخفة وقلبتها.. خطُ عليها من : وكتبعليها “The starry night-1889” الخلف", "\"كنت جالسا في مرسمي، أكتبُ بعض الخواطر، فجأةا وقعت عيناي على لوحةٍ عالمية، خيوط أشعة الشمس تسللت من نافذتي، أضاءت تفاصيل لوحتي..\"", "لحظات تأمل.. لم يكن الفن الانطباعي يوما بهذا الجمال. أفكارٌ تجول في دماغي.. هل هذه الدوامة البيضاء عبارةٌ عن أحلامنا؟! طموحٌ تناثرت في مهب الريح... في تلك المساء المرصعة بالنجوم..", "قريةٌ محاصرة بالأشجار والجبال، هل يستطيع أهلها تسلق هذه الشجرة الضخمة وتحقيق مرادهم؟! هل ستختلف نظرةُ الشاب عن الشائب؟! شابٌ بعضلاتٍ فتية قادرةٌ على الصعود أما الكهل..", "هل هي نفس نظرة فينسينت للوحته؟ أمم كان عجوز يقف على مفترق طريق من غير لوحاتٍ إرشادية؟ مجردُ متوحد يدعي الفن؟ أنا أراه عبقري. فلا يظهر فنٌّ مماثل بالصدفة.", "", "\"سماء سان ريمو في نيو سيتي\"", "بعد أن فشل أصدقائي في إخراج القيء الذي تراكم في سلة المهملات وفاحت رائحته.. قرروا إخراجي أنا بدلا منه.. إخراج شاب مزروعٌ بذراعه مغذي ويعاني من أعراض السرطان أسهل من إخراج القيء.. أو يمكنني القول بأن هذه الخطة \"ي\" بعد أن نفذت 27 خطة قبلاً في إخراجي من حيز التفكير القاتل."], ["صرخ بيرنارد مناديا فريد: تعال بسرعة حاملاً يوسف. لقد سرقت سيارة الماستينغ الخاصة بنسيبي.", "نظرت إلى وجه فريد وكان يكتم ضحكته الخبيثة همهمت بصوتٍخافت: إياك أن تفكر بذلك حتى.. لم أكمل عبارتي حتى كانت ذراعا فريد تلفني ويركض حاملني أنا والمغذي وحقيبة ظهري... باتجاه البابب. تبا لجينات الفراعنة القوية البائسة .. أحماضٌ نووية تتغذى على الفول المدمس والكشري.. سألني فريد عن المدة التي سوف تقضيها أمي وفادي عند خالتي التي جاءت للعمل هنا من الاردن. قلت له: يومان أو ثلاثة... لماذا تسأل؟ قال بيرنارد الأصهب: هذا مناسب.. بل أكثر من مناسب، هيا بنا إلى نيويورك يا أوغاد.", "أطلق فريد العنان لنفسه عن طريق ضحكة حادة كادت تصيبني بالصمم لم اعترض... وتكورت على نفسي من شدة التعب.", "أشعل فريد أغنية “Jack&Jack”", "We gonna Ri – Ri – Ri – Rise till we fall.", "وبدأوا بالترديد معها.. أخفض فريد صوت المكبرات الصوتية وقال: هذه الطريق خطرة ولا تصلح إلا لسيارات الدفع الرباعي.", "رد عليه برنارد: بحق الشوكولاته أتريدني إمضاء 42 ساعة للوصول؟! هذه ماستينغ يا رجل... عاود فريد ضحكة الساحرات.. وقام برفع الصوت مجددا عند مقطع . Whenwehitthebottom “ ” Nothinggonnastopus أنا على أمل بألا نسقط على الأرض... أمل ذلك.", "فتحتُعيناي بعد صراع مع أشعة الشمس المتسللة عبر النافذة.. لقد وصلنا في 11 ساعة وربع الساعة.. وكان يقول بيرنارد.. أخبرتكم.. هذه ماستينغ.. مسحتُ خيط اللعاب الذي قد سال على دقني .. وقلت: إلى أين تأخذونني يا حمقى!", "قال فريد: سوف ترى بعينيك الجميلة الغائرة", "برنارد: ها نحن في شارع منهاتن.. امممم ها هو، متحف الفن الحديث..", "رسمت على شفتاي ابتسامة صغيرة.. ولكن كتمتها لكي أتظاهر بعدم المبالاة."], ["", "\"ليلةٌ مرصعة بالأحلام\"", "هات البطاقة الشخصية وارجع للوراء قليلاً.. جملةٌ سمعتها من الأمن صاحب العيون الضيقة.. جيناتٌ آسيوية تغلف المكان وأنا جالس على الأرض أضربُ قدماي سويا، وأناملي تتململ على سحاب حقيبتي الشخصية.. أخرج ما فيها بحثا عن مضادات الاكتئاب قام فريد بانتشالي عن الأرض بذراعيه الفولاذية فجأة وهو يقول هيا أيها الفنان الرومانسي الذي يرتشف القهوة ولا يشربها.. ما العيب الجسيم الذي اقترفته كوني مثقف؟", "دخلنا إلى الجنة فجأةا عبر بابٍ حديدي ضخم.. انفتحت لي أبواب الحلم.. أبوابٌ تمنيت أن أعبرها برفقةِ فتاةٍ أحبها نتمايل سويا على بعضنا من لذة وخزة الحب... لم أكن أريدُ أن أتمايل بين ذراعي فريد.. وحمالة المغذي اللعين. عيوني تتجول... بين الحقيقة والخيال.. حقيقةٌ تتمثل بالبشر.. ولطالما كانت الحقيقة أليمة – جارحة.. أو شريرة... مع ذلك هناك حقائق صغيرة.. لا يعلمُ مكنونها الكثير... أو أنها لا تحمل في جوفها كمية من الألم والحقد كافيات للفت الأنظار لها؛ ممثلة بالأطفال. يمكنني القول بأن الأطفال كسحاب الصيف... وضع لمحاولةِ مقاومةِ حر الشمس الحارق... أو التخفيف من وطأ الأعمال الشيطانية البشرية وسط هذا الخيال الجميل.. الذي يحتمي بإطارات خشبية عتيقة... أو صندوق زجاجي يمسح كل عشرِ دقائق.", "لإخفاء بصمات الحقيقة القذرة... التي حاولت جاهدة المساس بالخيال؛ لإخراجه من حيز التفكير الإيجابي.. للبؤس المطلق. وجهتي محددة ... هدفي ثابت؛ عيناي تحاول قنص الخيال المفضل وكما اعتدت صاحب الهدف لا يلتفت لمغريات الطريق.. الغجري النائم أحد تحف هنري روسو، أنا والقرية... وإصرار الذاكرة.", "لصاحب الشارب الذي ينافس أحد البروفوسورات في آخر الخمسينيات جامعة دمشق العريقة.. سلفادور دالي.. كلها مغريات.. ومال زال الهدف ليلة النجوم... ليلة الأحلام... للعبقري فان كوخ", "وجدتها متربعة على العرش... وسط عقلي... ووسط القاعة الطويلة.. وأنا ثابت أمام الجمال ... منذ اللحظة الأولى التي رأيتها... تربةٌ خصبة تثمر فيها جميع المشاعر."], ["", "\"همسات مهملة\"", "من الشخص الذي قام باختراع فعل \"التكريم\" أو التعزيز.. لا أدري ما المفرد المناسب؛ من قام بتشييد التماثيل لأول مرة؟! تكريما لشخصية كانت مؤثرة واندثرت تحت التراب. أو شخص قد كان معجزة كاذبة.. في عيون الفاسدين أمثاله من السياسيين وقاموا بنسب المنشئات ... المؤسسات له.. في محاولةٍ لتخليد شيطان عاش يوما ما حياة ضمن الأناس العاديين.. إعطاء الشيء لغير مستحقيه.", "لو سمح لهذا التمثال بالكلام لمرةٍواحدة.. ماذا سيقول؟! عن عدد المشردين اللذين قد قضوا حاجتهم إلى جانبه؟! أم عدد الطيور التي حطت على رأسه وتركت له تذكارا كريه الرائحة.. أم ارتكاء المحبين عليه وهم يتبادلون القبل مخزولة المشاعر.. مجردُ حب استكشاف والغريزة القاتلة للجنس الآخر.. أهو تكريم... أم ذلٌّ وإهانة؟! على أي حال.. شاب بعمري غير قادرٍ على بناء تمثال عتيد يتغنى الجميع بإتقانه.", "ماذا أصنع لأخلد ذكرى أخي في نفوس الجميع؟ لكي لا يعاني من غياهب النسيان؟ كتاب؟! إلكتروني بالطبع ... فالميزانية خاصتي محدودة جدا... لكنها موجودة.. ومساعدة ودعم اندرو، كريستوف، وفكتوريا سيكون كل شيء على ما يرام.. مدونة باسم أخي الكبير على الانترنت ستفي بالغرض... إلى أن ألقى من يتبنى هذا الكتاب وربما أضع رسوماته بوسط الكلام.. لدي الفكرة ولن أتراجع عن التنفيذ... مهما كان صعبا ... سوف ألتقي بـ \"السكواد\" خاصتي لإنتاج شيء يليق بأخي.. شيءٌ مميز..", "لن أغير عنوان يومياته... سيبقى كما هو... \"همسات مهملة\"", "سمعتني أمي أفكر بصوتٍ عالٍ... ربتت على كتفي وقالت أتمنى ألا تستسلم.. تبعتها بضحكة ألم. لا تجري الرياح كما تشتهي السفن.. لكن أنا البحر والرياح والسفن.", "أتمنى أن تعلم يا يوسف أنك لن تعاني من النسيان بل خلدتك كتابتك، وجدت نفسي وذاتي يا يوسف، وجدتها بين سطور رسائلك، بين خطوط ومنحنيات لوحاتك.. بين الحياة والموت."], ["كل ما علي الآن هو معرفة سر الحياة..", "عندما أخبرت أصدقائي عن الفكرة التي صدعت نفسي ربت كريس على كتفي كأنه يطمأنني أن كل شيء سيصبح على ما يرام.. كل من هو يحمل اسم كريس عظيم.. كريستيانو رونالدو.. كريس مارتن.. كريستيان بيل... كريستوفر خاصنا.", "ذهب أندرو وكريستوفر لكي يشتروا تذاكر حفل إيد شاريين الذي سيقام آخر الشهر.", "بقيت أنا وفيكي في بيت الشجرة ... ما زلت أتعجب على قدرته على حملنا وصموده الرقيق.. أشاركها سماعات الـ i-pod خاصتي... وخصلات شعرها تداعب وجهي ... لم تفهم معنى الأغنية .. كانت أغنية من أحد الأفلام ... كيفو هالحلو.. المنو إلي ومني إله... حمدا لله إنها لا تجيد العربية أحبُّ الفن البديل... غير مبتذل إطلاقا.. موسيقى غيثارة أعمى تتبع خطوات الكلمات البسيطة المنسوجة بالمشاعر الدافئة... أدرت الأغنية إلى لغة تفهمها شخصيتي المفضلة Justthetwoof “ us”", "قالت على حين غرة، وهي شبه في اللاوعي.. وأنا في قمة الوعي... منتشي من جمال رائحتها..", "سأتكفل بعمل المدونة على الانترنت... أحبك وأكملت نومها بجواري.", "", "\"3 شهور بعد (أحبك)\"", "منبه الـتاسعة صباحا... أمي عادت وجنتيها وردية متدفقة الدماء.. هل هي آثار مرض؟ بسبب توسع العروق ليتدفق بها الدم بشلك هيستيري؟! أم الاهتمام بالغذاء وزيادة عمليات الأيض غذاءٌ عالي الزنك والحديد.. أم لماذا التعقيد؟! ربما السبب هو السعادة.", "أتناول الفرينش توست على الفطور وأنا أتصفح حساب الإنستغرام الخاص بكتاب يوسف.. نشرت صورة لحيتان قد لاقت حتفها على أحد شواطئ في ألمانيا بسبب مخلفات الكائنات البشرية المهملة.. هاشتاغ save_whales #"], ["رأيت رسالة منذ يومان تقريبا.. مرحبا، أنا أعرف أخاك كثيرا.. قابلته مرة واحدة.. كانت كفيلة بمعرفتي الوطيدة به.. أجبني عندما ترى رسالتي لكي أشكرك مع حبي ... وانغ شو.", "", "\"حقل أرز من نيوسيتي إلى البكين\"", "كنت أتمنى أن يكون لدي رموشٌ طويلة.. أعارك بها أشعة الشمس الحارقة.. أقلها أن أعارك شيء فشلت بأغلب المعارك.. هادئ ظاهريا وفي عقلي مئة ألف حرب... ومئة سلمٍ لم يتم..", "حياتي ليست كئيبة.. لكني أشفق على نفسي الجميع يتناول مع الافطار الشهي.. فطائر محلاة وعسل... وفيتامينات أما أنا أتناول البروزاك... لكي أعيش فقط... آه، كيف وصلتُ إلى هنا.. لا أدري.. من أنا؟ لا أتذكر... أذكر شيء وحيد.. إني مشتاقٌ لإبنتي.. أين أخذتها زوجتي؟ مشاهد كل صباح.. تتكرر.. إلا يوم واحد..", "أستفقت من نومي مبكرا لكي لا أتأخر عن العمل... بروزاك زلابية ونودلز من البارحة.. غسلت أسناني ومشطت شعري أوه نسيت شعري ناعمٌ جدا لا يتسرح... وضعت السلاح ذو الباغة الفارغة على جنبي.. وركبت السكوتر الخاص بي ذاهبٌ إلى عملي.. متحف الفن الحديث.", "كنت أغرق في الطريق المزدحم وأنا أفكر..", "أفتقد الريف الآسيوي جدا.. الهواء عليل.. والسفوح عاتية، أشعر بالشوق لذلك البعد الآخر شديد الاختلاف عن هذه الحياة الحالية.. كل شيء مخزول الطبيعة البحتة.. تتفشى البنايات والخراب البشري المساحات الخضراء كأنك في عالم من البلاستيك الملفوف بسذاجة الروح النابضة.", "مع ذلك أحب الفن جدا وبما أن عملي مليء برؤية الفنون وليس بصنعها.. كنت في شبابي أحب أن أرى لوحات كلود مونية، ويداه التي تحول الأمور إلى شكلٍ إنطباعي.. كأنك ترى الحياة بخطوط قصيرة... أو أن ترى نفس المقطع الناظري الطبيعي باندماج الـ 4 فصول سويا أو خلال الفجر والظهيرة وعشية ذات اليوم.. لنفس المقطع الخلاب."], ["إن سألتُعن ألواني المفضلة قد تكون الأصفر والأزرق.. يشعرانني بوجود البهوت والقدِم في وسط الحداثة.. عندما كنت صغيرا أتذكر تلك الصورة الرثة التي ألُتقطت في ميلادي الرابع وأنا أرتدي قميصا أصفر فاتح.. وبنطالا سماوي يقدح النار الكامنة في قدماي لتدفعانني على الوقوف طويلا لإلتقاط صورة مخططٌ لها مسبقا بهدف أن ترتدي طابع العفوية الكاذب.. أنا قديم... بعقلٍ حديث.. أما الآن.. انقلبت الطاولة.", "السكوتر الخاص بي يشبه البشر كثيرا.. أتخيله شخص خجول ولكن مثابر. غريب الأطوار لكن يواعد أكثر الفتيات شعبية.. قد يكون ممثلاً بارع جدا.. يمكن أن يعتليه روبرت دي نارو ويبدو كأنهما شخص واحد.. ملتحمان سويا.. أكره مساحة عقلي التي تحلل كل شيء.. حتى أنها قادرة على تحليل شخصية الجمادات التي تحيطني.. بإمكاني مصادقة وتسمية كل دمعةٍ ذرفت مني في الوقت الذي كنت في أمس الحاجة إلى شخصٍ يشُاركني مخاوفي في السقوط.. السقوط..", "قد وصلت إلى أرضية المتحف ... وسمعت أحد الحراس يهمس.. قد وصل الكوري.. قد استولى هذا العرق على درب التبانة وأخذ زميلاه بهز رأسيهما موافقان بشدة... ثم سأل أحدهم عن معنى درب التبانة.. هذه الدنيا غريبة يتفوه الغبي بالهراء ويوافقه الأغبى على الهراء خاصته... أنا لست كوري.. وذلكلا يعرف اسم المجرة التي يعيش بها.", "وقفت عند البوابة للتحقق من البطاقات الشخصية الخاصة بالزوار... كنت أريد وظيفة خطيرة أكثر.. كالعمل في وول ستريت مثلاً.. لكنها الـ \"باد كارما\"", "في ذلك اليوم أتذكر أن أوائل الزوار كانوا ثلاث شبان واحدٌ أمريكي وآخران يبدوان من الشرق الأوسط لملامح وجوههم الحادة.. كأنها سكين يفتك بروح العرق الأبيض الكاذب.", "لم يبدوا من عشاق الفن.. باستثناء المريض..كان يخفي حماسه بحبوب القلق المفرط.. بدى لي كأنه أمير من أحد أفلام ديزني .. كقريب علاء الدين.. لكن أضناه المرض.. وثقل حقيبة ظهره.. التي لا يحملها هو أصلاً.. لم أهتم إن كانوا من هواة الفن أم لا.. يتردد الجميع إلى المتاحف لكي يبدو مبتذلين الفن كأنه حكرٌ على فئة المراهقين الذي يدعمون فنون التعري لإشباع الدوبامين الخاص بعقلهم صاحب حجم حبة الفول السوداني."], ["حملهُ الشرق أوسطي الآخر على عجلة وأخذوا يغرقون بين ظرفتي الباب الضخم.. إلى البعد الآخر من الجنة الحقيقية ليست التي يدعي المتدينيون بوجودها بعد الحياة.", "رأيت الدفتر الجلدي الخاص بالشاب قريب علاء الدين يهوي من فتحة حقيبته... لم أستطع إخباره وقتها لازدحام الناس على البوابة.. دفعته إلي.. سأعيده لهم حين يخرجون إنه مجرد دفتر.. ومن يهتم أصلاً.", "انتهت مناوبتي ولم يظهر أحدٌ من الفرسان الثلاثة.. كأنهم قد سحبو من قبل الثقب الأسود المتمثل بالفن البحت... بعد الإنتظار قررت أن أجازف وأن أبحث عنهم قبل أن أسلم المناوبة لغيري.. عندما هممت بالوقوف واجهني الغبي والأغبى.. قال الغبي: يا صاحب شقتي الأعين... انتهت مناوبتك إرجع إلى بيتك... تجاهلت... وكظمت غيظي.. رددت: حسنا... سأرجع.", "ومضيت في طريقي.. فجأة رأيتُ قبضته تحكم على ذراعي.. وقال: ارجع إلى بلدك وإلى أولادك المسُوخ..", "شعرت أن كل الدم تركز بيدي.. ثوانِ سريعة كان أنفُهُ عبارة عن أشلاء..", "صرخ الأغبى: ما هذا؟! إنه قريب بروس لي اللعين! وهرب كأنه رأى مسخ.", "طردت يومها.. على أي حالة أكره الاستيقاظ مبكرا.", "", "\"جسر خيبة وتحرُّر من المتحف إلى منزلي\"", "أظن أن قصتي تصلح لتكون أحد مسلسلات نيتفليكس الأصلية، لا يوجد شواذ سوى أفكاري.. ولا انحلال قيم دون فقد روحي عذريتها .. وأن أضع الحليب قبل الرقائق الكاملة.. وكوكبٌ بلا تهجير.. أي أن أحقق الغير مقبول.. والمستحيل، ويشاهدني الجمهور وأنا أوزع نفسي على عديد من الشخصيات.. شبيه بمسلسلات الرعب ولكن يكمن الاختلاف في أن في أفلام الرعب جسدٌ واحد تغزوه عديد من الأرواح.. أما أنا روحٌ واحدة قسُمت إلى العديد من الأجساد المتعطشة للحياة.. بأجزاءٍ من الروح.", "لن يشاهدني سواي.. ولن أنشر للغير... أنا أنا وهملا أعرف ما هيأتهم."], ["أول صباح.. وأنا لا أفعل شيئا .. على جميع الأصعدة.. لا أفعل شيئا.. أشعل الشموع في وضح النهار.. رجلٌ في الأربعينيات.. يبحث عن ذاته وسط الخراب الكبير..", "لا يوجد سواء.. أنا وظلي.. أزهار صناعية.. ودفتر الفتى الشرقي.", "", "\"لا تخرج بلا سترة واقية\"", "أخاف الإنسان كثيرا.. أخافني.. وأخاف يداي، الأشخاص الذين أحببتهم صنعوا الأسوء بي.. أخافهم أنا وشخصيتي البالية الأنانية في أشخاصي اللذين دخلوا روحي واستعمروها.", "جسدي تعود على الخذلان... وبلعت الهموم حتى لساني لم يتذوق غيرها منذ أيام.. لا أستحق ما يحدث.. هل هو عذاب وابتلاء؟ أم أن قلبي ما زال يملك لهفته؟ ولا يريدُ التخطي.", "جفت دموعي.. وغسلت أكزيما وجهي التي سلختني وتركت آثار القلق عليه... أكرهني... لا أخاف نضجي لأننيلا أخاف من المعلوم.", "إلى متى سأبقى هكذا.. منتحرا نفسيا.. بجسدٍ ميت هل إن وخزت إبهامي بإبرة.. هل سأشعر من جديد؟ أم أن أحاول الاستماع لأغاني جديدة وأخفي الأغاني التي حرقت روحي وهي تذكرها؟ إن انهمرت دموعي على أغانٍ جديدة.. هل سأعتبر نفسي خائن للشعور؟؟", "يا الله... إني عبدٌ بنصف إيمان.. هل يكفيني لكي تنجدني؟", "دفتري القديم، يقولون أن الكتابة تدب الروح بالورق وفي نفس القارئ.. لا أعرف سبيل الوصول لذلك سأجرب.", "أقف عاجز... غير قادر على نسج الحروف.. جهزت القهوة لكن الريح جمدها .. الساعة متأخرة جدا.. الجو عاصف في قلبي قبل الخارج... لكن لم أصبح كاتبا بعد!", "عيناي يكسوها السواد.. روحي مفطورة.. أشعلت الشموع التي اشتريتها بـ 215 جنيها.. تبعث الروائح باسمها... أشعلت تلك التي كتب عليها “Love” لكي أشتم رائحته على الأقل.. لكن لم يصل دماغي أي مؤشرٍ على وجود رائحة غير رائحة الهدوء... هل رائحة الحب لا تعرف طريقا لأنفي.. أم أن قلبي رفضها؟ هل أصبحت كاتبا الآن؟"], ["أعيش وحيدا مع زميلي.. حين أقول وحيدا أعني ذلك.. قرب البحر.. وقرب إحدى المكتبات العريقة على مستوى العالم هل ذلك قد يلهمني؟ دخنت علبة سجائر كاملة.. وشعري طويل وذقني غير مشذبة ... هل أصبحت كاتب؟", "انفطر قلبي.. وعانيت كثيرا.. جربت جميع المشاعر.. لكن كيف السبيل لوصفها؟", "خيالُ الدخان يداعب أنفي.. ويتسلل إلى أذناي.. من أكون؟", "الروح.. روح.. ثلاث حروف تعلمت منها أبجدية كاملة في مدينة ساحلية.. لماذا الجميع يتخطى وأنا ما أزال عالقا لماذا أنهش عقلي.. كأنني جمعت العذراء مع الأسد.. حتى سال دمها.. وجعلها تخاف ظلها الذي تكون من شموع الروائح المغشوشة.", "يا ترى لو وضعت فتيل برأسي.. وأحرقتني.. هل سأجد الطريق؟ سأدلني على طريق النفق التي اغتصبت به الأحلام؟ ماذا ستكون رائحتي؟ جلدٌ ينسلخ أم جناحان يشتعلان؟", "عشت في أماكن لا تشبهني... قاسية وإن كانت شمعة سيكون رائحتها الخوف.. لم أكن الطفل الذي أريد.. ولم أكن أصبح الشاب الذي تُريد.", "درست الضعف.. واجتزت أصعب مراحله.. صدقني.. إني مخول لإطلاق نظريات بشأن هذه الصفة.. التي أرتديها قبل نومي. هل سيصل نبض يدي إلى حبر قلمي؟ وأصبح جبران بروح متمردة وأجنحة متكسرة.. هل سأخرج من قوقعتي الكوفية.", "عندما ودعت أمي قبل سفري.. ظننت أني كبرت الآن.. لكن يا أمي الشاب الصغير... ما زال يصغر وينكمش.", "في هذه المدينة وضعت قدمي على أول درجةٍ في حلم وحيد.. وخسرت باقي أحلامي.", "أتمايل بالقرب من العاصفة.. ولهيب شمعتي يُراقصني ويقبل وجنتاي.. ليخبرني أنني لستُمكروه من قبله على الأقل.. في ظل أنني ودعت أغلى الأمور على قلبي.. اتخذت صديق من النار.. منافق بلا أي رائحة تذكر.", "أما الآن، هل أصبحت كاتبا؟"], ["", "\"يا أنا\"", "أراني من بعيد.. أقبل ولا أصل.. أتعثر وأقف.. أضرم النار في أحلامي.. وأبحث عن سبيلها بالرماد.. أتلعثم بريقي.. وأختنق به، وأكره وجود قلب ينخز ويأمرني بالابتعاد.. عندما أرى الظلم، أراه بقلبي لا عيناي.. أكره كوني شخص تعمل وظائفه الحيوية على المشاعر.. أريد أن أحدث فرقا في هذا اللون الذي يسكو لسماء الليل.", "أظن أن جرأتي في القدرة على طلب يد إمرأة قد ينحصر على الكتابة لكي أناديها إلى بيت الطاعة.. أكتب فيها ما أريد.. وتحين لي الفرصة لكي أقرأها وقتما أشاء.. لن تجادلني كثيرا طالما ما زلت أنا من يقذف الحبر وأنا في أوجٍ اشتعالي.", "وإن قامت بخيانتي لأنني كاتبٌ حاد الطباع، أمزق الورق بنصل قلمي.. سوف تحتفظ بالوثائق على ورقٍ بالٍ.. لن يستطيع دافنشي فك شيفراتي.. وسوف يهيم عاشقها الجديد في بحر كلماتي ويفترس مرجان أفكاري.. ويعلم أن عشيقته خانت تعابير.. لم يصلها أحدٌ من قبلي.", "أريد أن أسقيها من فرط الشعور.. وأن أسجنها بين المشاعر والمشاعل.. لكي تلامس لهيب الفكرة التي قد نسجتها لها. أن أقنعها أن الأرض مسطحة.. طالما توجد عمالقة تدوسها.. أريدها أن تشعرني بأنني الكاتب الوحيد الذي يستحق القرآءة.. ولي الحق بالكتابة حيثما أشاء حتى على جبينها \" هذا المنتج غير قابل للقراءة من فئة البشر\"", "أريد أن تكون شريكتي.. تشاركني حروفي المبعثرة.. أن تشاركني مقعدي وهي تصحح المفرد المناسب.. الكتابة..", "الكتابة التي أريد.. أن نلد معجبا كاملاً لكي يصبح دليلاً لمشردي العلاقات إلى عمق الشعور.. على دموعي التي تذرف عندمالا أجد قلما.. لكي أفرغ غضبي به.", "سوف أحدث فرقا.. أن أكون أول شخص من البشر شارك الكتابة السقف الواحد.. بعيدا عن المنطق والتكليف.. بعيدا عن المستثقفين .. أنا.. وقلمي وهي."], ["", "\"عالمي الموازي\"", "أحد نصوصي المعدلة", "عندما كنت أعارك أخي الأكبر شبيه روبرت باتتسيون بلا أنياب حادة أو عيون تقدح القاني.. كنت أتمنى أن أقفز من النافذة الصغيرة إلى عالمٍ كبيرٍ لا يوجد به إلا أنا.. وذئاب السفح الأصفر بسنابل القمح تداري شعبها وتراقص النسيم.. النسيم، نسيمي يتسم بتراتيل بصوت سيلين ديون لا يفهم معناه سواي، والصخور المتدحرجة كالتي بفيلم “Frozen”", "تستطيع أن تمد ذراعك لكي تقنص غيوم السماء القرمزية كالتي حدثني عنها فينسينت وتتناول غزل بنات مجانا.. ولن تصاب بالسكري.", "نأكل المعاجم والكتب غذاء مليء بمفردات جزلة. نستفرغ الألوان.. قيءٌ أغلى من قيء حوت العنبر.. كلُّ واحدٍ منا كلود مونيه.. لا يوجد حرب وقنابل وعنف .. حرب دون راء.. وليلى مشروعها الناجح في آخر الوادي.. والقانيلا يعاني.", "نثملُ بلا شراب، طالما قد تشربنا تعفن الصفحات البالية.. يوجد ظلٌّ للريح ومتاهة للأرواح.. رؤوسنا تناطح السحاب.. جزمتي أجمل من إيطاليا. أنا الحاكم وأنا الشعب.. أسنٌّ القواعد وأكسرها.. تستطيع ركوب الحيتان بلا لجام في سماء أرضي القرمزية.. شمسي قرص زهرة عباد شمس تمطر حين تتذكر ماضيها مع غربان غياهب النسيان.", "جنون عظمتي يلفني ويخنق نرجسيتي.. جميعهم هانا.. وأنا البيكر، أضعهم في التنور وأحرق بقاياهم ولا أحتاج ثلاثة عشر سبب لذلك.", "أهوي وأتدهور في الهوة.. فجوة في وسط التل.. رطبة وترشح منها مياه جوف الأرض من جميع الاتجاهات.. تحسست عروقي كأنها نيل يريد هدم الدلتا.. كائنات.. أصوات همسات.. حركات سريعة تراقص لحن قلبي.. “Heartbeat...tellme...whatyouneed” حروفٌ بحجم الأرانب الصغيرة... تطل اللام بعنقها الطويل .. والهمزة تتربع على نبرتها وعين العين ترميني.. وقفت ساكنا لثوانٍ.. حتى أحرف عالمي تتمرد على نص دماغي.. رفعت يدي العملاقة بالنسبة لهم.. وأغمضت وأنا أتمتم .. ولم أنفك وقتا حتى فتحت عيناي رأيتها واقفة تحت قدماي ساكنة.. موسيقى"], ["الخلفية تتردد بيننا.. بدأت بالتقاطها واحدةا تلو الأخرى.. أنسجها.. أرفعها أقرأها.. أرتلها .. أرميها.. أتسلقها.. أمشي عليها.. أخرج من الظلام وسط كتل العظام والجماجم التي دفنت في مقبرة الأدب الجماعية.. إلى سماء ديناصورات تطير في سماءٍ ليلكية.", "أصعد.. كأنني نصف باحثٍ عن مكنون الكثير.. عن سطورٍ جديدة. لكي أكمل حلم كاتبٍ وضع الحجر الأساس.. مشى خطوة.. وسأكمل الألف القادمة.", "سعيدٌ بأنني أتهاوى.. وأن أتعثر بالنقاط.. بفواصلٍ تنهي كل نص لكي تذكرني أن كلامي مخزول النهاية.", "أن أتعثر وأسقط على حقل مفردات لم يفهمها إلا صانعها.. وناسجها.", "", "\"نحن شتات فلسطين.. وهي كمالنا\"", "عندما راسلت ابن خالتي آخر مرة.. علمت أنني مجرد طفل بالنسبة له، مع أن الفارق بيننا سنتان وثمان أشهر تقريبا الهموم تهلك الجسد .. والوحدة تغذي الحزن .. والمواصلة تحلل الأقدام.. لقد كان مثل بذرة عباد الشمس.. تنقله الرياح إلى مجاهيل كثيرة .. وما يزال يثمر، نحن شتاتٌكثيرة لبلدٍ مساحته بسيطة .. أنجبنا الطين .. ورعتنا عيون المشقة..", "تآمر الجميع علينا.. عندما دفعنا ضرائب على أملاكنا.. وصكوك ملكيتنا ذهب مع الريح .. وعندما لم يتبق لنا شئ .. قذفونا بالتخلي.. أو أننا قد بعنا تفاصيل وتجاعيد، أرضنا لأناس كأنهم كوم ملموم.. ونحن العرق الأصيل.. أيوجد عاقل يبيع أراضي حيفا ويرمي بنفسه إلى خيمة؟", "صدقني هناك من باع .. لكي يشتري روح أولاده، ويحمي عرضه باع ليتحاشى رؤية أطفاله يحتضرون.. أو أبواه يرقدون تحت أنقاض ثقيلة.", "نحن أسود هذه الأرض.. روضتنا الغربة حتى أصبحت مهنة ولكن ما زلنا في كل يوم جمعة نتناول المسخن ونزرع الزهرة بقاع وعاء المقلوبة حتى تنبت بنا رغبة مستمرة في العودة .."], ["لا يوجد وطن بديل عن موطني .. لم أشتم برتقالها من قبل .. لكن يمكنني تخيل هيأتها .. حلمت كثيرا بأن أرسم على رمل شواطئ يافا.. أو أن أجلس على شاطئ غزة وأنتظر البحر بأن يلد من أحشائه شيئا يقدر على هزيمة أهلها.. في ظل فشل جميع كائنات البر على استباحة حرمة غزتنا. لطالما ما شبهني أصدقائي بالإيطاليين بسبب أنفي المعقوف وعيناي التي تبث الخضار.. ربما سأكون جميلاً وأنا أرتدي قميصا أسود وأجدف بشوارع البندقية المائية والتقطت الصور بكاميرتي الفورية.. أنا أسند برج بيزا المائل عندما فشل الأوروربيين بذلك.", "ولكن ما يناسبني حقا أن أتناول على الإفطار الزيت والزعتر مرتديا القمباز.. أكبر على سفوح بلدي .. وأنتقل إلى مصر للتعليم .. وأرجع بشهادةٍ كبيرة.. لكي تعلقها أمي بساحة صدر البيت.. أن أكتب ألف كتاب على شرفات القدس.. وأن أقع في غرام فتاة جامعية تدرس الصحافة ونخرج للسينما في يافا.. هي تشاهد الفيلم .. وأنا أشاهدها.", "", "أحيانا نجلس نفكر بالأمر الذي يدفعنا للمقدمة، الرغبة الهيستيرية لحب المرتفعات قليلة", "الملوثات، ولكن مع ذلك قليلة الأكسجين، فرحة خانقة تحقن حركة الدماء في جسدك، أعراض الهايبوكسيا \"نقص الأكسجين\"..", "شيء غير قادر على إطلاق مصطلح عليه، قادرٌعلى حرقة شجرة مفردات كاملة لإنتاج كوب", "شاي واحد، متمثل بتسمية هذا الشيء، العزيمة.. هذا ما كنت أبحث عنه،", "أتذكر تلك الأيام جيدا، جالس في شرفة منزلي والمطر ينهمر في محاولة غسل ذنوب المستحقين، أناملٌ تداعب الزجاج، حذاء طويل، مقاوم للماء، أنا وأمي، ننزل سويا إلى المدرسة،", "بعد الوصول، ثلاث ثواني كفيلة لإظهار استياء الطاقم التعليمي لمدارس الأونروا من حضورنا، \"روحو ع الدار، محدش بدرس بالمطر\".. لم أكن أذهب إلى أمي لأني أعرف قلقها الدائم،", "ستطالبني بالرجوع للمنزل مع أحد الباصات، لذلك كنت أفضل العودة وحيد.", "اعتاد أقراني الذهاب لمحال الألعاب الإلكترونية، أما أنا قد كانت متعتي بالرجوع تحت المطر، وملاعبة الجراء المولودة حديثا، لم أقل لأحد من قبل، أعلم أن الكلاب نجسة، لكن شكلها"], ["جميل، في ذات المرات كانت الأم موجودة ولم ألحظ وجودها، علمت عندما سمعت زمجرة تأتي من جانبي، قاعدة الثلاث ثواني، ثلاث ثواني عن ألف سنة، أما أن أكمل تعليمي وأصبح شخصية مهمة في علم الجينات في إحدى جامعات أوروبا، أم أصبح طعام ساخن للأم المسعورة، ثلاثة", "ثواني وتبعتها بعشرْ كنت قد وصلت الشارع العام عند الحديقة، لم أكن أعلم الكلاب تخاف إذا هاجمت إنت أولا، علمت هذا متأخرا عندما كنت ارجع للبيت من شارع فؤاد بعد كورس تكمليلي للجامعة للسنة الأولى،", "عندما وصلت الشارع كان هناك رجلال أعلم ما اسمه أو حتى شكله، كان يرتدي وشاح أحمر عتيق، ومعه ولد صغير، ظننت أنه جده لأنه طاعن بالسن، سمعت طرف محادثة لم يجدر بي سماعها، المطر يتدفق عبر الفوهة الكونية..", "الإبن : \" يابا ليش ما نطلع من البيت كله مي والزينكو بدوش الواحد\"", "الأب : \" كل هاظ مشان طلعنا يابا، امشي امشي\"", "وصلت تقريبا للبيت، أجمل منظر قد يكون يوما هو الأحراج وهي مغلفة بالضباب..", "فتحت الباب وأنا اركض نحو غرفة المعيشة المدفأة مشعلة والتلفاز، أختي الوسطى تحت", "الغطاء تذاكر للجامعه إحدى مواد الرياضيات المقرفة، وابريق الشاي على\" الصوبة \"،", "\" أسامة؟! مروح بكير لسا الساعة سبعة! حسبي الله فيهم اساتذتكم\"", "دخلت غرفتي وبدلت ملابسي المنقوعة بالماء، وجلست على سريري،", "ماذا سأكون؟ هل يسقط سقف منزلي عندما أكبر جراء الأمطار؟ أم يفتك بي الكلب الخاص بأولاد أبو صالح اللحام، أم سأصبح أستاذ وكالة أدرس الرياضيات المادة التي اكرهها واكره", "مدرسيها؟", "الإيمان بالشيء هو صور من صور عزيمة الحفاظ على الشيء،", "ما زلت أطبق قاعدة ال٣ ثواني، أشعر احيانا إنها ٣ أيام، كل شي وكل قرار وليد اللحظة،", "وما كنت عارف ما رح ادرس جينات أو أروح لميلان، بس المهم إني عشت وما أكلني الكلب يومها."], ["", "\"كالنار بالهشيم\"", "أكتب لي رسالة ورقية .. بخط يدك .. وقلمك سريع الفوران ودموعك التي تعكر صفو الحروف .. بقايا جلدك المخفية تغطي ورقة .. وعندما ألمسها أشعر بدفء يديك الصغيرة.. ورائحتك تحتل مستشعرات أنفي .. أكتب خلالها ما تريد .. حدثني عن أصل النجوم وأنواع القطط التي اقتنيتها.. حدثني عما تريد.. طالما أنا من يقرأ بصوتك .. لن أرفض ذلك.", "نشُر كتاب (الهمسات) التي كانت صاخبة كفاية لكي تهز عرش النيويورك تايمز بشكلٍ مريب كأكثر كتاب تم البحث عنه على منصات الانترنت في الآونة الأخيرة.", "\"كما اعتدنا على الأعمال الملحمية التي خطت على جبين أعلى الجبال تنتشر كالنار بالهشيم بين عقول الناس وأعينهم بعد موت من أنتج هذه التحف الخالدة، كجزء ينم عن عاطفة البشر، وعلى قساوة صدرهم في الوقت ذاته.. ولكن هذا العمل لا يحتاج إلى جسد (يوسف) لأن روحه تطوف أرجاء المكان بكل سلاسة.. نقدم لكم هذا العمل العظيم. يوزع الآن مع دزينة مناديل.. سوف تستهلكها بالمقدمة فقط\".", "عندما نؤمن بالشيء .. نستطيع أن نلمس الشمس وأن تحرقها بلهيب فكرتك.. تستطيع إنتاج نسخة أفضل.. كأنهم أوراق متشابهة نفس النص.. وكتاب هواة مختلفين.", "بالوقت الذي كانوا يخرجون من الطابعة كنسخ بلهاء .. كنت أنا من يلوث حبرها.. أكتب عنا كثيرا.. لا أكتب عن المجهول.", "أنا .. كتفاي علق عليهما أيدي.. حاسوبي دائم الخراب.. أعين يتحرك بها مد وجزر.. بحيرتان صغيرتان.. هل هما صورة عن بحيرة فكتوريا.. أم أعين فكتوريا؟", "كريس: كنت على يقين في نجاح الهمسات التي ولدت من الأنامل", "آندي: سوف يطلق \"إيد شاريين\" بجولته القادمة أغنية جديدة! حتما سوف ننشر الكتاب ورقيا.. أرباح الأغنية ستكون في رصيدنا.", "فيكتوريا: لقد رأيت “story” الانستغرام خاصته!"], ["“I- whale – always love you” : اسمجذاب", "فادي: هل أنا أهيم بأحلامي.. أم ما أعيش حقيقي؟", "", "\"فينسينت\"", "- عودة الحياة -", "أشعرُ أنني قد دخلت بسبات عميق لسنوات، كدت أن أختنق بريقي شديد الحموضة، أتحسس أذني.. آه، لم تنمو بعد! أما ذقني كاللهب قدحت في أرجاء غرفتي الغبار! أين أنا الآن؟!", "الألوان فقد سيولتها .. جافة.. الأصفر تحول إلى البني.. عيني كاذبة؟ أو كما قيل .. عين الفنان لا تخطئ أبدا.. هل أنا فنان؟!", "المهم أنني أثبت نظريتي.. أظن أنني قد نمت لأسابيع .. ولكن لم تذبل الأزهار التي رسمتها .. أشعر بارتباكٍ شديد... عقارب الساعة تحللت أخذت معطفي الشتوي.. ولكن الطقس يبدو صيفيا أكثر من اللازم.", "لم أشعر بحرارة امستردام مثل هذا الوقت سلفا.. ألواني جفت ولكن تركتني أنا أسيل بالشوارع.. أبللها بدمي.. الذي يبدو شبه متخثر كأنني ميتٌحي.", "الضجيج يلفني.. مركباتٌ غريبة تشبه العربات ولكنها تنفذ الدخان الرمادي المحايد.. الناس ترتدي ملابس تحتوي على ألوان فاقعة كادت أن تحمي عيناي.. لوحات متحركة بإطارٍ أسود رفيع! أكاد أن أفقد ما تبقى من تفكيري السوي.. في أي عصرٍ أنا!", "زي تنكري رائع يا رجل! أشعر بأن فان كوخ عاد للحياة! هتف الفتى الذي كان على يميني.", "لكن أنا فينسينت فان كوخ، هل تعرفني؟", "ضحك الفتى بصوت عالٍ هو وصديقته الصهباء، ثم أدار ظهره وقال ما رأيك بالهودي خاصتي، يا فان كوخ؟ بنبرة استهزاء."], ["تعرفت عليها بثوانٍ.. إنها سمائي مليئة بالنجوم.. تحسستها لم تكن مرسومة بألوان زيتية.. شكلها متقن جدا لكن لا أذكر أنني قد رسمت على معطفٍ غريب لشاب يصغرني بأعوامٍعديدة! وقفت والصدمة تغطي ملامح وجهي البائس.", "قال الفتى المهووس بي.. سنذهب إلى المتحف الخاص بفينسنت هل تأتي؟ رددت أنا: متحفٌ خاص بي؟", "قال الفتى: كفاك أيها المتحاذق..", "وصلنا إلى مبنى رمادي كبير نصفه من زجاج.. بحدائق عباد شمس واسعة... نصف وجهي على بوابة كبيرة... ونصف روحي داخلي.", "دخلت البوابة ورأيت لوحاتٍتشبه لوحاتٍ رسمتها.. بشكلٍ دقيق الجميع يهيم بتفاصيلها.. شعرت بخيانة القدر.. من هذا الفنان الذي حصل على جميع الثناء.. وأنا لم يذكرني أحد.. لحظات وقد تجمعت علي عصابة فتيات... أيمكنني أن ألتقط \"سيلفي\" معك! هل بينك وبين فينسينت صلة قرابة!", "ولكن أنا فينسينت! ردذت علي مبتسمة: هل عدة للحياة؟ بعد موتك.", "", "\"ربما البؤس يمتلك مدة صلاحية\"", "عزيزي ثيو،", "ربما لن تصدق محتوى هذه الرسالة، لكن ربما أنا صدقا فنان لأناس خلُقت حديثا.. ذلك الوقت كان عصيب ولم يرد أحد اقتناء لوحة لي.. أما الآن أعد مؤسس لفرع فن كامل.. لأناس يقدرون اللحظات أذكر تلك المرة عندما فقدت صوابي على فتيانٍ يلحقون غربان الحقل بحجارةٍ صغيرة.. حاولوا تعكير صفو المقطع الفني الذي حاولت باستماتة أن أخرج مظهر جمالي من رحم قساوة الصخور الذي شقها جذور نباتٍ رقيق.. عندما ظننت أن الفن يذُاق من أفواه أصحاب الغليون ونصبوا أنفسهم نقاد للفنون بسبب أوراق النقود البالية.. في هذا العصر الغريب.. الجميع قادرٌ على تذوق الفن."], ["أشعرُ برغبةٍ عارمة في أن أسقط في حقلٍ شديد الصفار.. أن ألون أي شيء وكل شيء.. أريد أن أرسم سفينة أقطع بها أمستردام وأن أصل إلى روما.. أن أرشق ما تبقى من ألواني على الكتيدرائية.. أن أصنع معتقد جديد.. نحترم به الريش الذي قد تلفت في سبيل إظهار عمق الشعور على قطع قماش.", "أشعرُ بأنني قد وُلدِت توا.. يغطي جلدي الأحمر والقرمزي.. أن أزور صديقي كلود في حديقة منزله فائقة الجمال نحتسي الشاي.. أشعر وقتها سوف أقف عاجزا .. كنت معتادا على أن أصور القبيح.. جميل.. ربما سأعتمد على خيالي.", "كنت في فينة من الزمن قس.. أبٌ تهافت الجميع ليقبل يديه لم أكن اعلم أن خطط الرب جعلتني محاطا بمنحنيات لا تشبهني بتاتا.. عندما علمت كيفية حب الأديان عن طريق لوحاتٍ خرساء قادرة على الصراخ بصوتٍ كالنحيب.. أو العويل.. أن أذرف دموعي في سبيل أن أجعل الألوان قابلة للجريان على أسطح غريبة وأن أكتب اسمي تحتها بشكل مهمل.", "أكتبُ لك الآن وأنا أحرق أطرافي بالشموع التي أهدتني إياها أورسولا عندما اشترتها من أحد المتاجر في أزقة باريس عندما حرقت ما تبقى من شعوري.. قررت حرق جلدي الثخين جراء إحكامي على المشاعر التي ظننتها مخرجي الوحيد.. فهل وجدت المخرج؟", "فاتني القطار يا أخي.. والربيع يوجد بداخلي.. ليس مجرد فصل لن أذهب الآن.. تبقى لي الكثير ... وإن لن ينتهي البؤس سوف أبدد ما تبقى منه.. أتمنى لو كنت هنا..", "سوف أعاقر وحدتي وكأس لوني مملوء.. أثمل دون كحول.. أن أعشق الملاك.", "لن أقول وداعا يا أخي العزيز .. إلى اللقاء القريب.", "", "\"بيت شجرة متين\"", "وأنا أتنقل بين الرسائل على حساب \"الهمسات\" وجدتُرسالة من الرجل الآسيوي الذي التقف دفتر يوسف، ولما جرني الفضول في معرفة مكنونة."], ["مرحبا!", "أتمنى أن تكون بخير، وهنيئا على النجاح الكبير لكتاب الهمسات المهملة،", "عندما جرني فضولي المريب أن أقرأ مذكراته المكسوة بالجلد.. كانت صفحات فارغة.. جميعها تحمل نفس العنوان بتواريخ مختلفة.. عنوان كاد أن يلتهم حواشي الورقة.", "", "\"سر الحياة\"", "سأحاول جاهدا أن أسلمك إياه بيدي.. وإن عجزت عن ذلك سأرسله بالبريد.. دمت بخير.", "مرت تقريبا ساعة وأنا أكرر قراءة الرسالة.. فكتوريا نائمة كقطة وديعة.. الأغنية تتكرر.. \"وأنا سحاب.. للورد.. يلي يدفيك البرد\" ولم أجد أجمل من زهرة عباد الشمس خاصتي.", "هذه مسؤولية كبيرة أن أجد سرا للحياة لوحدي..", "", "\"الطريق الطويل قد شارف على الانتهاء\"", "هذه الطريق قطعته بقدم واحدة. قطعت ألف ميل.. هب لغيري ألف قدم ولن يمشي خطوة واحدة! أجرُّ رداء فخري وأنا أحمي أمي من عواصف الذاكرة.. بعدما كللت نفسي بتاجٍ وحكمت مشاعري التي أهدرتها.. كنت خائفا عندما أصبح بالثلاثين من عمري أن أكون شخصا مستهلك وطفلي لن يفخر بأبيه.. أعرف بحارا تزوج معلمة للغة العربية.. علموا أطفالهم كيفية الوصول للبر عن طريق قراءة حروف مرجان أعمق البحار.. عندما سقط أصغر أطفالهم في بحر البيض المتوسط فقد الأمل...تشبثت يداه بمنارة الاسكندرية.", "بعدما لاقتني أوتار الاصهب وأهداني أرباح الأغنية التي كان وقعها يتخطى سماء لندن الغائمة.. وصولا إلى بوخارست.. حتى عمان، ذهبت أنا وأمي وفكتوريا إلى أمستردام في بلاد الطواحين الهوائية بعدما استقبلت دعوةا من منظم متحف فينسينت.. لم يخبرني أحد ما هيأة المفاجأة التي قطعت فيها لوس انجيلوس إلى تكساس معاركا رعاة البقر اللذين في ذهني وصولا إلى طواحين هولندا."], ["الآن وبجميع جوارحي أجزم أنني قادر تقدير اللحظات.. عندما شعرت أنني فقدت متعتي في تذوق بساطة الأمور.. أعادتني للحياة نسحة كاتبٍأصلية قضيتُ أربعة أعوامٍ وأنا أبحثُعنها في رفوف مكتباتٍ لـثلاثة دول مختلفة.", "أما الآن أنا قادرٌ على تذوق الغيوم في رحلتي.. أو حتى مجرد الاستماع إلى أغنيتي المفضلة.. أحلم أن أتوه في حقل عباد شمس مع طولِ 193cm مستعدٌ على أن أجرح ركبتاي وأنا أمشي عليهما لكي يبتلعني حقلٌ بأعناقٍ طويلة.. عندما أرتشف قهوتي بالموكابوت وأن أسأل رفاق مائدتي Espresso “ ” amici وأن أكون الشخصية الرئيسية بمجرد أن أضع سماعات أذني وأمشي بين الحشود الحاقدة.", "فكتوريا: أخاف أن تصاب بالحساسية أنت والخالة ريتا.", "لأول مرة.. أومئ برأسي لكلام فيكي مبتسما دون كلام.. عندما دخلنا سوق الأزهار المعلقة.. لم أعرف أن أمستردام تمتلك سقفا من الزهور عندما أرفع رأسي تمطر علي بلقاحها.. أشعر بأنني في الجنة.. عندما سقطت ورقة من زهرة توليب بيضاء على جفن فكتوريا مكملة طريقها متوجهة على شفتيها .. مسكتها أمي وهي تتهاوى ووضعتها في دفترها الصغير.. عندما قالت أنها جزءٌ من عائلتنا الآن.. وهي تنظر اتجاهي لم أعلم وقتها ... هل تقصد التوليبة الصغيرة أم فكتوريا؟", "- وردة على كتافك.. على شفافك .. على شفافك ينبت الورد –", "حتما هذه أحد اللحظات التي غادرت روحي جسدي تحلت بين الأزهار.", "وصلنا أعتاب المبنى الهندسي العظيم عصر اليوم.. زجاج يمتزج مع قساوة الحجارة الرمادية.. رمادي.. قاسٍ.. زجاج.. هش.. رمادي محايد.. عدل...", "كان بانتظارنا المنظم.. شعر رمادي.. محايد أيضا.. ذقنٌتفوح منها زيوت ما بعد الحلاقة.. نظارةٌ تجعلك غير متردد بأن صاحبها تشرب الفن منذ نعومة أظافره..", "هل تمازحني؟ أستدفع 14 يورو مقابل الدخول.. تعالوا معي.. أنتم ضيوف الشرف هنا!", "كانت أمي ترتجف .. أمسكت يدها.. وقلت: أنا هُنا يا أمي.. تجولنا بقاعات اللوحات تغطيها.. سقفٌ وأرضية متحركة... برسمة زهور عباد الشمس التي سقاها فنسينت فرط الشعور.. تربة خيالية"], ["خصبة.. آكلو البطاطا ينظرون باتجاهنا.. لا سلام على طعام.. لوحة أعشق وجوه الصدمة التي بها.. الحذِاء المتهالك ينسيني مرارة الكون..", "المقهى الليلي .. لا أدري كيف تمرد فان جوخ عندما قال أنها أقبح لوحة له.. لا ألومه.. قضى ثلاث ليالٍ يرسمها .. أثر الإرهاق والهذيان سيطر عليه.", "أما أفضل لوحات الصيف أثناء إقامته بآرل – فرنسا.. هي بالتأكيد حقل القمح وشجرة السرو.. أسمع صوتها.. أسمعها تغني.", "أشار الشائب اللطيف بيده لنا.. وقال: هل أنتم مستعدون؟ دخلنا عبر باب كبيرٍ جدا .. وجدنا شيء جعل دمعة ريتا الأم تسيل بسلاسة..", "لوحة يوسف.. تتربع وسط لوحات فينسينت.", "\" قد قرأ أحد النقاد كتابة الشاب يوسف حول تحليلاته في حب فينسينت، الذي قد يكون أكثرنا فخرا إن عاد للحياة ورأى حب يوسف للوحاته وكتاباته.. لم أجد في مسيرة حياته القصيرة أي مؤشر على دخوله أحد مدارس النقد.. ولكن عجز أكبر نقاد من ميلان عاصمة الفن إلى ملوك تماثيل أثينا على هذا الوصف.", "تخليدا لذكرى يوسف .. ستعرض هذه اللوحة سنويا مثل هذا اليوم مصاحبة بتوزيع كتابة للزوار.", "-Mystery of love /song–", "وقفت أنا وأمي وهي تحتضن فيكتوريا أمام حديقة عباد الشمس.. نلمس رؤوسها.. كان الوقت غسقا.", "أقطفوا منها قدر ما تشاؤون.. قال أحد حراس الأمن.", "نظرنا بعيون بعضنا البعض.. بعدما كانت الدموع تقاوم الخروج بدأنا بقطفها ونحن نضحك.. نبكي.. حتى سال الدم من أيدينا دون أن نشعر.. جراء الأشواك المنثورة على سطح ساق الأزهار. أظن أنني قد علمت سر الحياة.. هو أن تعيشها دون قضاء كامل عمرك تهدره في محاولة كشف السر."], []], "toc": [{"page": 32, "title": "وداع أورورا"}, {"page": 36, "title": "4 EVER"}, {"page": 36, "title": "ريتا"}, {"page": 36, "title": "أورورا"}, {"page": 46, "title": "حيتان بكل مكان"}, {"page": 47, "title": "حوت العنبر"}, {"page": 49, "title": "يوميات حوت"}, {"page": 51, "title": "فادي يكمل عن يوسف ورسوماته"}, {"page": 51, "title": "ريتا"}, {"page": 53, "title": "فادي الجديد"}, {"page": 54, "title": "فادي"}, {"page": 56, "title": "سهرة المزرعة"}, {"page": 58, "title": "موسيقى وحلوى المارشيميلو"}, {"page": 60, "title": "قريةٌ حيثلا قضاء لها"}, {"page": 63, "title": "أول صباح في المزرعة"}, {"page": 64, "title": "آندرو"}, {"page": 67, "title": "العودة إلى المنزل"}, {"page": 67, "title": "فادي"}, {"page": 68, "title": "أزرقٌيبللُ خط الأفق"}, {"page": 68, "title": "سماء سان ريمو في نيو سيتي"}, {"page": 70, "title": "ليلةٌ مرصعة بالأحلام"}, {"page": 71, "title": "همسات مهملة"}, {"page": 72, "title": "3 شهور بعد (أحبك)"}, {"page": 73, "title": "حقل أرز من نيوسيتي إلى البكين"}, {"page": 75, "title": "جسر خيبة وتحرُّر من المتحف إلى منزلي"}, {"page": 76, "title": "لا تخرج بلا سترة واقية"}, {"page": 78, "title": "يا أنا"}, {"page": 79, "title": "عالمي الموازي"}, {"page": 80, "title": "نحن شتات فلسطين.. وهي كمالنا"}, {"page": 83, "title": "كالنار بالهشيم"}, {"page": 84, "title": "فينسينت"}, {"page": 85, "title": "ربما البؤس يمتلك مدة صلاحية"}, {"page": 86, "title": "بيت شجرة متين"}, {"page": 87, "title": "سر الحياة"}, {"page": 87, "title": "الطريق الطويل قد شارف على الانتهاء"}]};
